-- Poems batch 394
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-572','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','花满树。',53,'宋词/ci.song.10000.json','["花满树。", "两个黄鹂相语。", "恰似碧城双玉女。", "对歌还对舞。", "可惜娟娟楚楚。", "同伴彩云归去。", "居士心如泥上絮。", "那能无恨处。"]'),
('song-ci-573','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','嗟久客。',53,'宋词/ci.song.10000.json','["嗟久客。", "又见他乡寒食。", "流水断桥春寂寂。", "孤村烟火息。", "白去红飞无迹。", "千树总成新碧。", "醉里伤春愁似织。", "东风欺酒力。"]'),
('song-ci-574','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','芳思切，旧事不堪重说。',53,'宋词/ci.song.10000.json','["芳思切，旧事不堪重说。", "浓露凝香花喷血。", "花心双蛱蝶。", "燕语莺啼都歇。", "又过清明时节。", "记得离歌三两阕。", "未歌先哽咽。"]'),
('song-ci-575','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','花满树。',53,'宋词/ci.song.10000.json','["花满树。", "两个黄鹂相语。", "恰似碧城双玉女。", "对歌还对舞。", "可惜娟娟楚楚。", "同伴彩云归去。", "居士心如泥上絮。", "那能无恨处。"]'),
('song-ci-576','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','嗟久客。',53,'宋词/ci.song.10000.json','["嗟久客。", "又见他乡寒食。", "流水断桥春寂寂。", "孤村烟火息。", "白去红飞无迹。", "千树总成新碧。", "醉里伤春愁似织。", "东风欺酒力。"]'),
('song-ci-577','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','芳思切，旧事不堪重说。',53,'宋词/ci.song.10000.json','["芳思切，旧事不堪重说。", "浓露凝香花喷血。", "花心双蛱蝶。", "燕语莺啼都歇。", "又过清明时节。", "记得离歌三两阕。", "未歌先哽咽。"]'),
('song-ci-578','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','春又过。',53,'宋词/ci.song.10000.json','["春又过。", "那更雨摧风挫。", "留得浅红三两朵。", "竹梢烟雾锁。", "把酒对花危坐。", "多病多愁都可。", "舞蝶游蜂迷道左。", "惜春忙似我。"]'),
('song-ci-579','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','秋夜静。',53,'宋词/ci.song.10000.json','["秋夜静。", "屋上狂风初定。", "两两啼蛄相答应。", "灯蛾摇烛影。", "枕上鸡声遥听。", "起舞良宵偏永。", "明日谩寻弓剑整。", "衰颜重揽镜。"]'),
('song-ci-580','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','芳信拆。',53,'宋词/ci.song.10000.json','["芳信拆。", "漏泄东君消息。", "帝殿宝炉烟未熄。", "龙香飘片白。", "点缀枯梢的皪。", "疏影摇荡寒碧。", "指与纤纤教自摘。", "枝横云鬓侧。"]'),
('song-ci-581','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','天气暖。',53,'宋词/ci.song.10000.json','["天气暖。", "开了荼䕷一半。", "红日迟迟风拂面。", "阶前花影乱。", "俊雅风流不见。", "定被莺花留恋。", "千尺游丝舒又罥。", "系人心上线。"]'),
('song-ci-582','谒金门','吕胜己','宋','宋词','song-ci','谒金门','[]','歌罢奏。',53,'宋词/ci.song.10000.json','["歌罢奏。", "敛步拂开罗袖。", "宝扇轻摇香汗透。", "软香沾素手。", "小立偎人良久。", "一寸娇波横溜。", "心事未言眉已皱。", "无端催劝酒。"]'),
('song-ci-583','南乡子','吕胜己','宋','宋词','song-ci','南乡子','[]','斗笠棹边舟。',66,'宋词/ci.song.10000.json','["斗笠棹边舟。", "碧水湾头放自流。", "尽日垂丝鱼不上，优游。", "更觉心松奈得愁。", "行客语沧洲。", "笑道渔翁太拙休。", "万事要求须有道，何由。", "教与敲针换曲钩。"]'),
('song-ci-584','南乡子','吕胜己','宋','宋词','song-ci','南乡子','[]','纵棹越溪船。',66,'宋词/ci.song.10000.json','["纵棹越溪船。", "破浪冲涛到碧湾。", "种就长堤千亩竹，无边。", "插玉屯云满渭川。", "平日乐归田。", "不恋荣华不慕仙。", "得个容身栖隐处，宽闲。", "每日江边理钓竿。"]'),
('song-ci-585','减字木兰花','吕胜己','宋','宋词','song-ci','减字木兰花','[]','烟云变化。',52,'宋词/ci.song.10000.json','["烟云变化。", "面面青山如展画。", "俯对平川。", "野水烟村远接天。", "有时纵目。", "景物繁华观不足。", "月下风头。", "一曲清讴博见楼。"]'),
('song-ci-586','瑞鹤仙','吕胜己','宋','宋词','song-ci','瑞鹤仙','[]','南州春又到。',127,'宋词/ci.song.10000.json','["南州春又到。", "向腊尽冬残，冰姑先报。", "芳心爱春早。", "露生香馥馥，靓妆皎皎。", "诗人最巧。", "道竹外、斜枝更好。", "旋移根引水，浇培松竹，凑成三妙。", "回首。", "当年客里，荆棘途中，幸陪欢笑。", "闲愁似扫。", "记风雪、关山道。", "待飘花结子，和羹煮酒，还我山居送老。", "那青红、浪蕊浮花，尽锄去了。"]'),
('song-ci-587','瑞鹤仙','吕胜己','宋','宋词','song-ci','瑞鹤仙','[]','倚阑观四远。',126,'宋词/ci.song.10000.json','["倚阑观四远。", "近有客登临，故相磨难。", "山形欠舒展。", "小峰峦云树，晦明更变。", "江淮楚甸。", "又何曾、分明在眼。", "但临深、自觉身高，未可便名博见。", "休辨。", "吾心乐处，不要他人，共同称善。", "痴儿浅浅。", "因他谩说一遍。", "问还知宴坐，回光收视，大地河山尽现。", "待於中、会得些时，举觞奉劝。"]'),
('song-ci-588','瑞鹤仙','吕胜己','宋','宋词','song-ci','瑞鹤仙','[]','人生如意少。',127,'宋词/ci.song.10000.json','["人生如意少。", "谁得似仙翁，身名俱好。", "亨衢腾踏早。", "驾双旌五马，便居蓬岛。", "闽山蜀道。", "秉玉节、油幢屡到。", "号当今、有脚阳春，处处变愁成笑。", "尤妙。", "晚陪论道。", "密赞调元，虎符重剖。", "去劳自保。", "奉香火、归来了。", "见煌煌甲第，两两龙驹，绿鬓朱颜未到。", "是平生、种德阴功，自天有报。"]'),
('song-ci-589','瑞鹤仙','吕胜己','宋','宋词','song-ci','瑞鹤仙','["\u957f\u6c5f"]','金枝联玉叶。',127,'宋词/ci.song.10000.json','["金枝联玉叶。", "世代有宗英，声华烨烨。", "君侯更超绝。", "抱不群才气，壮图英发。", "津途轨辙。", "□武上、青宵迥别。", "自玉阶、契合君王，拍拍满怀风月。", "奇绝。", "身居萧散，志在功名，眼高天阔。", "恩来魏阕。", "长江上、驻旌节。", "待胡尘有警，纶巾羽扇，谈笑周郎事业。", "恁时看、国倚强宗，诏褒伟烈。"]'),
('song-ci-590','瑞鹤仙','吕胜己','宋','宋词','song-ci','瑞鹤仙','[]','残梅飘簌簌。',127,'宋词/ci.song.10000.json','["残梅飘簌簌。", "看柳上春归，揉条新绿。", "娇莺离幽谷。", "弄弹簧清响，飞迁乔木。", "年华迅速。", "叹浮生、流晖转烛。", "自春来、每每遨游，多办九霞醽醁。", "溪北。", "踏青微步，斗草慵眠，锦裀花褥。", "铅华簇簇。", "歌声妙、间丝竹。", "爱一川好处，高山流水，不减城南杜曲。", "笑平生、卓地无锥，老来富足。"]'),
('song-ci-591','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','往事千端，都销道、衰翁宦拙。',115,'宋词/ci.song.10000.json','["往事千端，都销道、衰翁宦拙。", "今会得、人情物态，尽皆休说。", "广厦尽堪舒笑傲，层楼又见凌空阔。", "试闲思、画戟比衡门，谁优劣。", "尘里事，无休歇。", "楼上事、真奇绝。", "有一川虚旷，万山环列。", "识破古今如旦暮，肯将物我刚分别。", "愿时时、与客坐楼心，谈风月。"]'),
('song-ci-592','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','屈指重阳，有半月、犹零九日。',118,'宋词/ci.song.10000.json','["屈指重阳，有半月、犹零九日。", "且停待、今宵月上，宝轮飞出。", "有客最谙闲况味，无人会得真消息。", "算何须、抵死要荣华，劳心力。", "楼观迥、遥山碧。", "槽窄小，真珠滴。", "随分赏、闲亭别圃，好天良夕。", "篱畔行看金蕊耀，林梢便见瑶芳白。", "玩春来、夏去复秋冬，尘中客。"]'),
('song-ci-593','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','小立危亭，风惨淡、斜阳满目。',117,'宋词/ci.song.10000.json','["小立危亭，风惨淡、斜阳满目。", "望渺渺、湘江一派，楚山千簇。", "芳草连云迷远树，断霞散绮飞孤骛。", "感骚人、赋客向来词，愁如束。", "磋远宦、甘微粟。", "惊世事，伤浮俗。", "且经营一醉，未怀荣辱。", "君不见、渊明归去后，一觞自泛东篱菊。", "仰高风、寂寞奠生刍，人如玉。"]'),
('song-ci-594','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','忆惜西来，春已暮、馀寒犹力。',118,'宋词/ci.song.10000.json','["忆惜西来，春已暮、馀寒犹力。", "正迤逦、登山临水，未磋行役。", "云笈偶寻高士传，桃川又访秦人迹。", "向此时、游宦兴阑珊，归无策。", "归计定，归心追。", "惊换岁，犹为客。", "还怅望、家山千里，迥无消息。", "□□不堪泥路远，烟林赖有梅花白。", "为孤芳、领略岁寒情，谁人识。"]'),
('song-ci-595','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','物理分明，人事巧、元来是拙。',115,'宋词/ci.song.10000.json','["物理分明，人事巧、元来是拙。", "常自觉、满怀春意，向他谁说。", "剩喜登临频眺望，那知出处成迂阔。", "细闲思、萧散较贪痴，谁为劣。", "高楼上、蝉声歇。", "飞楝外，云行绝。", "见明河星斗，半空森列。", "领略光阴成赋咏，等闲酬唱休旌别。", "要良辰、把酒倩佳宾，嘲风月。"]'),
('song-ci-596','满江红','吕胜己','宋','宋词','song-ci','满江红','["\u6ed5\u738b\u9601"]','拍碎红牙，一声上、梁尘暗落。',115,'宋词/ci.song.10000.json','["拍碎红牙，一声上、梁尘暗落。", "纨扇掩、雏莺叶下，巧呈绰约。", "字字只愁郎幸浅，声声似怨年华薄。", "坐中人、相顾感幽怀，添萧索。", "歌暂阕，杯交错。", "人又去，情怀沪。", "那堪听风雨，渭城吹角。", "去去已离闽岭路，行行渐近滕王阁。", "便无情、山海会相逢，坚心著。"]'),
('song-ci-597','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','檀扳频催，双拈袖、飞来趁拍。',119,'宋词/ci.song.10000.json','["檀扳频催，双拈袖、飞来趁拍。", "锦裀上、娇抬粉面，浅蛾脉脉。", "鸾观莺窥秋水净，鸿惊凤翥祥云白。", "看妖娆、体态与山精神，天仙谪。", "鞓带紧，弓靴窄。", "花压帽，云垂额。", "□回雪、定拼醉倒，厌厌良夕。", "明日恨随芳草远，回头目断遥山隔。", "料多情、应也念行人，思佳客。"]'),
('song-ci-598','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','墙下松筠，并手种、花窠尽著。',115,'宋词/ci.song.10000.json','["墙下松筠，并手种、花窠尽著。", "试屈指、一年前事，恍然如昨。", "繁杏新荷春夏景，疏梅细菊秋冬约。", "渭川翁、随分小生涯，些官爵。", "分物我，争强弱。", "都作梦，谁先觉。", "好一条平路，是人迷却。", "斑鬓已灰心里事，瘦滕谩卦瓢中药。", "愿当今、四海九州人，同欢乐。"]'),
('song-ci-599','满江红','吕胜己','宋','宋词','song-ci','满江红','[]','雪压山颓，谁撒下、琼花玉蕊。',115,'宋词/ci.song.10000.json','["雪压山颓，谁撒下、琼花玉蕊。", "寒气凛、沈沈天籁，望迷千里。", "群雀耐寒枯树顶，扁舟独钓平沙觜。", "把江南、图画展开看，都难比。", "台榭远、登临喜。", "楼阁上，歌声起。", "赏时光，居士独怜愁底。", "安得四方寒畯彦，归吾广厦千间里。", "但今生、此愿得从心，心休矣。"]'),
('song-ci-600','满江红','吕胜己','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','惨惨枯梢，初疑似、真酥点滴。',114,'宋词/ci.song.10000.json','["惨惨枯梢，初疑似、真酥点滴。", "见深红蒂萼，方认早梅消息。", "粉艳牵连春意动，冰姿照映霜华白。", "伴苍松、修竹似幽人，相寻觅。", "香远近，枝南北。", "幽涧畔，疏篱侧。", "便佣儿贩妇，也知怜惜。", "渭水渔翁方入社，西湖处士成陈迹。", "爱平生、炯炯岁寒心，无今昔。"]'),
('song-ci-601','江城子','吕胜己','宋','宋词','song-ci','江城子','["\u897f\u6e56"]','年年腊后见冰姑。',86,'宋词/ci.song.10000.json','["年年腊后见冰姑。", "玉肌肤。", "点琼酥。", "不老花荣，经岁转敷腴。", "向背稀稠如画里，明月下、影疏疏。", "江南有客问征途。", "寄音书。", "定来无。", "且傍盆池，巧石倚浮图。", "静对北山林处士，妆点就、小西湖。"]'),
('song-ci-602','江城子','吕胜己','宋','宋词','song-ci','江城子','[]','一钩新月下庭西。',86,'宋词/ci.song.10000.json','["一钩新月下庭西。", "绣帘低。", "漏声迟。", "小宴幽欢，依约似当时。", "娇盼注人都不语，眉黛蹙，鬓云敧。", "街槐阴下玉骢嘶。", "苦相催。", "醉中归。", "可惜明朝，秋色满东篱。", "只恐又成轻别也，情脉脉，恨凄凄。"]'),
('song-ci-603','满庭芳','吕胜己','宋','宋词','song-ci','满庭芳','[]','丹雘浮空，琉璃耀日，上云楼阁眈眈。',118,'宋词/ci.song.10000.json','["丹雘浮空，琉璃耀日，上云楼阁眈眈。", "□□居士，燕坐息玄谈。", "十载劳心问道，今悟罢、截日停参。", "凝神处，九苞丹凤，翔舞在山南。", "喃喃。", "成障碍，千经万论，从此休贪。", "且陶陶兀兀，对酒醺酣。", "清兴有时狂放，扁舟上、绿水澄潭。", "渔歌起，从他两岸，齐笑老翁憨。"]'),
('song-ci-604','卜算子','吕胜己','宋','宋词','song-ci','卜算子','[]','人事几时穷，我性偏宜静。',52,'宋词/ci.song.10000.json','["人事几时穷，我性偏宜静。", "世上谁无富贵心，到了须由命。", "闲里且偷安，醉后休教醒。", "醉里高歌妙入神，妙处君须听。"]'),
('song-ci-605','卜算子','吕胜己','宋','宋词','song-ci','卜算子','[]','梅蕾破香时，雪后交光夜。',52,'宋词/ci.song.10000.json','["梅蕾破香时，雪后交光夜。", "何处飞来两玉蛾，体态双闲雅。", "纵目碧城楼，劝酒留云榭。", "唱底仙家古道情，分付知音者。"]'),
('song-ci-606','瑞鹧鸪','吕胜己','宋','宋词','song-ci','瑞鹧鸪','[]','与君蹑足共凭阑。',64,'宋词/ci.song.10000.json','["与君蹑足共凭阑。", "俯视周回四面山。", "目静鲁邦心渺渺，气吞梦泽意闲闲。", "烟云变化更明晦，乌鹊忘机互往还。", "唤取黄尘冠盖客，暂来徙倚片时间。"]'),
('song-ci-607','瑞鹧鸪','吕胜己','宋','宋词','song-ci','瑞鹧鸪','[]','几时芟棘翦蒿蓬。',64,'宋词/ci.song.10000.json','["几时芟棘翦蒿蓬。", "付我天然地一弓。", "乔木茂林森耸耸，遥岑叠嶂碧重重。", "水心台榭超尘表，楼上乾坤跨域中。", "黄鹤巴陵千古事，那知不是此衰翁。"]'),
('song-ci-608','感皇恩','吕胜己','宋','宋词','song-ci','感皇恩','[]','秋意满江湖，雨轻风熟。',81,'宋词/ci.song.10000.json','["秋意满江湖，雨轻风熟。", "上水扁舟片帆速。", "远山低岸，贪看浅红深绿。", "不知回柁尾，沧湾宿。", "推枕起来，举杯相属。", "休叹风尘为微禄。", "几年行路，但觉登临不足。", "且翻楚调入，清江曲。"]'),
('song-ci-609','临江仙','吕胜己','宋','宋词','song-ci','临江仙','[]','忽忆裴公台上去，远空秋气棱棱。',70,'宋词/ci.song.10000.json','["忽忆裴公台上去，远空秋气棱棱。", "万山一水秀还明。", "此时三楚客，何意续骚经。", "爱竹子犹参杖履，能诗候喜同登。", "赓酬不尽古今情。", "清风生白尘，侧月照疏星。"]'),
('song-ci-610','好事近','吕胜己','宋','宋词','song-ci','好事近','[]','风景好樵川，郭外三洲烟渚。',53,'宋词/ci.song.10000.json','["风景好樵川，郭外三洲烟渚。", "过尽古今清逸，奈天公不与。", "地灵人意会符同，留待烟霞侣。", "一棹轻舟开岸，弄滩声风雨。"]'),
('song-ci-611','好事近','吕胜己','宋','宋词','song-ci','好事近','[]','宿面浅匀妆，梅粉旋生春色。',53,'宋词/ci.song.10000.json','["宿面浅匀妆，梅粉旋生春色。", "绣草冠儿宫样，系丁香新缬。", "凤檀槽上四条弦，轻□□□攧。", "恰似寻阳江畔，话长安时节。"]'),
('song-ci-612','鹊桥仙','吕胜己','宋','宋词','song-ci','鹊桥仙','[]','银花千里，玉阶三尺，远近高低一色。',68,'宋词/ci.song.10000.json','["银花千里，玉阶三尺，远近高低一色。", "天公今岁被诗催，特地放、冬前四白。", "梅梢竹外，频频轻撼，嫌乱瑶芳素质。", "耐寒相对不胜清，毡帐底、偎红未得。"]'),
('song-ci-613','木兰花慢','吕胜己','宋','宋词','song-ci','木兰花慢','[]','残红吹尽了，换新绿、染疏林。',124,'宋词/ci.song.10000.json','["残红吹尽了，换新绿、染疏林。", "正杜宇催归，行人贪路，天气轻阴。", "江亭旧游宴处，但瑶山、数叠晚云深。", "犹忆佳人敛黛，为予别泪盈襟。", "而今。", "旅况难禁。", "逢胜概、懒登临。", "念景熟难忘，情多易感，取次关心。", "平明又西去也，望关山、古道马骎骎。", "回首当年一梦，笑将浊酒重斟。"]'),
('song-ci-614','木兰花慢','吕胜己','宋','宋词','song-ci','木兰花慢','[]','无言凭燕几，爱香袅、博山炉。',124,'宋词/ci.song.10000.json','["无言凭燕几，爱香袅、博山炉。", "正暖日辉辉，晴云淡淡，千里平芜。", "田家尽收刈了，见牛羊、下垅暝烟孤。", "闻说丰年景致，老农击壤呜呜。", "狂夫。", "素乏良图。", "从上策、赋归欤。", "有千亩松筠，三洲风月，尽随吾初。", "凭谁去西塞岸，问玄真、此意果如何。", "寂寞无人共乐，醉乡是我华胥。"]'),
('song-ci-615','木兰花慢','吕胜己','宋','宋词','song-ci','木兰花慢','[]','对轩辕古镜，照华发、短刁骚。',126,'宋词/ci.song.10000.json','["对轩辕古镜，照华发、短刁骚。", "念壮岁心情，平生志气，可笑徒劳。", "云中谩夸魏尚，请休论、定远说班超。", "总是黄粱一梦，怎如尘外逍遥。", "蛮徭。", "洞入云宵。", "算无分、到仙曹。", "愿归隐闽山，来临渭水，葺个云巢。", "楼居共、真仙伴侣，又有时、混迹入渔樵。", "且恁随缘玩世，帝乡路觉迢迢。"]'),
('song-ci-616','木兰花慢','吕胜己','宋','宋词','song-ci','木兰花慢','[]','朝天门外路，路坦坦、走瑶京。',126,'宋词/ci.song.10000.json','["朝天门外路，路坦坦、走瑶京。", "悔年少狂图，争名远宦，为米孤征。", "星星。", "半凋鬓发，事千端、回首只堪惊。", "居士新来悟也，渭川小隐初成。", "临清。", "巧创幽亭。", "真富贵、享安荣。", "有猿鸟清讴，松篁森卫，桧柏双旌。", "蛙鸣。", "自然鼓吹，粲林华、前后锦围屏。", "须信早朝鸡唱，未如夜枕滩声。"]'),
('song-ci-617','木兰花慢','吕胜己','宋','宋词','song-ci','木兰花慢','[]','平生花恨少，又那得、酒中愁。',126,'宋词/ci.song.10000.json','["平生花恨少，又那得、酒中愁。", "自禅板停参，蒲团悟罢，身世忘忧。", "南柯旧时太守，尽当年、富贵即时休。", "莫羡痴儿小子，心心念念封侯。", "优游。", "取次凝眸。", "春浩浩、思悠悠。", "爱万木欣荣，幽泉流注，好鸟勾舟，感生生、自然造化，玩吾心、此外复何求。", "应有知音共赏，定当一语相投。"]'),
('song-ci-618','柳梢青','吕胜己','宋','宋词','song-ci','柳梢青','[]','叶下云行，亭皋风静，凉雨丝丝。',61,'宋词/ci.song.10000.json','["叶下云行，亭皋风静，凉雨丝丝。", "断雁孤鸣，寒蛩相应，寂寂书帏。", "蒲团纸帐兰台。", "梦不到、邯郸便回。", "蚁穴荣华，人间功业，都恼人怀。"]'),
('song-ci-619','鹧鸪天','吕胜己','宋','宋词','song-ci','鹧鸪天','[]','竹树萧萧屋数椽。',64,'宋词/ci.song.10000.json','["竹树萧萧屋数椽。", "平湖漫漫纳通川。", "有时竹杖芒鞋至，醉著山光水色间。", "成小隐，未经年。", "功名夷路稳加鞭。", "逢时且数中书考，他日还寻独乐园。"]'),
('song-ci-620','鹧鸪天','吕胜己','宋','宋词','song-ci','鹧鸪天','[]','记得追游故老家。',64,'宋词/ci.song.10000.json','["记得追游故老家。", "红莲幕府在长沙。", "放船桥口秋随月，走马春园夜踏花。", "思往昔，谩咨磋。", "几番魂梦转天涯。", "葵轩老子今何在，岳麓风雩噪暮鸦。"]'),
('song-ci-621','鹧鸪天','吕胜己','宋','宋词','song-ci','鹧鸪天','[]','一夜春寒透锦帏。',64,'宋词/ci.song.10000.json','["一夜春寒透锦帏。", "满庭花露起多时。", "垒金梳子双双耍，铺翠花儿袅袅垂。", "人去后，信来稀。", "等闲屈指数归期。", "门前恰限行人至，喜鹊如何圣得知。"]'),
('song-ci-622','鹧鸪天','吕胜己','宋','宋词','song-ci','鹧鸪天','[]','日日楼心与画眉。',64,'宋词/ci.song.10000.json','["日日楼心与画眉。", "松分蝉翅黛云低。", "象牙白齿双梳子，驼骨红纹小棹篦。", "朝暮宴，浅深杯。", "更阑生怕下楼梯。", "徐娘怪我今疏懒，不及庐郎年少时。"]'),
('song-ci-623','鹧鸪天','吕胜己','宋','宋词','song-ci','鹧鸪天','[]','纸帐虚明好醉眠。',64,'宋词/ci.song.10000.json','["纸帐虚明好醉眠。", "博山轻袅水沉烟。", "了知世上都如梦，须信壶中别有天。", "知我者，为君言。", "道人有个好因缘。", "丹成有日归云路，且最梅花作地仙。"]'),
('song-ci-624','点绛唇','吕胜己','宋','宋词','song-ci','点绛唇','[]','满路梅花，为谁开遍春风萼。',50,'宋词/ci.song.10000.json','["满路梅花，为谁开遍春风萼。", "短亭萧索。", "草草传杯酌。", "送子先归，我羡辽东鹤。", "他年约。", "瘦藤芒履。", "共子同丘壑。"]'),
('song-ci-625','点绛唇','吕胜己','宋','宋词','song-ci','点绛唇','[]','日月无根，循环常共天难老。',50,'宋词/ci.song.10000.json','["日月无根，循环常共天难老。", "世间扰扰。", "只见闲烦恼。", "满酌高吟，便是今生了。", "还知道。", "旧时官好。", "几个新华表。"]'),
('song-ci-626','点绛唇','吕胜己','宋','宋词','song-ci','点绛唇','[]','一叶扁舟，浮家来向江边住。',50,'宋词/ci.song.10000.json','["一叶扁舟，浮家来向江边住。", "这回归去。", "作个渔樵侣。", "不挂征帆，也莫遥双橹。", "天涯路。", "云山烟渚。", "总是留人处。"]'),
('song-ci-627','点绛唇','吕胜己','宋','宋词','song-ci','点绛唇','[]','桂子飘香，江南秋老霜风作。',50,'宋词/ci.song.10000.json','["桂子飘香，江南秋老霜风作。", "自怜漂泊。", "几度伤离索。", "孤馆迢迢，满引村醪酌。", "情无著。", "好音难托。", "又失黄花约。"]'),
('song-ci-628','点绛唇','吕胜己','宋','宋词','song-ci','点绛唇','[]','瑞气盈门，神仙谪下看看到。',50,'宋词/ci.song.10000.json','["瑞气盈门，神仙谪下看看到。", "已知消耗。", "弧矢呈祥了。", "种德阴功，自有多男报。", "还知道。", "果生蓬岛。", "不比人间早。"]'),
('song-ci-629','鱼游春水','吕胜己','宋','宋词','song-ci','鱼游春水','[]','林梢听布谷。',105,'宋词/ci.song.10000.json','["林梢听布谷。", "郭外舒怀仍快目。", "平田浩荡，虢虢泉鸣暗谷。", "香稻吐芒针棘细，秀麦遥风波浪绿。", "山童野老，意亲情热。", "我待休官弃禄。", "屏迹幽闲安退缩。", "渭三千亩修篁，巑巑绀玉。", "顾盼滩流萦八节，呼吸湖光穿九曲。", "贪求自乐，尽忘尘俗。"]'),
('song-ci-630','霜天晓角','吕胜己','宋','宋词','song-ci','霜天晓角','[]','晓来风作。',53,'宋词/ci.song.10000.json','["晓来风作。", "病怯春衫薄。", "郭外溪山明秀，红尘里、自拘缚。", "村酒频斟酌。", "野花遍绰约。", "十载人非物是，惊回首、梦初觉。"]'),
('song-ci-631','虞美人','吕胜己','宋','宋词','song-ci','虞美人','[]','疏风摆撼芙蓉沼。',66,'宋词/ci.song.10000.json','["疏风摆撼芙蓉沼。", "垅上梅英小。", "谁家姊妹去寻芳。", "粉面云鬟参杂、汉宫妆。", "邯郸奏罢宫中乐。", "邂逅同杯酌。", "老来花酒制颓龄。", "为爱嫣然娇靥、斗盈盈。"]'),
('song-ci-632','虞美人','吕胜己','宋','宋词','song-ci','虞美人','[]','年年冬后心情快。',66,'宋词/ci.song.10000.json','["年年冬后心情快。", "常是留宾醉。", "尊前笑靥粲金钿。", "更有半黄枨橘、满堆磐。", "人人爱道休官去。", "总是闲言语。", "古今文士与贤才。", "为甚独高陶令、赋归来。"]'),
('song-ci-633','虞美人','吕胜己','宋','宋词','song-ci','虞美人','["\u897f\u6e56"]','横波清翦西湖水。',66,'宋词/ci.song.10000.json','["横波清翦西湖水。", "黛拂吴山翠。", "藕丝衫子水沈香。", "坐久冰肌玉骨、起微凉。", "金徽泛柳听佳句。", "叠叠胎仙舞。", "曲终松下小磐桓。", "风露泠泠、直欲便骖鸾。"]'),
('song-ci-634','菩萨蛮','吕胜己','宋','宋词','song-ci','菩萨蛮','[]','遥山几叠天边碧。',52,'宋词/ci.song.10000.json','["遥山几叠天边碧。", "故教遮断天涯客。", "楼倚暮云端。", "春风罗袖寒。", "与君千里别。", "共此关山月。", "皓月一般明。", "君心怎敢凭。"]'),
('song-ci-635','菩萨蛮','吕胜己','宋','宋词','song-ci','菩萨蛮','[]','岭猿啸罢千山碧。',52,'宋词/ci.song.10000.json','["岭猿啸罢千山碧。", "小庵虚室团团白。", "庵在小山头。", "从来少客游。", "道人方打坐。", "举袖来迎我。", "问我此来因。", "拈花与道人。"]'),
('song-ci-636','南歌子','吕胜己','宋','宋词','song-ci','南歌子','[]','湛露凉亭馆，香风散芰荷。',62,'宋词/ci.song.10000.json','["湛露凉亭馆，香风散芰荷。", "晚来月色似金波。", "间绿围红、同伴雪儿歌。", "年少风流足，情深欢会多。", "佳人月下拜嫦娥。", "不似隔年牛女、望星河。"]'),
('song-ci-637','八声甘州','吕胜己','宋','宋词','song-ci','八声甘州','[]','自秋来、多病意无聊，不作渭山游。',119,'宋词/ci.song.10000.json','["自秋来、多病意无聊，不作渭山游。", "想兰菊凋疏，松筠茂密，亭馆清幽。", "四望遥山万叠，叠叠翠光浮。", "人道蓬莱岛，仿佛瀛洲。", "居士心迷丘壑，念迂疏老懒，难觅封侯。", "看才能成事业，且自抽头。", "携老稚、团栾百口，要他年、在此作菟裘。", "无言也，此生心事，都付东流。"]'),
('song-ci-638','如梦令','吕胜己','宋','宋词','song-ci','如梦令','[]','花上娇莺哑咤。',40,'宋词/ci.song.10000.json','["花上娇莺哑咤。", "著色江南图画。", "可惜好春风，有酒无人同把。", "拚舍。", "拚舍。", "独醉好天良夜。"]'),
('song-ci-639','如梦令','吕胜己','宋','宋词','song-ci','如梦令','[]','王谢堂前旧燕。',40,'宋词/ci.song.10000.json','["王谢堂前旧燕。", "毕竟情高意远。", "只恐宠恩深，后会不教人见。", "深劝。", "深劝。", "不枉追欢一遍。"]'),
('song-ci-640','如梦令','吕胜己','宋','宋词','song-ci','如梦令','[]','梅雪渐当时候。',40,'宋词/ci.song.10000.json','["梅雪渐当时候。", "访问全无消耗。", "凭杖小阳春，催取南枝先到。", "然后。", "然后。", "雪月交光同照。"]'),
('song-ci-641','西江月','吕胜己','宋','宋词','song-ci','西江月','[]','日日齐眉举案，年年劝酒持觥。',58,'宋词/ci.song.10000.json','["日日齐眉举案，年年劝酒持觥。", "今年著意寿卿卿。", "幼稚绵绵可庆。", "官冷未尝贫贱，家肥胜似功名。", "所为方便合人情。", "管取前途更永。"]'),
('song-ci-642','渔家傲','吕胜己','宋','宋词','song-ci','渔家傲','[]','长记浔阳江上宴。',72,'宋词/ci.song.10000.json','["长记浔阳江上宴。", "庚公楼上凭阑遍。", "北望淮山连楚甸。", "真伟观。", "中原气象依稀见。", "漂泊江湖波浪远。", "依然身在蛮溪畔。", "愁里不知时节换。", "春早晚。", "杜娟声里飞花满。"]'),
('song-ci-643','渔家傲','吕胜己','宋','宋词','song-ci','渔家傲','["\u897f\u6e56"]','闻道西洲梅已放。',72,'宋词/ci.song.10000.json','["闻道西洲梅已放。", "几时乘兴同寻访。", "稚子携壶翁策杖。", "徐徐往。", "青山绿水皆堪赏。", "满月当空川晃晃。", "却呼艇子遥双桨。", "几阵浓香新酝酿。", "波溶漾。", "宛然身在西湖上。"]'),
('song-ci-644','渔家傲','吕胜己','宋','宋词','song-ci','渔家傲','[]','特为梅花来渭水。',72,'宋词/ci.song.10000.json','["特为梅花来渭水。", "有人折得横梢至。", "粉毖香悭春意未。", "多应是。", "江南信息争先寄。", "水绿山青风日美。", "此时正惬幽人意。", "驱使风光佳句里。", "□满纸。", "却将旧日诗词比。"]'),
('song-ci-645','杏花天','吕胜己','宋','宋词','song-ci','杏花天','[]','当年悔我抛生计。',66,'宋词/ci.song.10000.json','["当年悔我抛生计。", "趁升斗、蛮乡远地。", "谁知事向无心起。", "回首邯郸梦里。", "风雪满□□□□。", "最好处、吴头楚尾。", "青山本是强人意。", "更时见、梅花助美。"]'),
('song-ci-646','感皇恩','唐致政','宋','宋词','song-ci','感皇恩','[]','君欲问予年，八十有七。',41,'宋词/ci.song.10000.json','["君欲问予年，八十有七。", "百岁十分尚留一。", "世间滋味，尝尽酸碱苦涩。", "时今倒食蔗、无甜汁。"]'),
('song-ci-647','浣溪沙','楼锷','宋','宋词','song-ci','浣溪沙','[]','夏半阳乌景最长。',56,'宋词/ci.song.10000.json','["夏半阳乌景最长。", "小池不断藕花香。", "电影雷声催急雨，十分凉。", "芡剥明珠随意嚼，瓜分琼玉趁时尝。", "双枪堂深新酿好，且传觞。"]'),
('song-ci-648','洞仙歌','林外','宋','宋词','song-ci','洞仙歌','[]','飞梁压水，虹影澄清晓。',103,'宋词/ci.song.10000.json','["飞梁压水，虹影澄清晓。", "橘里渔村半烟草。", "今来古往，物是人非，天地里，唯有江山不老。", "雨巾风帽。", "四海谁知我。", "一剑横空几番过。", "按玉龙、嘶未断，月冷波寒，归去也、林屋洞天无锁。", "认云屏烟障是吾庐，任满地苍苔，年年不扫。"]'),
('song-ci-649','西江月','梁安世','宋','宋词','song-ci','西江月','[]','南国秋光过二，宾鸿未带初寒。',58,'宋词/ci.song.10000.json','["南国秋光过二，宾鸿未带初寒。", "洞中驼褐已嫌单。", "洞口犹须挥扇。", "夕照千峰互见，晴空万象都还。", "羡他渔艇系澄湾。", "敧枕玻璃一片。"]'),
('song-ci-650','望海潮','黄岩叟','宋','宋词','song-ci','望海潮','[]','梅天雨歇，柳堤风定，江浮画鹢纵横。',129,'宋词/ci.song.10000.json','["梅天雨歇，柳堤风定，江浮画鹢纵横。", "瀛女弄萧，冯夷伐鼓，云间凤咽鼍鸣。", "波面走长鲸。", "卷怒涛来往，搅碎沧溟。", "两岸游人笑语，罗绮间簪缨。", "灵均逝魄无凭。", "但湘沅一水，到底澄清。", "菰黍万家，丝桐五彩，年年吊古深情。", "锦帜片霞明。", "使操舟妙手，翻动心旌。", "向晚鱼龙戏罢，千里浪花平。"]'),
('song-ci-651','多丽','富ノ','宋','宋词','song-ci','多丽','[]','淡云收、晓来春满湘中。',173,'宋词/ci.song.10000.json','["淡云收、晓来春满湘中。", "柳如烟、花枝如糁，万红千翠织浓。", "照帘旌、微穿丽日，动罗幕、轻转香风。", "天上良辰，人间淑景，生贤和气显殊锺。", "映时表、南山北斗，相并两穹崇。", "须知道、英明罕此，文武谁同。", "奉慈亲、承颜戏彩，更闻吉梦占熊。", "扫蛮氛、遂清三楚，定徐方、行策元功。", "趣召遄归，康时佐主，指挥谈笑虏巢空。", "寿觞举、器舟斟海，不用水精锺。", "休辞醉，千龄会遇，美事重重。"]'),
('song-ci-652','水调歌头','邵怀英','宋','宋词','song-ci','水调歌头','[]','香亲紫荷陌，和气满长沙。',114,'宋词/ci.song.10000.json','["香亲紫荷陌，和气满长沙。", "黄堂庶寝春晓，风软碧幢遮。", "天遣武夷仙客，来掌元戎金印，千骑拥高牙。", "收了绿林啸，喜动紫薇花。", "青藜杖，鸿宾略，属公家。", "长城应与借一，天语屡褒嘉。", "且伴彩衣行乐，指日丝纶飞诏，归去凤池夸。", "千岁祝眉寿，福海浩无涯。"]'),
('song-ci-653','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','韶华迤逦三春暮。',126,'宋词/ci.song.10000.json','["韶华迤逦三春暮。", "飞尽繁红无数。", "多情为与，牡丹长约，年年为主。", "晓露凝香，柔条千里，轻盈清素。", "最堪怜，玉质冰肌婀娜，江梅谩休争妒。", "翠蔓扶疏隐映，似碧纱笼罩，越溪游女。", "从前爱惜娇姿，终日愁风怕雨。", "夜月一帘，小楼魂断，有思量处。", "恐因循易嫁，东风烂熳，暗随春去。"]'),
('song-ci-654','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','小春时候，见早梅吐玉，裁琼妆白。',120,'宋词/ci.song.10000.json','["小春时候，见早梅吐玉，裁琼妆白。", "点点枝头光照眼，恼损柔肠情客。", "暗里芳心，出群标致，经岁成疏隔。", "如今风韵，何人依旧冰雪。", "冷艳潇洒天然，香姿肯易许，游蜂狂蝶。", "夜半黄昏担带了，多少清风明月。", "宋玉虽悲，元超虽恨，见了千愁歇。", "东君还许，有情取次攀折。"]'),
('song-ci-655','满庭芳','赵长卿','宋','宋词','song-ci','满庭芳','[]','爆竹声飞，屠苏香钿，华堂歌舞催春。',117,'宋词/ci.song.10000.json','["爆竹声飞，屠苏香钿，华堂歌舞催春。", "百年消息，经半已凌人。", "念我功名冷落，又重是、一岁还新。", "惊心事，安仁华鬓，年少已逡巡。", "明知生似寄，何须苦苦，役慕蹄轮。", "最难忘、通经好学沈沦。", "况是读书万卷，辜负他、此志难伸。", "从今去，灯窗勉进，云路岂无因。"]'),
('song-ci-656','花心动','赵长卿','宋','宋词','song-ci','花心动','[]','风软寒轻，暗香飘、扑面无限清楚。',127,'宋词/ci.song.10000.json','["风软寒轻，暗香飘、扑面无限清楚。", "乍淡乍浓，应想前村，定是早梅初吐。", "马儿行过坡儿下，危桥外、竹梢疏处。", "半斜露。", "花花蕊蕊，灿然满树。", "一晌看花凝伫。", "因念我西园，玉英真素。", "最是系心，婉娩精神，伴得水云仙侣。", "断肠没奈人千里，无计向、钗头频窥。", "泪如雨。", "那堪又还日暮。"]'),
('song-ci-657','踏莎行','赵长卿','宋','宋词','song-ci','踏莎行','[]','柳暗披风，桑柔宿雨。',68,'宋词/ci.song.10000.json','["柳暗披风，桑柔宿雨。", "一番绿遍江头树。", "莺花已过苦无多，看看又是春归去。", "病酒情怀，光阴如许。", "闲愁俏没安排处。", "新来著意与兜笼，身心苦役伊知否。"]'),
('song-ci-658','南歌子','赵长卿','宋','宋词','song-ci','南歌子','[]','春色烘衣暖，宫梅破鼻香。',62,'宋词/ci.song.10000.json','["春色烘衣暖，宫梅破鼻香。", "尽驱和气入兰堂。", "又是轻云微雨、下巫阳。", "酒带欢情重，醺醺气味长。", "晚来拂拭略梳妆。", "笑指一钩新月、上迥廊。"]'),
('song-ci-659','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','宿雨新晴天色好。',70,'宋词/ci.song.10000.json','["宿雨新晴天色好。", "秾李夭桃，一霎都开了。", "燕子归来深院悄。", "柳绵铺迳无人扫。", "咫尺莺花还又老。", "绿入闲阶，只有青青草。", "参揣前期谁可表。", "此情不语知多少。"]'),
('song-ci-660','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','镂玉裁琼莫比香。',64,'宋词/ci.song.10000.json','["镂玉裁琼莫比香。", "娉婷枝上殢春光。", "风流别有千般韵，割舍昏沈入醉乡。", "蜂共蝶，尽乾忙。", "檀心知未肯寻常。", "从来诗苦人消瘦，乞与幽窗富锦囊。"]'),
('song-ci-661','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','蜂蜜酿成花已飞。',64,'宋词/ci.song.10000.json','["蜂蜜酿成花已飞。", "海棠次第雨胭脂。", "园林检点春归也，只有萦风柳带垂。", "情默默，恨依依。", "可人天气日长时。", "东风恰好寻芳去，何事驱弛作别离。"]'),
('song-ci-662','江神子・江城子','赵长卿','宋','宋词','song-ci','江神子・江城子','[]','年年长见傲寒林。',86,'宋词/ci.song.10000.json','["年年长见傲寒林。", "压群英。", "有馀清。", "曾被芳心，红日恼诗情。", "玉质暗香无限意，偏婉娩，尽轻盈。", "今年潇洒照歧亭。", "更芳馨。", "也峥嵘。", "无奈多情，终是惜飘零。", "谁与东君收拾取，怕风雨，挫瑶琼。"]'),
('song-ci-663','南歌子','赵长卿','宋','宋词','song-ci','南歌子','[]','春思浓如酒，离心乱似绵。',62,'宋词/ci.song.10000.json','["春思浓如酒，离心乱似绵。", "一川芳草绿生烟。", "客里因循、重过艳阳天。", "屈指归期近，愁眉泪洒然。", "无端还被此情牵。", "为问桃源、还有再逢缘。"]'),
('song-ci-664','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','忆昔去年花下饮，团蛮争看酴醿。',70,'宋词/ci.song.10000.json','["忆昔去年花下饮，团蛮争看酴醿。", "酒浓花艳两相宜。", "醉中尝记得，裙带写新诗。", "还是春光惊已暮，此身犹在天涯。", "断肠无奈苦相思。", "忧心徒耿耿，分付与他谁。"]'),
('song-ci-665','一丛花','赵长卿','宋','宋词','song-ci','一丛花','[]','柳莺啼晓梦初惊。',94,'宋词/ci.song.10000.json','["柳莺啼晓梦初惊。", "香雾入帘清。", "胭脂淡注宫妆雅，似文君、犹带春酲。", "芳心婉娩，媚容绰约，桃李总消声。", "相如春思正萦萦。", "无奈惜花情。", "曲栏小槛幽深处，与殷勤、遮护娉婷。", "姚黄魏紫，十分颜色，终不似轻盈。"]'),
('song-ci-666','青玉案','赵长卿','宋','宋词','song-ci','青玉案','[]','天涯目断江南路。',80,'宋词/ci.song.10000.json','["天涯目断江南路。", "见芳草，迷风絮。", "绿暗花梢春几许。", "小桃寂寞，海棠零乱，飞尽胭脂雨。", "子规声里山城暮。", "月挂西南梦回处。", "满抱离愁推不去。", "双眉百皱，寸肠千缕，若事凭鳞羽。"]'),
('song-ci-667','醉蓬莱','赵长卿','宋','宋词','song-ci','醉蓬莱','[]','是三春已暮，浪蕊彤残，牡丹零落。',120,'宋词/ci.song.10000.json','["是三春已暮，浪蕊彤残，牡丹零落。", "独殿清和，有佳名芍药。", "浅浅芳业，绣幢鼎鼎，更艳香绰约。", "浑似扬州，画楼卷起，翠帘红幕。", "倚槛轻盈，万娇千媚，故整霞裙，笑花寂寞。", "太守风流，拥笙歌围著。", "坐上诗人，二千里外，念此身飘泊。", "客眼看花，归心对酒，番成萧索。"]'),
('song-ci-668','雨中花慢','赵长卿','宋','宋词','song-ci','雨中花慢','[]','宿霭凝阴，天气未晴，峭寒勒住群葩。',118,'宋词/ci.song.10000.json','["宿霭凝阴，天气未晴，峭寒勒住群葩。", "倚栏无语，羞辜负年华。", "柳媚梢头翠眼，桃蒸原上红霞。", "可堪那、尽日狂风荡荡，细雨斜斜。", "东君底事，无奈薄幸，著意残害莺花。", "惟是我，惜春情重，说奈咨磋。", "故与殷勤索酒，更将油幕高遮。", "对花欢笑，从教风雨，著醉酬他。"]'),
('song-ci-669','蓦山溪','赵长卿','宋','宋词','song-ci','蓦山溪','[]','晓来雨霁。',101,'宋词/ci.song.10000.json','["晓来雨霁。", "弱柳摇新翠。", "丽日媚东风，正不暖不寒天气。", "幽禽弄舌，花上诉春光，高一饷，低一饷，清喨圆还碎。", "那知时势。", "春亦元无意。", "草木自敷荣，似人生、功名富贵。", "我咱谙分，随有亦随无，不妒富，不憎贫，歌酒闲游戏。"]'),
('song-ci-670','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','芍药开残春已尽。',70,'宋词/ci.song.10000.json','["芍药开残春已尽。", "红浅香乾，蝶子迷花阵。", "阵是清和人正困。", "行云散后空留恨。", "小字金书频与问。", "意曲心诚，未必他能信。", "千结柔肠愁寸寸。", "钿钗几日重相近。"]'),
('song-ci-671','虞美人','赵长卿','宋','宋词','song-ci','虞美人','[]','江梅虽是孤芳早。',66,'宋词/ci.song.10000.json','["江梅虽是孤芳早。", "争似酴醿好。", "凡红飞尽草妻迷。", "婀娜枝头才见、细腰肢。", "玉容消得仙源惜。", "满架香堆白。", "檀心应共酒相宜。", "割舍花前猛饮、倒金卮。"]'),
('song-ci-672','虞美人','赵长卿','宋','宋词','song-ci','虞美人','[]','冰塘浅绿生芳草。',66,'宋词/ci.song.10000.json','["冰塘浅绿生芳草。", "枝上青梅小。", "柳眉愁黛为谁开。", "似向东君、喜见故人来。", "碧桃销恨犹堪爱。", "妃子今何在。", "风光小院酒尊同。", "向晚一钩新月、落花风。"]'),
('song-ci-673','江神子・江城子','赵长卿','宋','宋词','song-ci','江神子・江城子','[]','小溪清浅照孤芳。',86,'宋词/ci.song.10000.json','["小溪清浅照孤芳。", "蕊珠娘。", "暗传香。", "春染粉容，清丽傅宫妆。", "金缕翠蝉曾记得，花密密、过雕墙。", "而今冷落水云乡。", "念平康。", "转情伤。", "梦断巫云，空恨楚襄王。", "冰雪肌肤消瘦损，愁满地、对斜阳。"]'),
('song-ci-674','醉蓬莱','赵长卿','宋','宋词','song-ci','醉蓬莱','[]','是平分秋色，梦草池塘，暖风帘幕。',120,'宋词/ci.song.10000.json','["是平分秋色，梦草池塘，暖风帘幕。", "昨夜三台，灿天边芝角。", "自是君家，庆流泽远，降生申崧岳。", "厚德温良，高才粹雅，渊源学博。", "何事丹墀，尚淹阔步，未许中原，少勤方略。", "且对笙歌，醉黄金错落。", "蕊洞珠宫，媚人桃李，趁青春绰约。", "绿意红情，成阴结子，五云楼阁。"]'),
('song-ci-675','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','春事犹馀十日，吴蚕早已三眠。',68,'宋词/ci.song.10000.json','["春事犹馀十日，吴蚕早已三眠。", "多情忍对落花前。", "酴醿飘暖雪，荷叶媚晴天。", "香淡无心浸酒，绿浮可意邀船。", "时光堪恨也堪怜。", "单衣三月暮，歌扇一番圆。"]'),
('song-ci-676','青玉案','赵长卿','宋','宋词','song-ci','青玉案','[]','去年社日东风里。',80,'宋词/ci.song.10000.json','["去年社日东风里。", "向三径、开桃李。", "脆管危弦随意起。", "绿阴红影，暖香繁蕊，伴我醺醺醉。", "今年社日空垂泪。", "客舍看花甚情意。", "江上危楼愁独倚。", "欲将心事，巧凭来燕，说与人憔悴。"]'),
('song-ci-677','南歌子','赵长卿','宋','宋词','song-ci','南歌子','[]','枝上红飞尽，梢头绿已匀。',62,'宋词/ci.song.10000.json','["枝上红飞尽，梢头绿已匀。", "游丝柳絮媚青春。", "向晚暖风帘幕、练光新。", "春已匆匆去，那堪话别情。", "刘郎几日便登程。", "告你觅些欢笑、送行人。"]'),
('song-ci-678','醉落魄・一斛珠','赵长卿','宋','宋词','song-ci','醉落魄・一斛珠','[]','麦畦匀绿。',67,'宋词/ci.song.10000.json','["麦畦匀绿。", "枝头屑屑飞梅玉。", "伤心何事人南北。", "断尽回肠，忍听阳关曲。", "倚窗青荫亭亭竹。", "好风敲动声相续。", "夜阑怕见银台烛。", "会得离情，他也泪速速。"]'),
('song-ci-679','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','密雨随风，咋来一夜檐声溜。',49,'宋词/ci.song.10000.json','["密雨随风，咋来一夜檐声溜。", "奈何僝僽。", "官路梅花瘦。", "赋得多情，怕到春时候。", "如今一病非因酒。", "试问君知否。"]'),
('song-ci-680','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','春到垂杨，嫩黄染就金丝软。',50,'宋词/ci.song.10000.json','["春到垂杨，嫩黄染就金丝软。", "丽晴新暖。", "涌翠千山远。", "为甚年年，眉向东风展。", "闲消遣。", "欲归犹懒。", "渔笛天将晚。"]'),
('song-ci-681','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','轻暖轻寒，赏花天气春将半。',50,'宋词/ci.song.10000.json','["轻暖轻寒，赏花天气春将半。", "柳摇金线。", "求友莺相唤。", "玉腕蛾眉，意眼频频眄。", "歌喉软。", "玉卮受劝。", "一醉应相拼。"]'),
('song-ci-682','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','夜雨如倾，满溪添涨桃花水。',50,'宋词/ci.song.10000.json','["夜雨如倾，满溪添涨桃花水。", "落红铺地。", "枝上堆浓翠。", "去年如今，常伴酴醿醉。", "今年里。", "离家千里。", "独猛东风泪。"]'),
('song-ci-683','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','啼鸟喃喃，恨春归去春谁管。',50,'宋词/ci.song.10000.json','["啼鸟喃喃，恨春归去春谁管。", "日和风暖。", "绿暗闲庭院。", "还忆当年，绮席新相见。", "人已远。", "水流云散。", "空结多情怨。"]'),
('song-ci-684','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','弱质纤姿俪素妆。',64,'宋词/ci.song.10000.json','["弱质纤姿俪素妆。", "水沈山麝郁幽香。", "直疑姑射来天上，要恼人间傅粉郎。", "简酿酒，枕为囊。", "更馀风味胜糖霜。", "肯如红紫空姚冶，谩惹游蜂戏蝶忙。"]'),
('song-ci-685','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','玉容应不羡梅妆。',64,'宋词/ci.song.10000.json','["玉容应不羡梅妆。", "檀心特地赛炉香。", "半臧密叶墙头女，勾引酡颜马上郎。", "樽乏酒，且倾囊。", "蟹螯糟熟似黏霜。", "一年光景浑如梦，可惜人生忙处忙。"]'),
('song-ci-686','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','洗尽铅华不著妆。',64,'宋词/ci.song.10000.json','["洗尽铅华不著妆。", "一般真色自生香。", "飘飘何处凌波女，故故相迎马上郎。", "寻谱谍，发诗囊。", "绝胜梅萼嫁冰霜。", "故山寒食依然在，句引东坡旅兴忙。"]'),
('song-ci-687','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','镂玉裁琼学靓妆。',64,'宋词/ci.song.10000.json','["镂玉裁琼学靓妆。", "不须沈水自然香。", "好随梅蕊妆宫额，肯似桃花误阮郎。", "羞傅粉，贱香囊。", "何劳傲雪与凌霜。", "新来句引无情眼，拼为东风一晌忙。"]'),
('song-ci-688','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','绰约肌肤巧样妆。',64,'宋词/ci.song.10000.json','["绰约肌肤巧样妆。", "风流元自有清香。", "未应傅粉疑平叔，却笑荷花似六郎。", "浮蚁瓮，入诗囊。", "学人消瘦怯风霜。", "午窗一枕庄周梦，甘作花心粉蝶忙。"]'),
('song-ci-689','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','去年元夜，正钱塘，看天街灯烛。',63,'宋词/ci.song.10000.json','["去年元夜，正钱塘，看天街灯烛。", "闹蛾儿转处，熙熙语笑，百万红妆女。", "今年肯把轻辜负。", "列荧煌千炬。", "趁闲身未老，良辰美景，款醉新歌舞。"]'),
('song-ci-690','小重山','赵长卿','宋','宋词','song-ci','小重山','[]','清晚窗前杜宇啼。',70,'宋词/ci.song.10000.json','["清晚窗前杜宇啼。", "游仙惊梦醉，断魂迷。", "起来窗下看盆池。", "伤春去，消瘦不胜衣。", "柳陌记年时。", "行云音信杳、与心违。", "空教攒恨入双眉。", "人已远，红叶莫题诗。"]'),
('song-ci-691','小重山','赵长卿','宋','宋词','song-ci','小重山','[]','绿示阴阴春已休。',70,'宋词/ci.song.10000.json','["绿示阴阴春已休。", "群花飘尽也，不胜愁。", "游丝飞絮两悠悠。", "迷芳草，日暖雨初收。", "深院小迟留。", "好香烧一炷，细烟浮。", "更听羯鼓打梁州。", "恼人处，宿酒尚扶头。"]'),
('song-ci-692','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','梅花有意舒香粉。',52,'宋词/ci.song.10000.json','["梅花有意舒香粉。", "舒香已得先春信。", "香与露华清。", "露浓愁杀人。", "酒多愁愈重。", "此意谁能共。", "泪湿染衣斑。", "夜霜金缕寒。"]'),
('song-ci-693','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','梅花枝上东风软。',52,'宋词/ci.song.10000.json','["梅花枝上东风软。", "朝来吹散真香远。", "雅淡有馀清。", "客心和泪倾。", "美人临别夜。", "月晃灯初灺。", "玉枕小屏山。", "眉尖曾细看。"]'),
('song-ci-694','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','烟姿玉骨尘埃外，看自有神仙格。',125,'宋词/ci.song.10000.json','["烟姿玉骨尘埃外，看自有神仙格。", "花中越样风流，曾是名标清客。", "月夜香魂，雪天孤艳，可堪怜惜。", "向枝间且作，东风第一，和羹事、期他日。", "闻道春归未识。", "问伊家、却知消息。", "当时恼杀林逋，空绕团栾千百。", "横管轻吹处，馀香散、阿谁偏得。", "寿阳宫、应有佳人，待与点、新妆额。"]'),
('song-ci-695','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','苇绡开得仙花，就中最有佳人似。',126,'宋词/ci.song.10000.json','["苇绡开得仙花，就中最有佳人似。", "香肌胜雪，千般揉缚，禁他风雨。", "缟夜精神，繁春标致，忍教孤负。", "怅潘郎去后，河阳满县，知他是、谁为主。", "多谢文章吏部。", "遇衔杯、不曾轻许。", "应知这底，无言情绪，难为分付。", "吹遍春风，耀残明月，总伤心处。", "待闲亭夜永，游人散后，作飞仙去。"]'),
('song-ci-696','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','天教占得如簧，巧声乍啭千娇媚。',124,'宋词/ci.song.10000.json','["天教占得如簧，巧声乍啭千娇媚。", "金衣衬著，风流模样，於中可是。", "红杏香中，绿杨阴处，多应饶你。", "向黄昏、苦苦娇啼怨别，那堪更、东风起。", "别有诗肠鼓吹。", "未关他、等闲俗耳。", "双柑斗酒，当时曾是，高人留意。", "南国春归，上阳花落，止添憔悴。", "念啼声欲碎，何人解作留春计。"]'),
('song-ci-697','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','淡烟轻霭濛濛，望中乍歇凝晴昼。',123,'宋词/ci.song.10000.json','["淡烟轻霭濛濛，望中乍歇凝晴昼。", "才惊一霎催花，还又随风过了。", "清带梨梢，晕含桃脸，添春多少。", "向海棠点点，香红染遍，分明是、胭脂透。", "无奈芳心滴碎，阻游人、踏青携手。", "檐头线断，空中丝乱，才晴却又。", "帘幕闲垂处，轻风送、一番寒峭。", "正留君不住，潇潇更下黄昏后。"]'),
('song-ci-698','胜胜慢・声声慢','赵长卿','宋','宋词','song-ci','胜胜慢・声声慢','[]','浓芳满地，秀色连天，和烟带雨萋萋。',119,'宋词/ci.song.10000.json','["浓芳满地，秀色连天，和烟带雨萋萋。", "几许芳心，还解报得春晖。", "当时谢郎梦里，似殷勤、传与新诗。", "却为甚、动长门怨感，南浦伤离。", "追想天涯行客，应解拥车轮，步步相随。", "惆怅如丝，正是欲断肠时。", "凭高望中不见，路悠悠、南北东西。", "春去也，怨王孙、犹自未归。"]'),
('song-ci-699','胜胜慢・声声慢','赵长卿','宋','宋词','song-ci','胜胜慢・声声慢','[]','金垂烟重，雪扬风轻，东风惯得多娇。',119,'宋词/ci.song.10000.json','["金垂烟重，雪扬风轻，东风惯得多娇。", "秀色依依，偏应绿水朱楼。", "腰肢先来太瘦，更眉尖、惹得闲愁。", "牵情处，是张郎年少，一种风流。", "别后长堤目断，空记得当时，马上墙头。", "细雨轻烟，何处夕系扁舟。", "叮咛再须折赠，劝狂风、休挽长条。", "春未老，到成阴、终待共游。"]'),
('song-ci-700','南歌子','赵长卿','宋','宋词','song-ci','南歌子','[]','黯霭阴云覆，滂沱急雨飞。',62,'宋词/ci.song.10000.json','["黯霭阴云覆，滂沱急雨飞。", "洗残枝上乱红稀。", "恰是退花天气、困人时。", "向晓春酲重，偎人起较迟。", "薄罗初见拭轻衣。", "笑拭新妆、须要剪酴醿。"]'),
('song-ci-701','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','寒食风霜最可人。',48,'宋词/ci.song.10000.json','["寒食风霜最可人。", "梨花榆火一时新。", "心头眼底总宜春。", "薄暮归吟芳草路，落红深处鹧鸪声。", "东风疏雨唤愁生。"]'),
('song-ci-702','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','柳老抛绵春已深。',48,'宋词/ci.song.10000.json','["柳老抛绵春已深。", "夹衣初试晓寒轻。", "别离无奈此时情。", "先自愁怀容易感，不堪闻底子规声。", "西楼料得数回程。"]'),
('song-ci-703','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','不愤江梅喷暗香。',48,'宋词/ci.song.10000.json','["不愤江梅喷暗香。", "春前腊后正凄凉。", "霜风雪月忍思量。", "斜倚幽林如有恨，玉鳞飞后转堪伤。", "时人那解识孤芳。"]'),
('song-ci-704','朝中措','赵长卿','宋','宋词','song-ci','朝中措','[]','别来无事不思量。',56,'宋词/ci.song.10000.json','["别来无事不思量。", "霜日最凄凉。", "凝想倚栏干处，攒眉应为萧郎。", "梅花岂管人消瘦，只恁自芬芳。", "寄语行人知否，梅花得似人香。"]'),
('song-ci-705','昭君怨','赵长卿','宋','宋词','song-ci','昭君怨','[]','隔叶乳鸦声软。',48,'宋词/ci.song.10000.json','["隔叶乳鸦声软。", "啼断日斜影转。", "杨柳小腰肢。", "画楼西。", "役损风流心眼。", "眉上新愁无限。", "极目送云行。", "此时情。"]'),
('song-ci-706','桃源忆故人','赵长卿','宋','宋词','song-ci','桃源忆故人','[]','夜来一夜东风暖。',56,'宋词/ci.song.10000.json','["夜来一夜东风暖。", "春到桃腮柳眼。", "对景可堪肠断。", "强把愁眉展。", "花期惹起归期念。", "前事从头忖遍。", "凝想水遥山远。", "空结相思怨。"]'),
('song-ci-707','长相思','赵长卿','宋','宋词','song-ci','长相思','[]','花飞飞。',44,'宋词/ci.song.10000.json','["花飞飞。", "柳依依。", "帘卷东风日正迟。", "社前双燕归。", "药栏东，药栏西。", "记得当时素手携。", "弯弯月似眉。"]'),
('song-ci-708','感皇恩','赵长卿','宋','宋词','song-ci','感皇恩','[]','景物一番新，熙熙时候。',77,'宋词/ci.song.10000.json','["景物一番新，熙熙时候。", "小院融和渐长昼。", "东君有意，为怜纤腰消瘦。", "软风吹破眉间皱。", "袅袅枝头，轻黄微透。", "舞到春深转清秀。", "锦囊多感，又更新来伤酒。", "断肠无语凭栏久。"]'),
('song-ci-709','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','笙歌间错华筵启。',61,'宋词/ci.song.10000.json','["笙歌间错华筵启。", "喜新春新岁。", "菜传纤手青丝细。", "和气入、东风里。", "幡儿胜儿都姑媂。", "戴得更忔戏。", "愿新春已后，吉吉利利。", "百事都入意。"]'),
('song-ci-710','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','赤栏干外桃花雨。',52,'宋词/ci.song.10000.json','["赤栏干外桃花雨。", "飞花已觉春归去。", "柳色碧依依。", "浓阴春昼迟。", "海棠红未破。", "匀糁胭脂颗。", "风雨也相饶。", "应怜粉面娇。"]'),
('song-ci-711','丑奴儿・采桑子','赵长卿','宋','宋词','song-ci','丑奴儿・采桑子','[]','牡丹已过酴醿谢，飞尽繁花。',52,'宋词/ci.song.10000.json','["牡丹已过酴醿谢，飞尽繁花。", "浓翠啼鸦。", "绿水桥边卖酒家。", "年时携手寻春去，满引流霞。", "往事堪嚓。", "犹喜潘郎鬓未华。"]'),
('song-ci-712','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','帘卷轻风怜小春。',48,'宋词/ci.song.10000.json','["帘卷轻风怜小春。", "荷枯菊悴正愁人。", "江梅喜见一枝新。", "料得主人偏爱惜，也应冰雪好精神。", "故园桃李莫生嗔。"]'),
('song-ci-713','清平乐','赵长卿','宋','宋词','song-ci','清平乐','[]','楚梅娇小。',55,'宋词/ci.song.10000.json','["楚梅娇小。", "好是霜天晓。", "宿酒恼人香暗绕。", "浸影碧波池沼。", "生成素淡芳容。", "不须抹黛匀红。", "准拟凝成阴结子，莫教枉费春工。"]'),
('song-ci-714','清平乐','赵长卿','宋','宋词','song-ci','清平乐','[]','绮疏新晓。',54,'宋词/ci.song.10000.json','["绮疏新晓。", "学语雏莺巧。", "烟暖瑶阶梧叶老。", "满地东风芳草。", "少年不合风流。", "偿他酒债花愁。", "望断绿芜春去，销魂懒上层楼。"]'),
('song-ci-715','更漏子','赵长卿','宋','宋词','song-ci','更漏子','[]','日彤彤，风荡荡。',58,'宋词/ci.song.10000.json','["日彤彤，风荡荡。", "帘外柳花飞扬。", "红有限，绿无穷。", "雨晴芳径中。", "肠寸结。", "萦离别。", "还是去年时节。", "春暮也，子归啼。", "伤春三月时。"]'),
('song-ci-716','诉衷情','赵长卿','宋','宋词','song-ci','诉衷情','[]','檀心刻玉几千重。',54,'宋词/ci.song.10000.json','["檀心刻玉几千重。", "开处对房栊。", "黄昏淡月笼艳，香与酒争浓。", "宜轻素，鄙轻红。", "思无穷。", "化工著意，南南北北，一种东风。"]'),
('song-ci-717','小重山','赵长卿','宋','宋词','song-ci','小重山','[]','枝上杨花糁玉尘。',70,'宋词/ci.song.10000.json','["枝上杨花糁玉尘。", "晚风扶起处，雪轻盈。", "扑人点点细无声。", "谁能惜，撩乱满江城。", "忍泪未须倾。", "十年追往事，叹流莺。", "晓来雨过转伤情。", "铺池绿，遣恨寄浮萍。"]'),
('song-ci-718','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','绿尽烧痕芳草遍。',70,'宋词/ci.song.10000.json','["绿尽烧痕芳草遍。", "不暖不寒，切莫辜良宴。", "罨画屏风开羽扇。", "薄罗衫子仙衣练。", "晚雨小池添水面。", "戏跃赪鳞，又向波心见。", "持酒伊听声宛转。", "樽前唱彻昭阳怨。"]'),
('song-ci-719','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','梁上双双海燕归。',64,'宋词/ci.song.10000.json','["梁上双双海燕归。", "故人应不寄新诗。", "柳梧阴里高还下，帘幕中间去复回。", "追盛事，忆乌衣。", "王家巷陌日沈西。", "兴亡无限惊心语，说与时人总不知。"]'),
('song-ci-720','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','谡谡东风作雨寒。',64,'宋词/ci.song.10000.json','["谡谡东风作雨寒。", "无言独自凭栏干。", "绿肥红瘦春归去，恨逼愁侵酒怎宽。", "追往事，惜花残。", "残花往事总相关。", "风光台上伤心处，此意人休作等闲。"]'),
('song-ci-721','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','新元才过，渐融和气，先到帘帏。',64,'宋词/ci.song.10000.json','["新元才过，渐融和气，先到帘帏。", "谩闲绕、柳径花蹊里。", "探看试、春来未。", "年时曾把春抛弃。", "与春光陪泪。", "待今春、日日花前沈醉。", "款细偎红翠。"]'),
('song-ci-722','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','数声回雁。',64,'宋词/ci.song.10000.json','["数声回雁。", "几番疏雨，东风回暖。", "甚今年、立得春来晚。", "过人日、方相见。", "缕金幡胜教先办。", "著工夫裁剪。", "到那时睹当，须教滴惜，称得梅妆面。"]'),
('song-ci-723','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','冰檐垂箸，雪花飞絮，时方严肃。',64,'宋词/ci.song.10000.json','["冰檐垂箸，雪花飞絮，时方严肃。", "向寻常摇曳，凡花野草，怎生敢夸红绿。", "江梅孤洁无拘束。", "只温然如玉。", "自一般天赋，风流清秀，总不同粗俗。"]'),
('song-ci-724','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','而今风韵，旧时标致，总皆奇绝。',63,'宋词/ci.song.10000.json','["而今风韵，旧时标致，总皆奇绝。", "再相逢还是，春前腊后，粉面凝香雪。", "芳心自与群花别。", "尽孤高清洁。", "那情怀最是，与人好处，冷淡黄昏月。"]'),
('song-ci-725','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','雕墙风定，绮窗烛灺，沈吟独坐。',62,'宋词/ci.song.10000.json','["雕墙风定，绮窗烛灺，沈吟独坐。", "料雪霜深处，司花神女，暗里焚百和。", "恼人一阵香初过。", "把清愁薰破。", "更那堪得，冰姿玉貌，痛与惜则个。"]'),
('song-ci-726','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','龟纱隔雾，绣帘钩月，那时曾见。',63,'宋词/ci.song.10000.json','["龟纱隔雾，绣帘钩月，那时曾见。", "照影儿、觑了千回百转。", "素艳明於练。", "柔肠堆满相思愿。", "更重看几遍。", "是天然不用，施朱栊翠，羞损桃花面。"]'),
('song-ci-727','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','疏篱横出，绿枝斜露，笑盈盈地。',63,'宋词/ci.song.10000.json','["疏篱横出，绿枝斜露，笑盈盈地。", "悄一似、初睹东邻女，有无限、风流意。", "半开折得琼瑰蕊。", "惹新香沾袂。", "放曲屏珠幌胆瓶儿里，伴我醺醺睡。"]'),
('song-ci-728','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','冰澌池面。',63,'宋词/ci.song.10000.json','["冰澌池面。", "柳摇金线，春光无限。", "问梅花底事，收香藏蕊，到此方舒展。", "百花头上俱休管。", "且惊开俗眼。", "看绿阴结子，成功调鼎，有甚迟和晚。"]'),
('song-ci-729','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','溪桥山路。',63,'宋词/ci.song.10000.json','["溪桥山路。", "竹篱茅舍，凄凉风雨。", "被摧残沮挫，精神依旧，无奈相思苦。", "东君故与收拾取。", "忍教他尘土。", "向绿窗绣户，朱栏小槛，做个名花主。"]'),
('song-ci-730','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','雨孱风瘦，雪欺霜妒，时光牢落。',63,'宋词/ci.song.10000.json','["雨孱风瘦，雪欺霜妒，时光牢落。", "怎奈向、天与孤高出众，一任傍人恶。", "凡花且莫相嘲谑。", "尽强伊寂寞。", "便饶他、百计千方就做，酝藉如何学。"]'),
('song-ci-731','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','楼头月满。',63,'宋词/ci.song.10000.json','["楼头月满。", "栏干风度，有人肠断。", "为多情、役得神魂撩乱。", "又被梅萦绊。", "对花沈醉应须拼。", "且尊前相伴。", "恨无端玉笛，穿帘透幕，好梦还惊散。"]'),
('song-ci-732','探春令','赵长卿','宋','宋词','song-ci','探春令','[]','清江平淡，暗香潇洒，满林风露。',63,'宋词/ci.song.10000.json','["清江平淡，暗香潇洒，满林风露。", "渐枝上、也学杨花柳絮。", "轻逐春归去。", "东君著意勤遮护。", "总留他不住。", "幸西园别有，能言花貌，委曲关心愫。"]'),
('song-ci-733','宝鼎现','赵长卿','宋','宋词','song-ci','宝鼎现','[]','嚣尘尽扫，碧落辉腾，元宵三五。',191,'宋词/ci.song.10000.json','["嚣尘尽扫，碧落辉腾，元宵三五。", "更漏永、迟迟停鼓。", "天上人间当此遇。", "正年少、尽香车宝马，次第追随士女。", "看往来、巷陌连甍，簇起星逑无数。", "政简物阜清闲处。", "听笙歌、鼎沸频举。", "灯焰暖、庭帏高下，红影相交知几户。", "恣欢笑、道今宵景色，胜前时几度。", "细算来、皇都此夕，消得喧传今古。", "排备绮席成行，炉喷袅、沈檀轻缕。", "睹遨游彩仗，疑是神仙伴侣。", "欲飞去、恨难留住。", "渐到蓬瀛步。", "愿永逢、恁时恁节，且与风光为主。"]'),
('song-ci-734','青玉案','赵长卿','宋','宋词','song-ci','青玉案','[]','梅黄又见纤纤雨。',80,'宋词/ci.song.10000.json','["梅黄又见纤纤雨。", "客里情怀两眉聚。", "何处烟村啼杜宇。", "劝人归去，早思家转，听得声声苦。", "利名萦绊何时住。", "恼乱愁肠成万缕。", "满眼兴亡知几许。", "不如寻个，老松石畔，作个柴门户。"]'),
('song-ci-735','烛影摇红','赵长卿','宋','宋词','song-ci','烛影摇红','[]','梅雪飘香，杏花开艳燃春昼。',116,'宋词/ci.song.10000.json','["梅雪飘香，杏花开艳燃春昼。", "铜驼烟淡晓风轻，摇曳青青柳。", "海燕归来未久。", "向雕梁、初成对偶。", "日长人困，绿水池塘，清明时候。", "帘幕低垂，麝煤烟喷黄金兽。", "天涯人去杳无凭，不念东阳瘦。", "眉上新愁压旧。", "要消遣、除非殢酒。", "酒醒人静，月满南楼，相思还又。"]'),
('song-ci-736','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','银蟾光满，弄馀辉、冷浸江梅无力。',124,'宋词/ci.song.10000.json','["银蟾光满，弄馀辉、冷浸江梅无力。", "缓引柔条浮素蕊，横在闲窗虚壁。", "染纸挥毫，粉涂墨晕，不似今端的。", "天然造化，别是一般，清瘦踪迹。", "今夜翠葆堂深，梦回风定，因月才相识。", "先自离愁，那更被、晓角残更催逼。", "曙色将分，轻阴移尽，过眼难寻觅。", "江南图上，画工应为描得。"]'),
('song-ci-737','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','玉龙声杳，正瑶台曲舞，香山初彻。',120,'宋词/ci.song.10000.json','["玉龙声杳，正瑶台曲舞，香山初彻。", "褪粉掐酥千万颗，满地平铺银雪。", "草褥香茵，苔钱买住，留待黄昏月。", "有人妆罢，对花凝伫愁绝。", "休更恨落羞开，东君情分，自古多离别。", "好把芳心收拾取，与个和羹人说。", "摆脱风尘，消停酸苦，终有成时节。", "浮花浪蕊，到头不是生活。"]'),
('song-ci-738','阮郎归','赵长卿','宋','宋词','song-ci','阮郎归','[]','和风暖日小层楼。',56,'宋词/ci.song.10000.json','["和风暖日小层楼。", "人闲春事幽。", "杏花深处一声鸠。", "花飞水自流。", "寻旧梦，续扬州。", "眉山相对愁。", "忆曾和泪送行舟。", "清江古渡头。"]'),
('song-ci-739','虞美人','赵长卿','宋','宋词','song-ci','虞美人','[]','东风卷尽辛夷雪。',66,'宋词/ci.song.10000.json','["东风卷尽辛夷雪。", "逆旅清明节。", "黄昏烟雨失前山。", "陟遍朱栏、酒噤不禁寒。", "归来谁护衣篝火。", "倒拥文鸳卧。", "可堪连夜子规啼。", "唤得春归、人却未成归。"]'),
('song-ci-740','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','兰枯菊槁。',120,'宋词/ci.song.10000.json','["兰枯菊槁。", "是返魂香入，江南春早。", "谷静林幽人不见，梦与梨花颠倒。", "雪刻檀心，玉匀丰颊，妆趁严锺晓。", "海山么凤，绿衣何处飞绕。", "竹外孤袅一枝，古今解道，只有东坡老。", "莫倚广平心似铁，闲把珠玑挥扫。", "桃李舆台，冰霜宾客，月地还凄悄。", "暗香消尽，和羹心事谁表。"]'),
('song-ci-741','玉楼春','赵长卿','宋','宋词','song-ci','玉楼春','[]','江村百六春强半。',64,'宋词/ci.song.10000.json','["江村百六春强半。", "拍拍池塘春水满。", "风团柳絮舞如狂，雨压橘花香不散。", "阴阴巷陌闲庭院。", "小立危栏羞燕燕。", "不知何事未还乡，除却青春谁作伴。"]'),
('song-ci-742','谒金门','赵长卿','宋','宋词','song-ci','谒金门','[]','风又雨。',53,'宋词/ci.song.10000.json','["风又雨。", "满地残红无数。", "花不能言莺解语。", "晓来啼更苦。", "把酒东皋日暮。", "抵死留春春去。", "拟倩杨花寻去处。", "杨花无定据。"]'),
('song-ci-743','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','杨花飞尽莺声涩。',52,'宋词/ci.song.10000.json','["杨花飞尽莺声涩。", "杜娟唤得春归急。", "病酒起来迟。", "娇慵懒画眉。", "宝奁金鸭冷。", "重唤烧香饼。", "著意炼龙涎。", "纤纤手逴烟。"]'),
('song-ci-744','画堂春','赵长卿','宋','宋词','song-ci','画堂春','[]','小亭烟柳水溶溶。',57,'宋词/ci.song.10000.json','["小亭烟柳水溶溶。", "野花白白红红。", "恼人池上晚来风。", "吹损春容。", "又是清明天气，记当年、小院相逢。", "凭栏幽思几千重。", "残杏香中。"]'),
('song-ci-745','画堂春','赵长卿','宋','宋词','song-ci','画堂春','[]','夜来暖趁海棠时。',55,'宋词/ci.song.10000.json','["夜来暖趁海棠时。", "脸边匀透胭脂。", "乱红娇影困垂垂。", "睡损杨妃。", "多少肉温香润，朱唇绿鬓相偎。", "晚风何苦过台西。", "断送春归。"]'),
('song-ci-746','卜算子','赵长卿','宋','宋词','song-ci','卜算子','[]','春水满江南，三月多芳草。',53,'宋词/ci.song.10000.json','["春水满江南，三月多芳草。", "幽鸟闲将远恨来，一一都啼了。", "不学鸳鸯老。", "回首临平道。", "人道长眉似远山，山不似长眉好。"]'),
('song-ci-747','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','水边篱落独横枝，冉冉风烟岑寂。',119,'宋词/ci.song.10000.json','["水边篱落独横枝，冉冉风烟岑寂。", "踏雪寻芳村路永，竹屋西头遥识。", "蕙草香销，小桃红未，醉眼惊春色。", "离愁何处，断肠无限陈迹。", "憔悴素脸朱唇，天寒日暮，倚栏干无力。", "岁晚天涯驿使远，难寄江南消息。", "自笑平生，怜清惜淡，故园曾亲植。", "百花虽好，问还有恁标格。"]'),
('song-ci-748','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','肩舆晓踏江头月。',52,'宋词/ci.song.10000.json','["肩舆晓踏江头月。", "月华冷浸消残雪。", "雪月照疏篱。", "梅花三两枝。", "人怜花淡薄。", "花恨人牢落。", "不似那回时。", "醺醺醉玉肌。"]'),
('song-ci-749','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','开尽梅花，雪残庭户春来早。',50,'宋词/ci.song.10000.json','["开尽梅花，雪残庭户春来早。", "岁华偏好。", "只恐催人老。", "惟有诗情，犹被花枝恼。", "金樽倒。", "共成欢笑。", "终是清狂少。"]'),
('song-ci-750','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','手种梅花三四株。',64,'宋词/ci.song.10000.json','["手种梅花三四株。", "要看冰霜照清臞。", "朝来几朵茅檐下，竹外江头恐不如。", "凝玉面，吐香须。", "莫嫌孤瘦渐丰馀。", "化工不肯辜人意，做底欢娱报答渠。"]'),
('song-ci-751','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','["\u6ed5\u738b\u9601"]','只惯娇痴不惯愁。',64,'宋词/ci.song.10000.json','["只惯娇痴不惯愁。", "离情浑不挂眉头。", "可怜恼尽尊前客，却趁东风上小舟。", "真个去，不忺留。", "落花流水一春休。", "自怜不及春江水，随到滕王阁下流。"]'),
('song-ci-752','瑞鹤仙','赵长卿','宋','宋词','song-ci','瑞鹤仙','[]','海棠花半落。',126,'宋词/ci.song.10000.json','["海棠花半落。", "正蕙圃风生，兰亭香扑。", "青英暝池阁。", "任翻红飞絮，游丝穿幕。", "情怀易著。", "奈宿酲、情绪正恶。", "叹韶光渐改，年华荏苒，旧欢如许。", "追念凭肩盟誓，枕臂私言，尽成离索。", "记得忘却。", "当时事，那时约。", "怕灯前月下，得见则个，厌厌只待窥著。", "问新来、为谁萦牵，又还瘦削。"]'),
('song-ci-753','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','过尽征鸿来尽燕，故园消息茫然。',70,'宋词/ci.song.10000.json','["过尽征鸿来尽燕，故园消息茫然。", "一春憔悴有谁怜。", "怀家寒食夜，中酒落花天。", "见说江头春浪渺，殷勤欲送归船。", "别来此处最萦牵。", "断篷南浦雨，疏柳断桥烟。"]'),
('song-ci-754','一丛花','赵长卿','宋','宋词','song-ci','一丛花','[]','阶前春草乱愁芽。',94,'宋词/ci.song.10000.json','["阶前春草乱愁芽。", "尘暗绿窗纱。", "钗盟镜约知何限，最断肠、湓浦琵琶。", "南渚送船，西城折柳，遗恨在天涯。", "夜来魂梦到侬家。", "一笑脸如霞。", "莺啼燕恨西窗下，问何事、潘鬓先华。", "钟动五更，魂归千里，残角怨梅花。"]'),
('song-ci-755','柳梢青','赵长卿','宋','宋词','song-ci','柳梢青','[]','桃杏舒红。',61,'宋词/ci.song.10000.json','["桃杏舒红。", "迟迟暖日，媚景芳浓。", "紫燕穿帘，香泥著地，未乳巢空。", "千山万水重重。", "烟雨里、王维画中。", "芳草斜阳，无人江渡，蓑笠渔翁。"]'),
('song-ci-756','花心动','赵长卿','宋','宋词','song-ci','花心动','[]','绿水平湖，浸芙渠烂锦，艳胜倾国。',128,'宋词/ci.song.10000.json','["绿水平湖，浸芙渠烂锦，艳胜倾国。", "半敛半开，斜立斜敧，好似困娇无力。", "水仙应赴瑶池宴，醉归去、美人扶策。", "驻香驾、拥波心媚容，倩妆颜色。", "曾见苕川澄碧。", "匀粉面、溪头旧时相识。", "翠被绣裀，彩扇香篝，度岁杳无消息。", "露痕滴尽风前泪，追往恨、悠悠踪迹。", "动怨忆。", "多情自家赋得。"]'),
('song-ci-757','鼓笛慢・水龙吟','赵长卿','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','暑风吹雨仙源过，深院静，凉於水。',127,'宋词/ci.song.10000.json','["暑风吹雨仙源过，深院静，凉於水。", "莲花郎面，翠幢红粉，烘人香细。", "别院新番，曲成初按，词清声脆。", "奈难堪羞涩，朦松病眼，无心听，笙簧美。", "还记当年此际。", "叹飘零、萍踪千里。", "楚云寂寞，吴歌凄切，成何情意。", "因念而今，水乡潇洒，风亭高致。", "对花前可是，十分蒙斗，肯辜欢醉。"]'),
('song-ci-758','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','晚妆才罢，见栊丝匀玉，一团娇秀。',121,'宋词/ci.song.10000.json','["晚妆才罢，见栊丝匀玉，一团娇秀。", "趁得年光，长是向、金谷无花时候。", "不比莺莺，不关燕燕，不似章台柳。", "清凉无汗，雪肌潇洒难偶。", "好是斜月黄昏，瑶阶钿砌，百媚初含酒。", "恼杀多情香喷喷，双靥盈盈回首。", "倾国倾城，千金莫惜，兰蕙应难友。", "沈郎拚了，为花一味销瘦。"]'),
('song-ci-759','满庭芳','赵长卿','宋','宋词','song-ci','满庭芳','[]','竹飐斜梢，荷倾馀沥，晚风初到南池。',118,'宋词/ci.song.10000.json','["竹飐斜梢，荷倾馀沥，晚风初到南池。", "雨收池上，高柳乱蝉嘶。", "冉冉莲香满院，夕阳映、红浸庭闱。", "凉生到，碧瓜破玉，白酒酌玻璃。", "思量，浮世事，枯荣辱宠，欢喜忧悲。", "算劳心劳力，得甚便宜。", "粗有田园笑傲，拣些个、朋友追随。", "好时景，莫教挫过，撞著醉如泥。"]'),
('song-ci-760','满庭芳','赵长卿','宋','宋词','song-ci','满庭芳','[]','红藕洲塘，黄葵庭院，渚风时动清飔。',118,'宋词/ci.song.10000.json','["红藕洲塘，黄葵庭院，渚风时动清飔。", "素纨轻飐，凉色爽征衣。", "一一光阴日月，关情处、前事难期。", "空凝想，临鸾有恨，谁与画新眉。", "刀头，心寸折，江南厚约，惟是侬知。", "念默歌停舞，冷落屏帏。", "何日朱笼鹦鹉，迎门报、金勒东归。", "罗弦管，合欢声里，烂醉玉东西。"]'),
('song-ci-761','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','山路乱蝉吟，声隐茂林修竹。',53,'宋词/ci.song.10000.json','["山路乱蝉吟，声隐茂林修竹。", "恰值快风收雨，递荷香芬馥。", "破除愁虑酒宜多，把酒再三嘱。", "遥想溪亭潇洒，称晚凉新浴。"]'),
('song-ci-762','虞美人','赵长卿','宋','宋词','song-ci','虞美人','[]','二乔姊妹新妆了。',66,'宋词/ci.song.10000.json','["二乔姊妹新妆了。", "照水盈盈笑。", "多情相约五湖游。", "似向群花丛里、骋风流。", "丁香枝上千千结。", "怨惹相思切。", "争如特地嫁薰风。", "吐尽芳心点点、绛唇红。"]'),
('song-ci-763','醉蓬莱','赵长卿','宋','宋词','song-ci','醉蓬莱','[]','正火山槐夏，黛叶湘枝，荔子新摘。',120,'宋词/ci.song.10000.json','["正火山槐夏，黛叶湘枝，荔子新摘。", "千里驰驱，荐仙源佳席。", "浪比龙晴，未输崖蜜，灿烂然红摘。", "满贮雕盘，纤纤素手，丹苞新擘。", "梨栗粗疏，带酸橘柚，凡品多般，总羞标格。", "何以浓香，洗烦襟仙液。", "为爱真妃，再三珍重，价倾城倾国。", "玉骨冰肌，风流酝藉，直宜消得。"]'),
('song-ci-764','醉蓬莱','赵长卿','宋','宋词','song-ci','醉蓬莱','[]','见浴兰才罢，拂掠新妆，巧梳云髻。',120,'宋词/ci.song.10000.json','["见浴兰才罢，拂掠新妆，巧梳云髻。", "初试生衣，恰三裁贴体。", "艾虎宜男，朱符辟恶，好储祥纳吉。", "金凤钗头，应时戴了，千般忔戏。", "那更殷勤，再三祝愿，斗巧合欢，彩丝缠臂。", "刻玉香蒲，泛金觥迎醉。", "午日熏风，楚词高咏，度遏云声脆。", "赤口白舌，从今消灭，诸馀可意。"]'),
('song-ci-765','踏莎行','赵长卿','宋','宋词','song-ci','踏莎行','[]','树影将圆，林梢不动。',68,'宋词/ci.song.10000.json','["树影将圆，林梢不动。", "汗珠挹透纱衣重。", "荷风忽送雨飞来，晚凉习习生幽梦。", "珠箔高钩，瑶琴闲弄。", "移樽邀取蝉娟共。", "今宵拼著醉眠呵，夜香闻早添金凤。"]'),
('song-ci-766','醉落魄・一斛珠','赵长卿','宋','宋词','song-ci','醉落魄・一斛珠','["\u897f\u6e56"]','淡妆浓抹。',67,'宋词/ci.song.10000.json','["淡妆浓抹。", "西湖人面两奇绝。", "菖蒲角黍家家节。", "水戏鱼龙，十里画帘揭。", "凌波无限生尘袜。", "冰肌莹彻香罗雪。", "游船且莫催归楫。", "遮莫黄昏，天外有新月。"]'),
('song-ci-767','阮郎归','赵长卿','宋','宋词','song-ci','阮郎归','[]','东城沙软马蹄轻。',56,'宋词/ci.song.10000.json','["东城沙软马蹄轻。", "清和雨乍晴。", "柳阴曲径泣流莺。", "凄凉不忍听。", "休苦怨，莫悲鸣。", "何须雨泪倾。", "但将巧语写心诚。", "东君肯薄情。"]'),
('song-ci-768','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','乱叠青钱荷叶小。',70,'宋词/ci.song.10000.json','["乱叠青钱荷叶小。", "浓绿阴阴，学语雏莺巧。", "小树飞花芳径草。", "堆红衬碧於中好。", "梅子弄黄枝上早。", "春已归时，戏蝶游蜂少。", "细把新词才和了。", "鸡声已唤纱窗晓。"]'),
('song-ci-769','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','新晴水暖藕花红。',64,'宋词/ci.song.10000.json','["新晴水暖藕花红。", "烘人暑意晚来浓。", "共携纤手桥东路，杨柳青青一径风。", "深翠里，艳香中。", "双莺初下蕊珠宫。", "月笼粉面三更露，凉透萧萧一梦中。"]'),
('song-ci-770','江神子・江城子','赵长卿','宋','宋词','song-ci','江神子・江城子','[]','彩云飞尽楚天空。',86,'宋词/ci.song.10000.json','["彩云飞尽楚天空。", "碧溶溶。", "一帘风。", "吹起荷花，香雾喷人浓。", "明月凄凉多少恨，恨难许，我情锺。", "相思魂梦几时穷。", "洞房中。", "忆从容。", "须信别来，应也敛眉峰。", "好景良宵添怅望，无计与，一樽同。"]'),
('song-ci-771','新荷叶','赵长卿','宋','宋词','song-ci','新荷叶','["\u897f\u6e56"]','冷彻蓬壶，翠幢鼎鼎生香。',100,'宋词/ci.song.10000.json','["冷彻蓬壶，翠幢鼎鼎生香。", "十顷玻璃，望中无限清凉。", "遮风掩日，高低衬、密护红妆。", "阴阴湖里，羡他双浴鸳鸯。", "猛忆西湖，当年一梦难忘。", "折得曾将盖雨，归思如狂。", "水云千里，不堪更、回首思量。", "而今把酒，为伊沈醉何妨。"]'),
('song-ci-772','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','帘幕轻风洒洒，园林绿荫垂垂。',68,'宋词/ci.song.10000.json','["帘幕轻风洒洒，园林绿荫垂垂。", "楝花开遍麦秋时。", "雨深芳草渡，蝴蝶正慵飞。", "憔悴三春心事，风流一弄金衣。", "韶光老尽起深思。", "日长庭院里，徙倚听催归。"]'),
('song-ci-773','朝中措','赵长卿','宋','宋词','song-ci','朝中措','[]','荷钱浮翠点前溪。',56,'宋词/ci.song.10000.json','["荷钱浮翠点前溪。", "梅雨日长时。", "恰是清和天气，雕鞍又作分携。", "别来几日愁心折，针线小蛮衣。", "羞对绿阴庭院，衔泥燕燕于飞。"]'),
('song-ci-774','减字木兰花','赵长卿','宋','宋词','song-ci','减字木兰花','[]','柳丝摇翠。',52,'宋词/ci.song.10000.json','["柳丝摇翠。", "翠幄笼阴无限意。", "不绊行舟。", "只向江边绊客愁。", "月明风细。", "分付一江流去水。", "娇眼伤春。", "谁是章台欲折人。"]'),
('song-ci-775','卜算子','赵长卿','宋','宋词','song-ci','卜算子','[]','执手送行人，水满荷花浦。',52,'宋词/ci.song.10000.json','["执手送行人，水满荷花浦。", "旧恨新愁不忍论，泪压潇潇雨。", "行计已匆匆，无计留伊住。", "一点相思万里心，谁怕关山阻。"]'),
('song-ci-776','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','柳上斜阳红万缕，烘人满院荷香。',70,'宋词/ci.song.10000.json','["柳上斜阳红万缕，烘人满院荷香。", "晚凉初浴略梳妆。", "冠儿轻替枕，衫子染莺黄。", "蓄意新词轻缓唱，殷勤满捧瑶觞。", "醉乡日月得能长。", "仙源正闲散，伴我老高唐。"]'),
('song-ci-777','雨中花令','赵长卿','宋','宋词','song-ci','雨中花令','[]','绿锁窗纱梧叶底。',68,'宋词/ci.song.10000.json','["绿锁窗纱梧叶底。", "麦秋时、晓寒慵起。", "宿酒厌厌，残香冉冉，浑似那时天气。", "别日不堪频屈指。", "回头早、一年不啻。", "搔首无言，栏干十二，倚了又还重倚。"]'),
('song-ci-778','画堂春','赵长卿','宋','宋词','song-ci','画堂春','[]','湖光乘雨碧连天。',60,'宋词/ci.song.10000.json','["湖光乘雨碧连天。", "绕堤映、草色芊芊。", "舞风杨柳欲撕绵。", "依依起翠烟。", "还是春风客路，对花时、空负蝉娟。", "暮寒楼阁碧云间。", "罗袖成斑。"]'),
('song-ci-779','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','露挹新荷扑鼻香。',48,'宋词/ci.song.10000.json','["露挹新荷扑鼻香。", "恼人更漏乡浪浪。", "柳梳斜月上纱窗。", "小醉耳边私语好，五云楼阁羡刘郎。", "酒阑烛暗断回肠。"]'),
('song-ci-780','西江月','赵长卿','宋','宋词','song-ci','西江月','[]','水满平塘过雨，洗妆红褪芙蕖。',58,'宋词/ci.song.10000.json','["水满平塘过雨，洗妆红褪芙蕖。", "绿荷美影荫龟鱼。", "无限闲中景趣。", "潇洒高堂邃馆，那堪左右图书。", "凌云赋得似相如。", "多少风流态度。"]'),
('song-ci-781','卜算子','赵长卿','宋','宋词','song-ci','卜算子','[]','闲路踏花来，闲逐清和云。',53,'宋词/ci.song.10000.json','["闲路踏花来，闲逐清和云。", "来去虽然总是闲，有多少伤心处。", "红碧好池塘，朱绿深庭户。", "随分山歌社舞中，且乐陶陶趣。"]'),
('song-ci-782','清平乐','赵长卿','宋','宋词','song-ci','清平乐','[]','水乡清楚。',54,'宋词/ci.song.10000.json','["水乡清楚。", "襟袖销袢暑。", "绰约藕花初过雨。", "出浴杨妃无语。", "葡萄满酌玻璃。", "已拼一醉酬伊。", "浪卷夕阳红碎，池光飞上帘帏。"]'),
('song-ci-783','清平乐','赵长卿','宋','宋词','song-ci','清平乐','[]','清和时候。',54,'宋词/ci.song.10000.json','["清和时候。", "底事休交瘦。", "满酌流霞看舞袖。", "步步锦裀红皱。", "六么舞到虚催。", "几多深意徘徊。", "拼了明朝中酒，为伊更饮琼杯。"]'),
('song-ci-784','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','雾透龟纱月映栏。',48,'宋词/ci.song.10000.json','["雾透龟纱月映栏。", "麦秋天气怯衣单。", "楝花风软晓来寒。", "懒起麝煤重换火，暖香浓处敛眉山。", "眼波横浸绿云鬟。"]'),
('song-ci-785','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','薄雾轻阴酿晓寒。',48,'宋词/ci.song.10000.json','["薄雾轻阴酿晓寒。", "起来宿酒尚酡颜。", "柳莺何事苦关关。", "新恨旧愁俱唤起，当年紫袖看弓弯。", "泪和梅雨两潸潸。"]'),
('song-ci-786','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','牙领番腾一线红。',64,'宋词/ci.song.10000.json','["牙领番腾一线红。", "花儿新样喜相逢。", "薄纱衫子轻笼玉，削玉身材瘦怯风。", "人易老，恨难穷。", "翠屏罗幌两心同。", "既无闲事萦怀抱，莫把双蛾皱碧峰。"]'),
('song-ci-787','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','方池新涨蒲萄绿。',52,'宋词/ci.song.10000.json','["方池新涨蒲萄绿。", "晓来雨过花如浴。", "测测杏园风。", "梢头一捻红。", "危楼愁独倚。", "一寸心千里。", "宿酒尚微醺。", "懒装堆髻云。"]'),
('song-ci-788','西江月','赵长卿','宋','宋词','song-ci','西江月','[]','稳唱巧翻新曲，灵犀密意潜通。',58,'宋词/ci.song.10000.json','["稳唱巧翻新曲，灵犀密意潜通。", "荷花香染晚来风。", "相对恍然如梦。", "有恨眉尖皱碧，多情酒晕生红。", "此愁不是等闲浓。", "应为仙源倾动。"]'),
('song-ci-789','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','睡起风帘一派垂。',48,'宋词/ci.song.10000.json','["睡起风帘一派垂。", "失巢燕子傍人飞。", "日长深院委香泥。", "绿笋出林翻锦箨，红葵著雨褪胭脂。", "微风度竹入轻衣。"]'),
('song-ci-790','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','忆昔临平山下过。',70,'宋词/ci.song.10000.json','["忆昔临平山下过。", "无数荷花，照水无纤黦。", "短艇直疑天上坐。", "醉眠花里香无那。", "雨浥红妆娇娜娜。", "脉脉含情，欲向风前破。", "莫道晚来风景可。", "青房著子千千颗。"]'),
('song-ci-791','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','密叶阴阴翠幄深。',48,'宋词/ci.song.10000.json','["密叶阴阴翠幄深。", "梅黄弄雨正频频。", "榴花照眼一枝新。", "缑岭有人今毓粹，飞凫不日簉严宸。", "一尊敬寿太夫人。"]'),
('song-ci-792','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','["\u897f\u6e56"]','雨过西湖绿涨平。',48,'宋词/ci.song.10000.json','["雨过西湖绿涨平。", "环湖密柳暗藏莺。", "麦秋天气似清明。", "对策有人新切直，逢春不日尽施行。", "扁舟未用速归程。"]'),
('song-ci-793','青玉案','赵长卿','宋','宋词','song-ci','青玉案','[]','结堂雄占云烟表。',78,'宋词/ci.song.10000.json','["结堂雄占云烟表。", "万象争呈巧。", "老木参天溪四绕。", "乱山横秀，一湖澄照。", "天付阴晴好。", "夜空唤客清樽倒。", "明月飞来上林杪。", "凉满九宵风露浩。", "酒慵起舞，一声清啸。", "平压波声小。"]'),
('song-ci-794','青玉案','赵长卿','宋','宋词','song-ci','青玉案','[]','恍如辽鹤归华表。',78,'宋词/ci.song.10000.json','["恍如辽鹤归华表。", "阅尽人间巧。", "天乞一堂山对绕。", "微波不动，岸巾时照。", "照见星星好。", "舞风荷盖从敧倒。", "碧树生凉自天杪。", "谁识元龙胸次浩。", "骑鲸欲去，引杯独啸。", "醉眼青天小。"]'),
('song-ci-795','谒金门','赵长卿','宋','宋词','song-ci','谒金门','[]','今夜雨。',53,'宋词/ci.song.10000.json','["今夜雨。", "扫尽一番袢暑。", "宛似潇潇鸣远浦。", "短蓬何日去。", "自漉床头玉醑。", "清兴有谁知否。", "反笑功名能几许。", "槐宫非浪语。"]'),
('song-ci-796','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','江城向晓，被西风揉碎，一天丝雨。',120,'宋词/ci.song.10000.json','["江城向晓，被西风揉碎，一天丝雨。", "乱织离愁千万缕，多少关心情绪。", "促织鸣时，木犀开后，秋色还如许。", "那堪飘泊，异乡千里孤旅。", "应想帘幕闲垂，西楼东院，齐把归期数。", "记得临歧收泪眼，执手叮咛言语。", "白酒红萸，黄花绿橘，莫等闲辜负。", "朱笼归骑，甚时先报鹦鹉。"]'),
('song-ci-797','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','花王有意，念三秋寂寞，凄凉天气。',120,'宋词/ci.song.10000.json','["花王有意，念三秋寂寞，凄凉天气。", "木落烟深山雾冷，不比寻常风味。", "勒驾闲来，柳蒲憔悴，无限惊心事。", "仙容香艳，俨然春盛标致。", "雅态出格天姿，风流酝藉，羞杀岩前桂。", "寄语芙蓉临水际，莫骋芳颜妖丽。", "一朵凭栏，千花退避，恼得骚人醉。", "等闲风雨，更休僝僽容易。"]'),
('song-ci-798','声声慢','赵长卿','宋','宋词','song-ci','声声慢','[]','金风玉露，绿橘黄澄，商秋爽气飘逸。',121,'宋词/ci.song.10000.json','["金风玉露，绿橘黄澄，商秋爽气飘逸。", "南斗腾光，应是间生贤出。", "照人紫芝眉宇，更仙风、谁能俦匹。", "细屈指，到小春时候，恰则三日。", "莫论早年富贵，也休问文章，有如椽笔。", "尧舜逢君，启沃定知多术。", "而今且张锦幄，麝煤泛、暖香郁郁。", "华堂里，听瑶琴轻弄，水仙新律。"]'),
('song-ci-799','瑞鹤仙','赵长卿','宋','宋词','song-ci','瑞鹤仙','[]','西风苹末起。',127,'宋词/ci.song.10000.json','["西风苹末起。", "动院落清秋，新凉如水。", "纤歌遏云际。", "正美人翻曲，阳春轻丽。", "兰衣玉佩。", "拥南斗、光中一醉。", "有邦人、万口同声，赞叹我公恺悌。", "百里。", "年丰谷稔，事简刑清，颂声盈耳。", "鹏程九万，摹空展、垂天翼。", "定丹书飞下，彤墀归去，秘略家传小试。", "看封留、亘古功名，未容退避。"]'),
('song-ci-800','满庭芳','赵长卿','宋','宋词','song-ci','满庭芳','[]','雨洗长空，风清云路，又还毕备佳期。',118,'宋词/ci.song.10000.json','["雨洗长空，风清云路，又还毕备佳期。", "夜凉如水，一似去秋时。", "渺渺银河浪静，星桥外、香霭馡馡。", "霞轺举，鸾骖鹊驭，稳稳过飞梯。", "经年，成间阻，相逢无语，应喜应悲。", "怕玉绳低处，依旧睽离。", "和我愁肠万缕，嫦娥怨、底事来迟。", "广寒殿，春风桂魄，首与慰相思。"]'),
('song-ci-801','水调歌头','赵长卿','宋','宋词','song-ci','水调歌头','[]','今夕知何夕，秋色正平分。',114,'宋词/ci.song.10000.json','["今夕知何夕，秋色正平分。", "嫦娥此际，底事越样好精神。", "已是天高气肃，那更清风洒洒，万里没纤云。", "把酒临风饮，酒面起红鳞。", "歌一曲，舞一曲，捧金樽。", "从他妄想，老兔憔悴正纷纷。", "我为桂花拚醉，明日扶头不起，颠倒白纶巾。", "天若知人意，夜雨莫倾盆。"]'),
('song-ci-802','蓦山溪','赵长卿','宋','宋词','song-ci','蓦山溪','[]','满城风雨，又是重阳近。',102,'宋词/ci.song.10000.json','["满城风雨，又是重阳近。", "黄菊媚清秋，倚东篱、商量开尽。", "红萸白酒，景物一年年，人渐远，梦还稀，赢得无穷恨。", "钗分镜破，一一关方寸。", "强醉欲消除，醉魂醒、凄凉越闷。", "鸳鸯宿债，偿了恶因缘，当时事，只今愁，斑尽安仁鬓。"]'),
('song-ci-803','洞仙歌','赵长卿','宋','宋词','song-ci','洞仙歌','[]','芰荷已老，菊与芙蓉未。',105,'宋词/ci.song.10000.json','["芰荷已老，菊与芙蓉未。", "一夜秋容上岩桂。", "间蘩芜、嫩黄染就琼瑰，开未足，已早香传十里。", "从前分付处，明月清风，不用斜晖照佳丽。", "叹浮花，徒解咤，浅白深红，争似我、潇洒堆金积翠。", "看天阔、秋高露华清，见标致风流，更无尘意。"]'),
('song-ci-804','虞美人','赵长卿','宋','宋词','song-ci','虞美人','[]','西风明月临台榭。',66,'宋词/ci.song.10000.json','["西风明月临台榭。", "准拟中秋夜。", "一年等待到而今。", "为甚今宵陡顿、却无情。", "姮娥应怨孤眠苦。", "取次为云雨。", "素蟾特地暗中圆。", "未放清光容易、到仙源。"]'),
('song-ci-805','醉蓬莱','赵长卿','宋','宋词','song-ci','醉蓬莱','[]','正金风无露。',120,'宋词/ci.song.10000.json','["正金风无露。", "玉宇生凉，楚郊无暑。", "催起行人，恰槐黄时序。", "万里晴宵，几人争睹，快鹏抟一举。", "明月圆时，素秋中夜，凌云新赋。", "那更渊源，词锋轻锐，笔阵纵横，学通今古。", "誉望飞腾，是麟宗文虎。", "魁荐归来，华堂香里，与管弦为主。", "待看明年，彤墀射策，鳌头独步。"]'),
('song-ci-806','洞仙歌','赵长卿','宋','宋词','song-ci','洞仙歌','[]','黄花满地，庭院重阳后。',101,'宋词/ci.song.10000.json','["黄花满地，庭院重阳后。", "天气凄清透襟袖。", "动离情、最苦旅馆萧条，那更堪、风剪凋零飞柳。", "临歧曾执手。", "祝付叮咛，知会别来念人否。", "为多情，生怕分离，只知道、准拟别来消瘦。", "甚苦苦、促装赴归期，要趁他、橘绿澄黄时候。"]'),
('song-ci-807','夏云峰','赵长卿','宋','宋词','song-ci','夏云峰','[]','露华清。',111,'宋词/ci.song.10000.json','["露华清。", "天气爽、新秋已觉凉生。", "朱户小窗，坐来低按秦筝。", "几多妖艳，都总是、白雪馀声。", "那更、玉肌肤韵胜，体段轻盈。", "照人双眼偏明，况周郎、自来多病多情。", "把酒为伊，再三著意须听。", "销魂无语，一任侧耳与心倾。", "是我不卿卿，更有谁可卿卿。"]'),
('song-ci-808','感皇恩','赵长卿','宋','宋词','song-ci','感皇恩','[]','碧水浸芙容，秋风楚岸。',77,'宋词/ci.song.10000.json','["碧水浸芙容，秋风楚岸。", "三岁光阴转头换。", "且留都骑，未许匆匆分散。", "更持杯酒殷勤劝。", "休作等闲，别离人看。", "且对笙歌醉须拼。", "如君才调，掌得玉堂词翰。", "定应不久劳州县。"]'),
('song-ci-809','瑞鹤仙','赵长卿','宋','宋词','song-ci','瑞鹤仙','[]','败荷擎沼面，红叶舞林梢，光阴何速。',127,'宋词/ci.song.10000.json','["败荷擎沼面，红叶舞林梢，光阴何速。", "碧天静如水，金风透帘幕，露清蝉伏。", "追思往事，念当年、悲伤宋玉。", "渐危楼向晚，魂销处、倚遍阑干曲。", "凝目。", "一霎微雨，塞鸿声断，酒病相续。", "无情赏处，金井梧，东篱菊。", "渐兰桡归去，银蟾满夜，水村烟渡怎宿。", "负伊家、万愁千恨，甚时是足。"]'),
('song-ci-810','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','万里西风吹去旆，满城无奈离情。',70,'宋词/ci.song.10000.json','["万里西风吹去旆，满城无奈离情。", "甘棠也似戴公深。", "晓来风露里，叶叶做秋声。", "十载两番遗爱在，须知愁满宜春。", "楚天低处是归程。", "夕阳疏雨外，莫遣乱蝉鸣。"]'),
('song-ci-811','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','枫叶白苹秋未老，晚风吹泛轻艎。',70,'宋词/ci.song.10000.json','["枫叶白苹秋未老，晚风吹泛轻艎。", "青山沥沥水茫茫。", "情随流水远，恨逐暮山长。", "一点相思千点泪，眼前无限情伤。", "佳人犹自捧离觞。", "阳关休唱彻，唱彻断人肠。"]'),
('song-ci-812','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','亭树萧萧生暮凉。',64,'宋词/ci.song.10000.json','["亭树萧萧生暮凉。", "安排清梦到胡床。", "楚山楚水秋江外，江北江南客恨长。", "苹渚冷，橘汀黄。", "断魂残梦更斜阳。", "欲将此日悲秋泪，洒向江天哭楚狂。"]'),
('song-ci-813','蓦山溪','赵长卿','宋','宋词','song-ci','蓦山溪','[]','木犀开了。',102,'宋词/ci.song.10000.json','["木犀开了。", "还是生辰到。", "一笑对西风，喜人与、花容俱好。", "寿筵开处，香雾扑帘帏，笙簧奏，星河晓，拼取金罍倒。", "当年仙子，容易抛蓬岛。", "月窟与花期，要同向、人间不老。", "拈枝弄蕊，此乐几时穷，一岁里，一番新，莫与蟠桃道。"]'),
('song-ci-814','醉落魄・一斛珠','赵长卿','宋','宋词','song-ci','醉落魄・一斛珠','[]','伤离恨别。',67,'宋词/ci.song.10000.json','["伤离恨别。", "愁肠又似丁香结。", "不应斗顿音书绝。", "烟水连天，何处认红叶。", "残更数尽银缸灭。", "边城画角声呜咽。", "罗衾泪滴相思血。", "花影移来，摇碎半窗月。"]'),
('song-ci-815','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','初过菊花天，饯送月宫仙客。',53,'宋词/ci.song.10000.json','["初过菊花天，饯送月宫仙客。", "丹桂拒霜浓淡，映眉间黄色。", "红裙歌夜饮离觞，努力赴劲敌。", "惟愿捷书来到，道一声都得。"]'),
('song-ci-816','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','倚楼小小穿针女。',52,'宋词/ci.song.10000.json','["倚楼小小穿针女。", "秋光点点蛛丝雨。", "今夕是何宵。", "龙车乌鹊桥。", "经年谋一笑。", "岂解令人巧。", "不用问如何。", "人间巧更多。"]'),
('song-ci-817','卜算子','赵长卿','宋','宋词','song-ci','卜算子','[]','凉夜竹堂空，小睡匆匆醒。',52,'宋词/ci.song.10000.json','["凉夜竹堂空，小睡匆匆醒。", "庭院无人月上阶，满地栏干影。", "何处最知秋，风在梧桐井。", "夜半骖鸾弄玉笙，露湿衣裳冷。"]'),
('song-ci-818','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','蓼岸西风，小舟江上渔歌唱。',50,'宋词/ci.song.10000.json','["蓼岸西风，小舟江上渔歌唱。", "倚栏凝想。", "幂幂云垂帐。", "好事因循，寂寞闲惆怅。", "如何向。", "又来心上。", "空向高亭望。"]'),
('song-ci-819','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','淅淅蓼花风，怪道晓来凄恻。',53,'宋词/ci.song.10000.json','["淅淅蓼花风，怪道晓来凄恻。", "翻见密云抛雨，动一山秋色。", "从前多感为伤时，无处顿然寂。", "个事已寒前约，只晚阴凝碧。"]'),
('song-ci-820','品令','赵长卿','宋','宋词','song-ci','品令','[]','情难托。',66,'宋词/ci.song.10000.json','["情难托。", "离愁重、悄愁没处安著。", "那堪更、一叶知秋后，天色儿、渐冷落。", "马上征衫频搵泪，一半斑斑污却。", "别来为、思忆叮咛话，空赢得、瘦如削。"]'),
('song-ci-821','小重山','赵长卿','宋','宋词','song-ci','小重山','[]','一夜西风响翠条。',70,'宋词/ci.song.10000.json','["一夜西风响翠条。", "碧纱窗外雨，长凉飙。", "朝来绿涨水平桥。", "添清景，疏韵入芭蕉。", "坐久篆烟销。", "多情人去后，信音遥。", "即今消瘦沈郎腰。", "悲秋切，虚度可人宵。"]'),
('song-ci-822','采桑子','赵长卿','宋','宋词','song-ci','采桑子','[]','去年岩桂花香里，著意非常。',52,'宋词/ci.song.10000.json','["去年岩桂花香里，著意非常。", "月在东厢。", "酒与繁华一色黄。", "今年杯酒流连处，银烛交光。", "往事难忘。", "待把真诚问阿郎。"]'),
('song-ci-823','朝中措','赵长卿','宋','宋词','song-ci','朝中措','[]','柳林幂幂暮烟斜。',57,'宋词/ci.song.10000.json','["柳林幂幂暮烟斜。", "秋水浅平沙。", "楼外碧天无际，紫山断处横霞。", "星稀渐觉，东檐隐月，凉到窗纱。", "多少伤怀往事，隔溪灯火人家。"]'),
('song-ci-824','朝中措','赵长卿','宋','宋词','song-ci','朝中措','["\u94b1\u5858\u6c5f"]','征帆一缕转弯斜。',57,'宋词/ci.song.10000.json','["征帆一缕转弯斜。", "惊鹭起沙汀。", "点点随风逆上，满江飞破残霞。", "楼前光景，楼心红粉，蝉翼轻纱。", "却忆钱塘江上，曲栏横槛他家。"]'),
('song-ci-825','洞仙歌','赵长卿','宋','宋词','song-ci','洞仙歌','[]','广寒宫殿，不在人间世。',108,'宋词/ci.song.10000.json','["广寒宫殿，不在人间世。", "分付天香与岩桂。", "向西风、遥曳处，数十里知闻，金翠里、别有出群标致。", "东园盛事。", "五亩浓阴芘。", "必以诗书取荣贵。", "况一门，三秀才，未足钦崇，那更是、异姓同居兄弟。", "更细把、繁英祝姮娥，看禹浪飞腾，定应来岁。"]'),
('song-ci-826','似娘儿','赵长卿','宋','宋词','song-ci','似娘儿','[]','橘绿与澄黄。',76,'宋词/ci.song.10000.json','["橘绿与澄黄。", "今小春、已过重阳。", "晚来一霎霏微雨，单衣渐觉，西风冷也，无限情伤。", "孤馆最凄凉。", "天色儿、苦恁凄惶。", "离愁一枕灯残后，睡来不是，行行坐坐，月在迥廊。"]'),
('song-ci-827','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','一梦十年劳忆记。',70,'宋词/ci.song.10000.json','["一梦十年劳忆记。", "社燕宾鸿，来去何容易。", "宿酒半醒便午睡。", "芭蕉叶映纱窗翠。", "衬粉泥书双合字。", "鸾凤鸳鸯，总是双双意。", "已作吹箫长久计。", "鸳衾空有中宵泪。"]'),
('song-ci-828','夜行船','赵长卿','宋','宋词','song-ci','夜行船','[]','泪眼江头看锦树。',62,'宋词/ci.song.10000.json','["泪眼江头看锦树。", "别离又还秋暮。", "细水浮浮，轻风冉冉，稳送扁舟去。", "归去江山应得助。", "新诗定须多赋。", "有雁南来，槐溪千万，寄我惊人句。"]'),
('song-ci-829','清平乐','赵长卿','宋','宋词','song-ci','清平乐','[]','鸿来燕去。',54,'宋词/ci.song.10000.json','["鸿来燕去。", "又是秋光暮。", "冉冉流年嗟暗度。", "这心事还无据。", "寒窗露冷风清。", "旅魂幽梦频惊。", "何日利名俱赛，为予笑下愁城。"]'),
('song-ci-830','清平乐','赵长卿','宋','宋词','song-ci','清平乐','[]','秋容眼界。',54,'宋词/ci.song.10000.json','["秋容眼界。", "随寓浑堪爱。", "远岫连天横淡霭。", "望断孤鸿飞外。", "夕阳红树林坰。", "重重锦障横陈。", "一段江南景色，倩谁为下丹青。"]'),
('song-ci-831','一翦梅','赵长卿','宋','宋词','song-ci','一翦梅','[]','霁霭迷空晓未收。',70,'宋词/ci.song.10000.json','["霁霭迷空晓未收。", "羁馆残灯，永夜悲秋。", "梧桐叶上三更雨，别是人间一段愁。", "睡又不成梦又休。", "多愁多病，当甚风流。", "真情一点苦萦人，才下眉尖，恰上心头。"]'),
('song-ci-832','南歌子','赵长卿','宋','宋词','song-ci','南歌子','[]','此日知何日，他乡忆故乡。',62,'宋词/ci.song.10000.json','["此日知何日，他乡忆故乡。", "乱山深处过重阳。", "走马吹花、无复少年狂。", "黄菊擎枝重，红茱湿露香。", "扁舟随雁过潇湘。", "遥想莱庭、应恨不同觞。"]'),
('song-ci-833','醉花阴','赵长卿','宋','宋词','song-ci','醉花阴','[]','老去悲秋人转瘦。',62,'宋词/ci.song.10000.json','["老去悲秋人转瘦。", "更异乡重九。", "人意自凄凉，只有茱萸，岁岁香依旧。", "登高无奈空搔首。", "落照归鸦后。", "六代旧江山，满眼兴亡，一洗黄花酒。"]'),
('song-ci-834','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','西风转柂蒹葭浦。',52,'宋词/ci.song.10000.json','["西风转柂蒹葭浦。", "客愁生怕秋阑雨。", "衾冷梦魂惊。", "声声滴到明。", "不眠敧枕听。", "故故添新恨。", "新恨有谁知。", "天寒雁正稀。"]'),
('song-ci-835','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','炊烟一点孤村迥。',52,'宋词/ci.song.10000.json','["炊烟一点孤村迥。", "娇容敛尽天容净。", "雁字忽横秋。", "秋江泻客愁。", "银钩空寄恨。", "恨满凭谁问。", "袖手立西风。", "舟行秋色中。"]'),
('song-ci-836','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','雨滴梧桐点点愁。',48,'宋词/ci.song.10000.json','["雨滴梧桐点点愁。", "冷催秋色上帘钩。", "蛩声何事早知秋。", "一夜凉风惊去燕，满川晴涨漾轻鸥。", "怀人千里思悠悠。"]'),
('song-ci-837','满庭芳','赵长卿','宋','宋词','song-ci','满庭芳','[]','晚色沈沈，雨声寂莫，夜寒初冻云头。',118,'宋词/ci.song.10000.json','["晚色沈沈，雨声寂莫，夜寒初冻云头。", "晓来阶砌，一捻冷光浮。", "目断江天霭霭，低迷映、绿竹修修。", "多才客，高吟柳絮，还更上层楼。", "烹茶，新试水，人间清楚，物外遨游。", "胜似他、销金暖帐情柔。", "细看流风迥舞，终日价、浅酌轻讴。", "醺醺地，美人翻曲，消尽古今愁。"]'),
('song-ci-838','御街行','赵长卿','宋','宋词','song-ci','御街行','[]','晚来无奈伤心处。',94,'宋词/ci.song.10000.json','["晚来无奈伤心处。", "见红叶、随风舞。", "解鞍还向乱山深，黄昏后、不成情绪。", "先来离恨，打叠不下，天气还凄楚。", "风儿住后云来去。", "装撰些儿雨。", "无眠托首对孤灯，好语向谁分付。", "从来烦恼，吓得胆碎，此度难担负。"]'),
('song-ci-839','有有令','赵长卿','宋','宋词','song-ci','有有令','[]','前山减翠。',101,'宋词/ci.song.10000.json','["前山减翠。", "疏竹度轻风，日移金影碎。", "还又年华暮，看看是、新春至。", "那更堪、有个人人，似花似玉，温柔伶俐。", "准拟。", "恩情忔戏。", "拈弄上、则人难比。", "我也埋根竖柱，你也争些气。", "大家一捺头地。", "美中更美。", "厮守定、共伊百岁。"]'),
('song-ci-840','摊破丑奴儿・采桑子','赵长卿','宋','宋词','song-ci','摊破丑奴儿・采桑子','[]','树头红叶飞都尽，景物凄凉。',74,'宋词/ci.song.10000.json','["树头红叶飞都尽，景物凄凉。", "秀出群芳。", "又见江梅浅淡妆。", "也囉，真个是、可人香。", "兰魂蕙魄应羞死，独占风光。", "梦断高堂。", "月送疏枝过女墙。", "也囉，真个是、可人香。"]'),
('song-ci-841','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','日欲低时江景好，暮山紫翠重重。',70,'宋词/ci.song.10000.json','["日欲低时江景好，暮山紫翠重重。", "钓筒收尽碧潭空。", "一船霜夜月，两岸荻花风。", "遥忆暖春新向火，黄昏下了帘栊。", "水村渔浦舣孤篷。", "单衾愁梦断，无梦转愁浓。"]'),
('song-ci-842','南歌子','赵长卿','宋','宋词','song-ci','南歌子','[]','霜结凝寒夜，星辉识晓晴。',62,'宋词/ci.song.10000.json','["霜结凝寒夜，星辉识晓晴。", "兰膏重剔且教明。", "为照梢头香缕、一丝轻。", "坐久看看困，新词缀未成。", "梅花熏得酒初醒。", "更向耳边低道、月三更。"]'),
('song-ci-843','永遇乐','赵长卿','宋','宋词','song-ci','永遇乐','[]','宵露珠零，溅冰花薄，凝瑞偏早。',128,'宋词/ci.song.10000.json','["宵露珠零，溅冰花薄，凝瑞偏早。", "月练轻翻，风刀碎剪，青女呈纤巧。", "微丹枫缬，低摧蕉尾，不觉半池莲倒。", "最好是、千林橘柚，轻黄一村封了。", "佳人指冷，暗惊罗幕，一夜斜飞多少。", "怕倚银屏，愁看玉砌，金菊鲜鲜晓。", "伤嗟傅粉，佳期还未，何处冷沾衣透。", "争知人、临鸾试罢，与梅共瘦。"]'),
('song-ci-844','玉蝴蝶','赵长卿','宋','宋词','song-ci','玉蝴蝶','[]','片片空中剪水，巧妆春色，照耀江湖。',124,'宋词/ci.song.10000.json','["片片空中剪水，巧妆春色，照耀江湖。", "渐觉花球转柳，荚阵飞榆。", "散银杯、时时逐马。", "翻缟带、一一随车。", "遍帘隅。", "寒生冰箸，光剖明珠。", "应须。", "浅斟低唱，毡垂红帐，兽爇金炉。", "更向高楼，纵观吟醉谢娘扶。", "静时闻、竹声岩谷，漫不见、禽影江湖。", "尽踌躇。", "歌阑宝玉，赋就相如。"]'),
('song-ci-845','潇湘夜雨・满庭芳','赵长卿','宋','宋词','song-ci','潇湘夜雨・满庭芳','[]','斜点银缸，高擎莲炬，夜寒不奈微风。',117,'宋词/ci.song.10000.json','["斜点银缸，高擎莲炬，夜寒不奈微风。", "重重帘幕掩堂中。", "香渐远、长烟袅穟，光不定、寒影摇红。", "偏奇处，当庭月暗，吐焰如虹。", "红裳呈艳丽，□娥一见，无奈狂纵。", "试烦他纤手，卷上纱龙。", "开正好、银花照夜，堆不尽、金粟凝空。", "叮咛语，频将好事，来报主人公。"]'),
('song-ci-846','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','据炉肃坐，听瓶笙、别有天然宫徵。',120,'宋词/ci.song.10000.json','["据炉肃坐，听瓶笙、别有天然宫徵。", "纸帐屏山浑不俗，写出江南烟水。", "檠短灯青，灰闲香软，所欠惟梅矣。", "风飞无定，数声时颤窗纸。", "试问夜已何其，呼童起看，月上东墙未。", "天外忽闻征雁过，还把音书来寄。", "短笠埋烟，轻蓑鸣雨，已办征船计。", "放教归去，故乡江上鱼美。"]'),
('song-ci-847','摊破丑奴儿・采桑子','赵长卿','宋','宋词','song-ci','摊破丑奴儿・采桑子','[]','又是两分携。',76,'宋词/ci.song.10000.json','["又是两分携。", "憔悴损、看怎医治。", "烟村一带寒红绕，悲风红叶，残阳暮草，还似年时。", "愁绪暗犹夷。", "谩屈指、数遍归期。", "短檠灯烬无人问，此时只有，窗前素月，刚伴相思。"]'),
('song-ci-848','柳梢青','赵长卿','宋','宋词','song-ci','柳梢青','[]','云暗天低。',61,'宋词/ci.song.10000.json','["云暗天低。", "枫林凋翠，寒雁声悲。", "茅店儿前，竹篱巴后，初见横枝。", "盈盈粉面香肌。", "记月榭、当年见伊。", "有恨难传，无肠可断，立马多时。"]'),
('song-ci-849','祝英台近','赵长卿','宋','宋词','song-ci','祝英台近','[]','记临歧，销黯处。',95,'宋词/ci.song.10000.json','["记临歧，销黯处。", "离恨惨歌舞。", "恰是江梅，开遍小春暮。", "断肠一曲金衣，两行玉箸，酒阑后、欲行难去。", "恶情绪。", "因念锦幄香奁，别来负情素。", "冷落深闺，知解怨人否。", "料应宝瑟慵弹，露华懒傅，对鸾镜、终朝凝伫。"]'),
('song-ci-850','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','瓦湿鸳鸯，夜深霜重江风冷。',50,'宋词/ci.song.10000.json','["瓦湿鸳鸯，夜深霜重江风冷。", "月华明映。", "清浸梅梢粉。", "漏断寒浓，惹起当年恨。", "君休问。", "雁飞欲尽。", "没个南来信。"]'),
('song-ci-851','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','当日相逢，枕衾清夜纱窗冷。',50,'宋词/ci.song.10000.json','["当日相逢，枕衾清夜纱窗冷。", "翠梅低映。", "汗湿香腮粉。", "美满风情，结下无穷恨。", "凭谁问。", "此心难尽。", "说与他争信。"]'),
('song-ci-852','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','云霁山横，翠涛拥起千重恨。',50,'宋词/ci.song.10000.json','["云霁山横，翠涛拥起千重恨。", "砌成愁闷。", "那更梅花褪。", "凤管云笙，无不萦方寸。", "叮咛问。", "泪痕羞愠。", "界破香腮粉。"]'),
('song-ci-853','柳梢青','赵长卿','宋','宋词','song-ci','柳梢青','[]','千林落叶声声悲。',63,'宋词/ci.song.10000.json','["千林落叶声声悲。", "听凄惨、江皋雁飞。", "难似玉肌，总惊花貌，压倒芳菲。", "香心吐尽因谁。", "料调鼎、工夫易期。", "休唱阳关，莫歌白雪，雨泪沾衣。"]'),
('song-ci-854','西江月','赵长卿','宋','宋词','song-ci','西江月','[]','背日犹馀残雪，向阳初绽红梅。',58,'宋词/ci.song.10000.json','["背日犹馀残雪，向阳初绽红梅。", "腊寒那事更相宜。", "醉了还醒又醉。", "堪笑多愁早老，管他闲是闲非。", "对花酌酒两忘机。", "唱个哩囉囉哩。"]'),
('song-ci-855','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','一钩新月照西楼。',58,'宋词/ci.song.10000.json','["一钩新月照西楼。", "清夜思悠悠。", "那堪更被，征鸿嘹唳，绊惹离愁。", "倚栏不语情如醉，都总寄眉头。", "从前只为，惜他伶俐，举措风流。"]'),
('song-ci-856','别怨','赵长卿','宋','宋词','song-ci','别怨','[]','娇马频嘶。',77,'宋词/ci.song.10000.json','["娇马频嘶。", "晓霜浓、寒色侵衣。", "凤帷私语处，翻成离怨不胜悲。", "更与叮咛祝后期。", "素约谐心事，重来了、比看相思。", "如何见得，明年春事浓时。", "稳乘金腰袅，来烂醉、玉东西。"]'),
('song-ci-857','减字木兰花','赵长卿','宋','宋词','song-ci','减字木兰花','[]','小春天气。',52,'宋词/ci.song.10000.json','["小春天气。", "未唱阳关心已醉。", "红蓼秋容。", "后会何时得再逢。", "归期好事。", "仰看皇州扬雨露。", "百里恩波。", "拟欲留公无奈何。"]'),
('song-ci-858','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','去路马蹄轻，正是小春时节。',53,'宋词/ci.song.10000.json','["去路马蹄轻，正是小春时节。", "爱日暖烘江树，缀梅梢新雪。", "范滂揽辔正澄清，知我公明洁。", "分此仁风恺悌，济邻邦欢悦。"]'),
('song-ci-859','霜天晓角','赵长卿','宋','宋词','song-ci','霜天晓角','[]','合儿幽静处，围炉面小窗。',54,'宋词/ci.song.10000.json','["合儿幽静处，围炉面小窗。", "好是斗头儿坐，梅烟炷、返魂香。", "对火怯夜冷，猛饮消漏长。", "饮罢且收拾睡，斜月照、满帘霜。"]'),
('song-ci-860','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','宝篆龙煤烧欲残。',64,'宋词/ci.song.10000.json','["宝篆龙煤烧欲残。", "细听铜漏已更阑。", "纱窗斜月移梅影，特地笼灯仔细看。", "幽梦断，旧盟寒。", "那时屈曲小屏山。", "风光得似而今不，肯把花枝作等闲。"]'),
('song-ci-861','蓦山溪','赵长卿','宋','宋词','song-ci','蓦山溪','["\u897f\u6e56"]','玉妃整佩，绛节参差御。',102,'宋词/ci.song.10000.json','["玉妃整佩，绛节参差御。", "一笑唤春回，正江南、天寒岁暮。", "孤标独立，占断世间香，云屋冷，雪篱深，长记西湖路。", "人间尘土，不是留花处。", "羌管一声催，碎琼瑶、纷纷似雨。", "枝头著子，聊与世调羹，功就后，盍归休，还记来时不。"]'),
('song-ci-862','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','雪压前村曲径迷。',48,'宋词/ci.song.10000.json','["雪压前村曲径迷。", "万山寒立玉参差。", "孤舟独钓一蓑归。", "别坞时听风折竹，断桥闲看水流澌。", "一枝冻蕊出疏篱。"]'),
('song-ci-863','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','风卷霜林叶叶飞。',48,'宋词/ci.song.10000.json','["风卷霜林叶叶飞。", "雁横寒影一行低。", "淡烟衰草不胜诗。", "白酒已篘浮蚁熟，黄鸡未老藁头肥。", "问侬不醉待何时。"]'),
('song-ci-864','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','忆为梅花醉不醒。',48,'宋词/ci.song.10000.json','["忆为梅花醉不醒。", "断桥流水去无声。", "鹭翘沙嘴亦多情。", "疏影卧波波不动，暗香浮月月微明。", "高楼羌管未须横。"]'),
('song-ci-865','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','离绪千重，角声偏著羁人枕。',50,'宋词/ci.song.10000.json','["离绪千重，角声偏著羁人枕。", "那堪酒醒。", "句引愁难整。", "门锁黄昏，月浸梅花冷。", "人初静。", "斗垂天迥。", "雁落清江影。"]'),
('song-ci-866','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','门外寒江泊小船。',64,'宋词/ci.song.10000.json','["门外寒江泊小船。", "月明留客小窗前。", "夜香烧尽更声远，斗帐低垂暖意生。", "醺著酒，炙些灯。", "伴他针线懒成眠。", "情知今夜鸳鸯梦，不似孤篷宿雁边。"]'),
('song-ci-867','望江南・忆江南','赵长卿','宋','宋词','song-ci','望江南・忆江南','[]','山又水，云岫插峰峦。',64,'宋词/ci.song.10000.json','["山又水，云岫插峰峦。", "断雁飞时霜月冷，乱鸦啼处日衔山。", "疑在画图间。", "金乌转，游子损朱颜。", "别泪盈襟双袖湿，春心不放两眉间。", "此去几时还。"]'),
('song-ci-868','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','枫林飒飒凋寒叶。',52,'宋词/ci.song.10000.json','["枫林飒飒凋寒叶。", "汀苹败蓼遥相接。", "景物已非秋。", "凄凉动客愁。", "还家贫亦好。", "肯厌杯中草。", "香饭滑流匙。", "三登快乐时。"]'),
('song-ci-869','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','霜风飒飒溪山碧。',52,'宋词/ci.song.10000.json','["霜风飒飒溪山碧。", "寒波一望伤行色。", "落日淡荒村。", "人家半掩门。", "孤舟移野渡。", "古木栖鸦聚。", "著雨晚风酸。", "貂裘不奈寒。"]'),
('song-ci-870','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','败荷倒尽芙蓉老。',52,'宋词/ci.song.10000.json','["败荷倒尽芙蓉老。", "寒光黯淡迷衰草。", "行客易销魂。", "笛飞何处村。", "云寒天借碧。", "树瘦烟笼直。", "若个是乡关。", "夕阳西去山。"]'),
('song-ci-871','阮郎归','赵长卿','宋','宋词','song-ci','阮郎归','[]','年年为客遍天涯。',56,'宋词/ci.song.10000.json','["年年为客遍天涯。", "梦迟归路赊。", "无端星月浸窗纱。", "一枝寒影斜。", "肠未断，鬓先华。", "新来瘦转加。", "角声吹彻小梅花。", "夜长人忆家。"]'),
('song-ci-872','霜天晓角','赵长卿','宋','宋词','song-ci','霜天晓角','[]','香来不歇。',54,'宋词/ci.song.10000.json','["香来不歇。", "谁把南枝折。", "的砾疏花初破，都因是、夜来雪。", "清绝。", "十分绝。", "孤标难细说。", "独立野塘清浅，谁作伴、空夜月。"]'),
('song-ci-873','霜天晓角','赵长卿','宋','宋词','song-ci','霜天晓角','[]','雪花飞歇。',54,'宋词/ci.song.10000.json','["雪花飞歇。", "好向前村折。", "行至断桥斜处，寒蕊瘦、不禁雪。", "韵绝。", "香更绝。", "归来人共说。", "最爱夜堂深迥，疏影占、半窗月。"]'),
('song-ci-874','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','客帆卸尽风初定。',52,'宋词/ci.song.10000.json','["客帆卸尽风初定。", "夜空霜落无江冷。", "幸自不思归。", "无端乌夜啼。", "鸡鸣残月落。", "到枕秋声恶。", "有酒不须斟。", "酒深愁转深。"]'),
('song-ci-875','忆秦娥','赵长卿','宋','宋词','song-ci','忆秦娥','[]','寒萧索。',56,'宋词/ci.song.10000.json','["寒萧索。", "征鸿过尽离怀恶。", "离怀恶。", "江空天迥，夜寒枫落。", "有人应误刀头约。", "情深翻恨郎情薄。", "郎情薄。", "梦回长是，半床闲却。"]'),
('song-ci-876','如梦令','赵长卿','宋','宋词','song-ci','如梦令','[]','何处一声鸣橹。',40,'宋词/ci.song.10000.json','["何处一声鸣橹。", "惊起满川寒鹭。", "一著画难成，雪霁乱山无数。", "且住。", "且住。", "数遍溪南烟树。"]'),
('song-ci-877','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','危楼横枕清江上，两岸碧山如画。',126,'宋词/ci.song.10000.json','["危楼横枕清江上，两岸碧山如画。", "夕烟幂幂，晚灯点点，楼台新夜。", "明月当天，白沙流水，冷光连野。", "浸栏干万顷，琉璃软皱，打鱼艇、相高下。", "何处一声羌管，是谁家、倚楼人也。", "多情对景，无言有恨，欲歌还罢。", "把酒临筵，阿谁知我，此怀难写。", "忍思量后夜，芳容不似，暗尘随马。"]'),
('song-ci-878','水调歌头','赵长卿','宋','宋词','song-ci','水调歌头','[]','离愁晚如织，托酒与消磨。',114,'宋词/ci.song.10000.json','["离愁晚如织，托酒与消磨。", "奈何酒薄愁重，越醉越愁多。", "忍对碧天好夜，皓月流光无际，光影转庭柯。", "有恨空垂泪，无语但悲歌。", "因凝想，从别后，蹙双蛾。", "春来底事，孤负紫袖与红靴。", "速整雕鞍归去，著意浅斟低唱，细看小婆娑。", "万蕊千花里，一任玉颜酡。"]'),
('song-ci-879','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','酒潮匀颊双眸溜。',126,'宋词/ci.song.10000.json','["酒潮匀颊双眸溜。", "美映远山横秀。", "风流俊雅，娇痴体态，眼前稀有。", "莲步弯弯，移归拍里，凌波难偶。", "对仙源醉眼，玉纤笼巧，拨轻声、鱼纹皱。", "我自多情多病，对人前、只推伤酒。", "瞒他不得，诗情懒倦，沈腰销瘦。", "多谢东君，殷勤知我，曲翻红袖。", "拼来朝又是，扶头不起，江楼知不。"]'),
('song-ci-880','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','夕阳底尽，望楚天空阔，稀星帘幕。',120,'宋词/ci.song.10000.json','["夕阳底尽，望楚天空阔，稀星帘幕。", "暮霭横江烟万缕，照水参差楼阁。", "两两三三，楼前归鹭，飞过栏干角。", "霜风何事，绕檐吹动寂寞。", "消散我已忘机，而今百念，灰了心头火。", "对酒当歌浑冷淡，一任他懑嗔恶。", "松竹园林，柳梧庭院，自有人间乐。", "闲云休问，去来本是无著。"]'),
('song-ci-881','水调歌头','赵长卿','宋','宋词','song-ci','水调歌头','[]','贪痴无了日，人事没休期。',114,'宋词/ci.song.10000.json','["贪痴无了日，人事没休期。", "白驹过隙，百岁能得几多时。", "自古腰金结绶，著意经营辛苦，回首不胜悲。", "名未能安稳，身已至倾危。", "空剜刻，休巧诈，莫心欺。", "须知天定，只见高塚与新碑。", "我已从头识破，赢得当歌临酒，欢笑且随宜。", "较甚荣和辱，争甚是和非。"]'),
('song-ci-882','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','�稍�著意斟量过，天下事、无穷尽。',127,'宋词/ci.song.10000.json','["�稍�著意斟量过，天下事、无穷尽。", "贪荣贪富，朝思夕计，空劳方寸。", "蹑足封王，功名盖世，谁如韩信。", "更堆金积玉，石崇豪侈，当时望、倾西晋。", "长乐宫中一叹，又何须累累悬印。", "坠楼效死，轻车东市，头膏血刃。", "尤物虚名，於身何补，一齐休问。", "遇当歌临酒，舒眉展眼，且随缘分。"]'),
('song-ci-883','蓦山溪','赵长卿','宋','宋词','song-ci','蓦山溪','[]','壶天冰雪，消尽虚堂暑。',100,'宋词/ci.song.10000.json','["壶天冰雪，消尽虚堂暑。", "多谢故人风，送花香传小树。", "香风初过，一曲断肠声，如怨诉。", "诉闲愁，落落琵琶语。", "江边马上，弹指成千古。", "泪眼与啼妆，叹风流、只今何处。", "芳心役损，触事起悲酸，招玉素。", "拨檀槽，整理金衣缕。"]'),
('song-ci-884','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','精神俊雅，更那堪、天与风流标格。',120,'宋词/ci.song.10000.json','["精神俊雅，更那堪、天与风流标格。", "罗绮丛中偏艳冶，偷处教人怜惜。", "目剪秋波，指纤春笋，新样冠儿直。", "高堂云雨，甚人有分消得。", "忔戏笑里含羞，回眸低盼，此意谁能识。", "密约幽欢空怅望，何日能谐端的。", "玳席歌馀，兰堂香散，此际愁如织。", "人归空对，晚阴庭树横碧。"]'),
('song-ci-885','瑞鹤仙','赵长卿','宋','宋词','song-ci','瑞鹤仙','[]','无言屈指也。',126,'宋词/ci.song.10000.json','["无言屈指也。", "算年年底事，长为旅也。", "凄惶受尽也。", "把良辰美景，总成虚也。", "自嗟叹也。", "这情怀、如何诉也。", "谩愁明怕暗，单栖独宿，怎生禁也。", "闲也。", "有时临镜，渐觉形容，日消减也。", "光阴换也。", "空辜负、少年也。", "念仙源深处，暖香小院，赢得群花怨也。", "是亏他见了，多教骂几句也。"]'),
('song-ci-886','蓦山溪','赵长卿','宋','宋词','song-ci','蓦山溪','[]','无非无是。',102,'宋词/ci.song.10000.json','["无非无是。", "好个闲居士。", "衣食不求人，又识得、三文两字。", "不贪不伪，一味乐天真，三径里。", "四时花，随分堪游戏。", "学些沓拖，也似没意志。", "诗酒度流年，熟谙得、无争三昧。", "风波歧路，成败霎时间，你富贵。", "你荣华，我自关门睡。"]'),
('song-ci-887','青玉案','赵长卿','宋','宋词','song-ci','青玉案','[]','东门杨柳空盈路。',80,'宋词/ci.song.10000.json','["东门杨柳空盈路。", "系得征鞍能驻不。", "暗绿枝头新过雨。", "柔丝千尺，乳莺百啭，似怨行人去。", "行人去后如何处。", "去向天边簉鹓鹭。", "瑶管琼台多雅趣。", "花砖稳上，玉阶阔步，肯念人尘土。"]'),
('song-ci-888','虞美人','赵长卿','宋','宋词','song-ci','虞美人','[]','雨声破晓催行桨。',66,'宋词/ci.song.10000.json','["雨声破晓催行桨。", "拍拍溪流长。", "绿杨绕岸水痕斜。", "恰似画桥西畔、那人家。", "人家楼阁临江渚。", "应是停歌舞。", "珠帘整日不闲钩。", "目断征帆、犹未识归舟。"]'),
('song-ci-889','虞美人','赵长卿','宋','宋词','song-ci','虞美人','[]','灯前忍见啼红面。',66,'宋词/ci.song.10000.json','["灯前忍见啼红面。", "别酒频斟劝。", "愁蛾敛翠不胜情。", "报道看看天色、待平明。", "殷勤重把阳关唱。", "休要教人望。", "出门犹自尚叮咛。", "厮养频催恰好、趁凉行。"]'),
('song-ci-890','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','十里春风杨柳路，年年带雨披云。',70,'宋词/ci.song.10000.json','["十里春风杨柳路，年年带雨披云。", "柔条万缕不胜情。", "还将无意眼，识遍有心人。", "饿损宫腰终不似，效颦总是难成。", "只愁秋色入高林。", "残蝉和落叶，此际不堪论。"]'),
('song-ci-891','渔家傲','赵长卿','宋','宋词','song-ci','渔家傲','[]','客里情怀谁可表。',72,'宋词/ci.song.10000.json','["客里情怀谁可表。", "凄凉举目知多少。", "强饮强歌还强笑。", "心悄悄。", "从头彻底思量了。", "当日相逢非草草。", "果然恩爱成烦恼。", "稳整征鞍归去好。", "重厮守。", "相期待与同偕老。"]'),
('song-ci-892','江神子・江城子','赵长卿','宋','宋词','song-ci','江神子・江城子','[]','当时得意两心齐。',86,'宋词/ci.song.10000.json','["当时得意两心齐。", "绮窗西。", "共于飞。", "拂掠宫妆，长与画新眉。", "一自别来烟水阔，愁易积，梦还稀。", "相逢恰似旧家时。", "恨依依。", "语低低。", "多少关情，冷暖有谁知。", "只此定应谐素愿，但指日，约鸾栖。"]'),
('song-ci-893','御街行','赵长卿','宋','宋词','song-ci','御街行','[]','香熏斗帐相逢乍。',94,'宋词/ci.song.10000.json','["香熏斗帐相逢乍。", "正宫漏、沈沈夜。", "月飞梅影上帘栊，标致风流娇雅。", "眼波横浸，照人百媚，无限叮咛话。", "玉鞍门上嘶归马。", "趱行色、难留也。", "别来花艳不禁春，浪向东风轻嫁。", "空馀小院，博山修竹，依旧窗儿下。"]'),
('song-ci-894','一丛花','赵长卿','宋','宋词','song-ci','一丛花','[]','当歌临酒恨难穷。',94,'宋词/ci.song.10000.json','["当歌临酒恨难穷。", "酒不似愁浓。", "风帆正起归与兴，岸东西、芳草茸茸。", "楚梦乍回，吴音初听，谁念我孤踪。", "藏春小院暖融融。", "眼色与心通。", "乌云有意重梳掠，便安排、金屋房栊。", "云雨厚因，鸳鸯宿债，作个好家风。"]'),
('song-ci-895','天仙子','赵长卿','宋','宋词','song-ci','天仙子','[]','眼色媚人娇欲度。',80,'宋词/ci.song.10000.json','["眼色媚人娇欲度。", "行尽巫阳云又雨。", "花时还复见芳姿，情几许。", "愁何许。", "莫向耳边传好语。", "往事悠悠曾记否。", "忍听黄鹂啼锦树。", "啼声惊碎百花心。", "分付与。", "谁为主。", "落蕊飞红知甚处。"]'),
('song-ci-896','瑞鹧鸪','赵长卿','宋','宋词','song-ci','瑞鹧鸪','[]','宝奁常见晓妆时。',64,'宋词/ci.song.10000.json','["宝奁常见晓妆时。", "面药香融傅口脂。", "扰扰亲曾撩绿鬓，纤纤巧与画新眉。", "浓欢已散西风远，忆泪无多为你垂。", "各自从今好消遣，莫将红叶浪题诗。"]'),
('song-ci-897','瑞鹧鸪','赵长卿','宋','宋词','song-ci','瑞鹧鸪','[]','结丝千绪不胜愁。',64,'宋词/ci.song.10000.json','["结丝千绪不胜愁。", "莫怪安仁鬓早秋。", "檀口未歌先愠泪，柳眉将敛半凝羞。", "杯倾潋滟送行酒，岸舣飘飘欲去舟。", "待得名登天府后，归来茱菊映钗头。"]'),
('song-ci-898','行香子','赵长卿','宋','宋词','song-ci','行香子','[]','骄马花骢。',82,'宋词/ci.song.10000.json','["骄马花骢。", "柳陌经从。", "小春天、十里和风。", "个人家住，曲巷墙东。", "好轩窗，好体面，好仪容。", "烛灺歌慵。", "斜月朦胧。", "夜新寒、斗帐香浓。", "梦回画角，云雨匆匆。", "恨相逢，恨分散，恨情锺。"]'),
('song-ci-899','夜行船','赵长卿','宋','宋词','song-ci','夜行船','[]','龟甲炉烟轻袅。',65,'宋词/ci.song.10000.json','["龟甲炉烟轻袅。", "帘栊静、乳莺啼晓。", "拂掠新妆，时宜头面，绣草冠儿小。", "衫子揉蓝初著了。", "身材称、就中恰好。", "手拈双纨，菱花重照，带朵宜男草。"]'),
('song-ci-900','采桑子','赵长卿','宋','宋词','song-ci','采桑子','[]','疏帘乍卷孜孜看，冰玉精神。',52,'宋词/ci.song.10000.json','["疏帘乍卷孜孜看，冰玉精神。", "体白停匀。", "端的于人不薄情。", "更无背约和焦燥，各表真诚。", "才得相亲。", "切莫分张向别人。"]'),
('song-ci-901','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','["\u957f\u6c5f"]','闲上西楼供远望。',70,'宋词/ci.song.10000.json','["闲上西楼供远望。", "一曲新声，巧媚谁家唱。", "独倚危栏听半晌。", "长江快泻澄无浪。", "清泪恰同清水涨。", "拭尽重流，触事如何向。", "不觉黄昏灯已上。", "旧愁还是新愁样。"]'),
('song-ci-902','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','天净姮娥初整驾。',70,'宋词/ci.song.10000.json','["天净姮娥初整驾。", "桂魄蟾辉，来趁清和夜。", "费尽丹青无计画。", "纤纤侧向疏桐挂。", "人在扶疏桐影下。", "耳畔轻轻，细说家常话。", "年少难留应不借。", "未歌先咽歌还罢。"]'),
('song-ci-903','蝶恋花','赵长卿','宋','宋词','song-ci','蝶恋花','[]','叶底蜂衙催日晚。',70,'宋词/ci.song.10000.json','["叶底蜂衙催日晚。", "向晚匀妆，巧画宫眉浅。", "翠幕无风香自远。", "金船酌酒须教满。", "未说别离魂已断。", "雨幌云屏，只恐良宵短。", "心事不随飞絮乱。", "宦情肯把恩情换。"]'),
('song-ci-904','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','睡觉扶头听晓钟。',64,'宋词/ci.song.10000.json','["睡觉扶头听晓钟。", "隔帘花雾湿香红。", "翠摇钿砌梧桐影，暖透罗襦芍药风。", "闲对影，记曾逢。", "画眉临镜霎时同。", "相思已有无穷恨，忍见孤鸾宿镜中。"]'),
('song-ci-905','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','宝篆烟消香已残。',64,'宋词/ci.song.10000.json','["宝篆烟消香已残。", "蝉娟月色浸栏干。", "歌喉不作寻常唱，酒令从他各自还。", "传杯手，莫教闲。", "醉红潮脸媚酡颜。", "相携共学骖鸾侣，却笑卢郎旧约寒。"]'),
('song-ci-906','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','绿水澄江得胜游。',64,'宋词/ci.song.10000.json','["绿水澄江得胜游。", "浪平风软称轻舟。", "樽前我易伤前事，柳外人谁独倚楼。", "空感慨，惜风流。", "风流赢得谩多愁。", "愁多著甚销磨得，莫怪安仁鬓早秋。"]'),
('song-ci-907','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','一曲清歌金缕衣。',64,'宋词/ci.song.10000.json','["一曲清歌金缕衣。", "巧佼心事有谁知。", "自从别后难相见，空解题红寄好诗。", "忆携手，过阶墀。", "月笼花影半明时。", "玉钗头上轻轻颤，摇落钗头豆蔻枝。"]'),
('song-ci-908','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','人随社节去匆匆。',58,'宋词/ci.song.10000.json','["人随社节去匆匆。", "此恨几时穷。", "阳台寂寞，巫山凄惨，云雨成空。", "芭蕉密处窗儿下，冷落旧香中。", "黄昏静也，蛩声满院，明月清风。"]'),
('song-ci-909','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','槐阴密处啭黄鹂。',58,'宋词/ci.song.10000.json','["槐阴密处啭黄鹂。", "午日正长时。", "一番过雨，绿荷池面，冷浸琉璃。", "红尘不到华堂里，纤楚对蛾眉。", "笑偎人道，新词觅个，美底腔儿。"]'),
('song-ci-910','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','当年策马过钱塘。',58,'宋词/ci.song.10000.json','["当年策马过钱塘。", "曲径小平康。", "繁红酽白，娇莺姹燕，争唤何郎。", "而今又客东风里，浑不似寻常。", "只愁别后，月房云洞，啼损红妆。"]'),
('song-ci-911','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','蕊嫩花房无限好，东风一样春工。',70,'宋词/ci.song.10000.json','["蕊嫩花房无限好，东风一样春工。", "百年欢笑酒樽同。", "笙吹雏凤语，裙染石榴红。", "且向五云深处住，锦衾绣幌从容。", "如何即是出樊笼。", "蓬莱人少到，云雨事难穷。"]'),
('song-ci-912','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','破靥盈盈巧笑，举杯滟滟迎逢。',66,'宋词/ci.song.10000.json','["破靥盈盈巧笑，举杯滟滟迎逢。", "慧心端有谢娘风。", "烛花香雾，娇困面微红。", "别恨彩笺虽寄，清歌浅酌难同。", "梦回楚馆雨云空。", "相思春暮，愁满绿芜中。"]'),
('song-ci-913','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','夜久笙箫吹彻，更深星斗还稀。',66,'宋词/ci.song.10000.json','["夜久笙箫吹彻，更深星斗还稀。", "醉拈裙带写新诗。", "锁窗风露，烛灺月明时。", "水调悠扬声美，幽情彼此心知。", "古香烟断彩云归。", "满倾蕉叶，齐唱传花枝。"]'),
('song-ci-914','惜奴娇','赵长卿','宋','宋词','song-ci','惜奴娇','[]','洛浦娇魂，恐得到、人间少。',93,'宋词/ci.song.10000.json','["洛浦娇魂，恐得到、人间少。", "把风流、分付花貌。", "六出精神，腊寒射、香试到。", "清秀。", "与江梅、争相先后。", "檐卜粗疏，怎似妖娆体调。", "比山樊、也应错道。", "最是殷勤，捧出金盏银台笑。", "拼了。", "仙源与、奇葩醉倒。"]'),
('song-ci-915','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','无情风掠芭蕉响，还是重门已闭。',127,'宋词/ci.song.10000.json','["无情风掠芭蕉响，还是重门已闭。", "银缸独对，相思方切，教人怎睡。", "解叹从前事，解叹了、依前鳖气。", "想他家那里，知人憔悴，相应是、睡也未。", "且恁和衣强寝，奈无寐、依前重起。", "起来思想，当初与你，忒煞容易。", "及至而今也，半头天眼，不存不济。", "最消魂苦是，黄昏前后，冷清清地。"]'),
('song-ci-916','水调歌头','赵长卿','宋','宋词','song-ci','水调歌头','[]','把酒相劳苦，月色耀天章。',114,'宋词/ci.song.10000.json','["把酒相劳苦，月色耀天章。", "冰轮碾破寒碧，飞入酒樽凉。", "击节词人妙句，吸此清辉万丈，肺腑亦生光。", "揽袂欲仙举，逸兴共天长。", "日边客，幕中俊，坐间狂。", "浩歌清啸，恍然云海渺茫茫。", "唤醒谪仙苏二，何事常愁客少，更恐被云妨。", "月与人长好，广大醉为乡。"]'),
('song-ci-917','水龙吟','赵长卿','宋','宋词','song-ci','水龙吟','[]','先来天与精神，更因丽景添殊态。',126,'宋词/ci.song.10000.json','["先来天与精神，更因丽景添殊态。", "拖轻苒苒，才凝一段，还分五彩。", "毕竟非烟，有时为雨，惹情无奈。", "道无心，怎被歌声遏断，迟迟向、青天外。", "宜伴先生醉卧，得饶道、和山须买。", "也曾恼杀襄王，谁道依前不会。", "我欲乘风归去，翻怅恨、帝乡何在。", "念佳期未展，天长莫合，尽空相对。"]'),
('song-ci-918','诉衷情','赵长卿','宋','宋词','song-ci','诉衷情','[]','花前月下会鸳鸯。',55,'宋词/ci.song.10000.json','["花前月下会鸳鸯。", "分散两情伤。", "临行祝付真意，臂间皓齿留香。", "还更毒，又何妨。", "尽成疮。", "疮儿可后，痕儿见在，见后思量。"]'),
('song-ci-919','满江红','赵长卿','宋','宋词','song-ci','满江红','[]','懊恼平生，奈天赋、恩情太薄。',115,'宋词/ci.song.10000.json','["懊恼平生，奈天赋、恩情太薄。", "二三岁、看伊受尽，眼尖眉角。", "记得当初低耳畔，是谁先有于飞约。", "惟到今、划地误盟言，还先恶。", "天眼见，人难度。", "天易感，人难托。", "人心险，天又怎生捉摸。", "莫问傍人非与是，手儿但把心儿托。", "便不成、厮守许多时，乾休却。"]'),
('song-ci-920','贺新郎','赵长卿','宋','宋词','song-ci','贺新郎','[]','负你千行泪。',141,'宋词/ci.song.10000.json','["负你千行泪。", "大都来、一寸心儿，万般萦系。", "似恁愁烦那里洎。", "故自三年二岁。", "为你后、甘心憔悴。", "终待说、山盟海誓。", "这恩情、到此非容易。", "拼做个，久长计。", "紧要事须评议。", "怕人人、蓦地知时，怎生处置。", "毒害心肠祆知是。", "怕你生烦到底。", "便莫待、将人轻弃。", "不是我多疑你。", "被傍人、赚后失圈圚。", "经一事，长一智。"]'),
('song-ci-921','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','连沧危观暮江前。',58,'宋词/ci.song.10000.json','["连沧危观暮江前。", "几醉使君筵。", "少年俊气，曾将吟笔，买断江天。", "重来细把朋游数，回首一辛酸。", "兰成已老，文园多病，负此江山。"]'),
('song-ci-922','簇水','赵长卿','宋','宋词','song-ci','簇水','[]','长忆当初，是他见我心先有。',104,'宋词/ci.song.10000.json','["长忆当初，是他见我心先有。", "一钩才下，便引得鱼儿开口。", "好是重门深院，寂寞黄昏后。", "厮觑著、一面儿酒。", "试撋就。", "便把我、得人意处，闵子里、施纤手。", "云情雨意，似十二巫山旧。", "更向枕前言约，许我长相守。", "忺人也，犹自眉头皱。"]'),
('song-ci-923','摊破丑奴儿・采桑子','赵长卿','宋','宋词','song-ci','摊破丑奴儿・采桑子','[]','最苦是离愁。',75,'宋词/ci.song.10000.json','["最苦是离愁。", "行坐里、只在心头。", "待要作个巫山梦，孤衾展转，无眠到晓，和梦都休。", "梦里也无由。", "谁敢望、真个绸缪。", "暂时不见浑闲事，只愁柳絮杨花，自来摆荡难留。"]'),
('song-ci-924','更漏子','赵长卿','宋','宋词','song-ci','更漏子','[]','烛消红，窗送白。',56,'宋词/ci.song.10000.json','["烛消红，窗送白。", "冷落一衾寒色。", "鸦唤起，马忘行", "月来衣上明。", "酒香唇，妆印臂。", "亿共人人睡。", "魂蝶乱，梦鸾孤。", "知他睡也无。"]'),
('song-ci-925','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','一味风流一味香。',48,'宋词/ci.song.10000.json','["一味风流一味香。", "十分浓艳十分妆。", "自然娇态自然芳。", "楼上好风楼下水，雪前栏槛竹前窗。", "也宜单著也宜双。"]'),
('song-ci-926','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','恻恻笙竽万籁风。',48,'宋词/ci.song.10000.json','["恻恻笙竽万籁风。", "阳关叠遍酒尊空。", "相逢草草别匆匆。", "满眼泪珠和雨洒，一襟愁绪抵秋浓。", "相思今夜五云东。"]'),
('song-ci-927','汉宫春','赵长卿','宋','宋词','song-ci','汉宫春','[]','讲柳谈花，我从来口快，忺说他家。',118,'宋词/ci.song.10000.json','["讲柳谈花，我从来口快，忺说他家。", "眼前见了，无限楚女吴娃。", "千停万稳，较量来、终不如他。", "便做得，宫仪院体，歌谈不带烟花。", "从前万事堪夸。", "爱拈笺弄管，锦字敧斜。", "新来与人臑著，不许胡巴。", "嚎懑谩惹，料福缘、浅似他些。", "谁为我，传诗递曲，殷勤题上窗纱。"]'),
('song-ci-928','雨中花慢','赵长卿','宋','宋词','song-ci','雨中花慢','[]','帊子分香，罗巾拭泪，别来时、未觅凄惶。',119,'宋词/ci.song.10000.json','["帊子分香，罗巾拭泪，别来时、未觅凄惶。", "上得船儿来了，剗地凄凉。", "可惜花前月里，却成水远山长。", "做成恩爱，如今赢得，万里千乡。", "情知这场寂寞，不干你事，伤我穷忙。", "不道是、久长活路，终要称量。", "我则匆匆归去，知你且、种种随娘。", "下梢睚彻，有时共你风光。"]'),
('song-ci-929','柳梢青','赵长卿','宋','宋词','song-ci','柳梢青','[]','小窗闲适。',61,'宋词/ci.song.10000.json','["小窗闲适。", "云髻亸肩，香肌偎膝。", "玉局无尘，明琼欲碎，春纤同掷。", "不争百万呼卢，赌今夜、鸳帷痛惜。", "好忍马儿，若还输了，当甚则剧。"]'),
('song-ci-930','南歌子','赵长卿','宋','宋词','song-ci','南歌子','[]','梅萼和霜晓，梨花带雪春。',62,'宋词/ci.song.10000.json','["梅萼和霜晓，梨花带雪春。", "玉肌琼艳本无尘。", "肯把铅华容易、污天真。", "汤饼尝初罢，罗巾拭转新。", "几回贪耍失黄昏。", "月里归来无处、觅精神。"]'),
('song-ci-931','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','人在梦云楼上别，残灯影里迟留。',70,'宋词/ci.song.10000.json','["人在梦云楼上别，残灯影里迟留。", "依稀绿惨更红羞。", "露痕双脸湿，山样两眉愁。", "几幅片帆天际去，云涛烟浪悠悠。", "今宵独立古江头。", "水腥鱼菜市，风碎荻花舟。"]'),
('song-ci-932','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','画角声沈卷暮霞。',48,'宋词/ci.song.10000.json','["画角声沈卷暮霞。", "寒生促索锦屏遮。", "沈檀半爇髻堆鸦。", "蝴蝶梦回馀烛影，子规啼处隔窗纱。", "夜深明月浸梨花。"]'),
('song-ci-933','浪淘沙','赵长卿','宋','宋词','song-ci','浪淘沙','[]','帘卷露花容。',64,'宋词/ci.song.10000.json','["帘卷露花容。", "几度相逢。", "他知我意欲相通。", "偏奈天教多阻间，积恨何穷。", "云雨杳无踪。", "愁怕东风。", "时闻语笑恣欢浓。", "惟有俺咱真分浅，往事成空。"]'),
('song-ci-934','如梦令','赵长卿','宋','宋词','song-ci','如梦令','[]','竹外半窥娇面。',40,'宋词/ci.song.10000.json','["竹外半窥娇面。", "真个出尘体段。", "没处可偷怜，空恁眼穿肠断。", "休恋。", "休恋。", "只是与伊分浅。"]'),
('song-ci-935','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','闲理丝簧听好音。',48,'宋词/ci.song.10000.json','["闲理丝簧听好音。", "西楼剪烛夜深深。", "半嗔半喜此时心。", "暖语温存无恙语，韵开香靥笑吟吟。", "别来烦恼到如今。"]'),
('song-ci-936','减字木兰花','赵长卿','宋','宋词','song-ci','减字木兰花','[]','阳关唱彻。',52,'宋词/ci.song.10000.json','["阳关唱彻。", "断尽离肠声哽咽。", "酒已三巡。", "今夜王孙是路人。", "此情难说。", "莫负等闲风与月。", "欲问归期。", "来戴钗头艾虎儿。"]'),
('song-ci-937','减字木兰花','赵长卿','宋','宋词','song-ci','减字木兰花','[]','半窗斜月。',52,'宋词/ci.song.10000.json','["半窗斜月。", "茅店萧条灯已灭。", "床下蛩声。", "声动凄凉不忍听。", "终宵无寐。", "覆去翻来真个是。", "屈指归期。", "应是梅花烂熳时。"]'),
('song-ci-938','夜行船','赵长卿','宋','宋词','song-ci','夜行船','[]','短棹轻舟排办了。',68,'宋词/ci.song.10000.json','["短棹轻舟排办了。", "歌声断、晚霞残照。", "红蓼坡头，绿杨堤外，离恨知多少。", "别后莫教音信杳。", "叹光阴、初自来堪笑。", "画角谯门，槐溪归路，正是楚天清晓。"]'),
('song-ci-939','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','玉楼初见念奴娇。',58,'宋词/ci.song.10000.json','["玉楼初见念奴娇。", "无处不妖娆。", "眼传密意，樽前烛外，怎不魂消。", "西风明月相逢夜，枕簟正凉宵。", "殢人记得，叮咛残漏，且慢明朝。"]'),
('song-ci-940','品令','赵长卿','宋','宋词','song-ci','品令','[]','黄昏时候，诮不语、心如醉。',79,'宋词/ci.song.10000.json','["黄昏时候，诮不语、心如醉。", "无眠凝想，别来绣阁，多应憔悴。", "上了灯儿，知是睡哩坐哩。", "蓦思归计。", "又还是重屈指。", "从今已后，暌离千万，且休容易。", "这底凄惶，你看是谁不是。"]'),
('song-ci-941','柳梢青','赵长卿','宋','宋词','song-ci','柳梢青','[]','甜言软语。',61,'宋词/ci.song.10000.json','["甜言软语。", "长记那时，萧娘叮嘱。", "清管危弦，前欢难断，鳞鸿无据。", "纷纷眼底浮花，拈弄动、几多思虑。", "千结丁香，且须珍重，休胡分付。"]'),
('song-ci-942','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','金兽喷香瑞霭氛。',48,'宋词/ci.song.10000.json','["金兽喷香瑞霭氛。", "夜凉如水酒醺醺。", "照人娇眼媚生春。", "我自愁多魂已断，不禁楚雨带巫云。", "人情又是一番新。"]'),
('song-ci-943','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','坐看销金暖帐中。',48,'宋词/ci.song.10000.json','["坐看销金暖帐中。", "羔儿酒美兽煤红。", "浅斟低唱好家风。", "爱客东君多解事，晚妆新与画眉峰。", "便须催唤出房栊。"]'),
('song-ci-944','浣溪沙','赵长卿','宋','宋词','song-ci','浣溪沙','[]','堆枕冠儿翡翠钗。',48,'宋词/ci.song.10000.json','["堆枕冠儿翡翠钗。", "蒙金领子满絣鞋。", "于中沈净好情怀。", "新欲晚凉梳洗罢，半娇微笑下堂来。", "莲花因甚未曾开。"]'),
('song-ci-945','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','天外浓云云外雨，雨声初上檐牙。',70,'宋词/ci.song.10000.json','["天外浓云云外雨，雨声初上檐牙。", "红蕖应褪洗妆花。", "晚凉如有意，霫霫到山家。", "为唤山童多索酒，金锺细酌流霞。", "晕生玉颊酒潮斜。", "闲中无宠辱，醉里是生涯。"]'),
('song-ci-946','夜行船','赵长卿','宋','宋词','song-ci','夜行船','[]','绿盖红幢笼碧水。',72,'宋词/ci.song.10000.json','["绿盖红幢笼碧水。", "鱼跳处、浪痕匀碎。", "惜别殷勤，留连无计，歌声与、泪和柔脆。", "一叶扁舟烟浪里。", "曲滩头、此情无际。", "窈窕眉山，暮霞红处，雨云想、翠峰十二。"]'),
('song-ci-947','浪淘沙','赵长卿','宋','宋词','song-ci','浪淘沙','[]','窈窕绣帏深。',64,'宋词/ci.song.10000.json','["窈窕绣帏深。", "窈窕娉婷。", "梅花初试晚妆新。", "那更娇痴年纪小，冰雪精神。", "举措忒轻盈。", "歌彻新声。", "柔肠魂断不堪听。", "但恐巫山留不住，飞作行云。"]'),
('song-ci-948','如梦令','赵长卿','宋','宋词','song-ci','如梦令','[]','居士年来懒散。',40,'宋词/ci.song.10000.json','["居士年来懒散。", "凡事只从宽简。", "身外更无求，祗要夏凉冬暖。", "美满。", "美满。", "得过何须积趱。"]'),
('song-ci-949','卜算子','赵长卿','宋','宋词','song-ci','卜算子','[]','十载仰高明，一见心相许。',52,'宋词/ci.song.10000.json','["十载仰高明，一见心相许。", "来日孤舟西水门。", "风饱征帆腹。", "后夜起相思，明月清江曲。", "若见秋风寒雁来，能寄音书否。"]'),
('song-ci-950','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','先来客路足伤悲。',58,'宋词/ci.song.10000.json','["先来客路足伤悲。", "那更话别离。", "玉骢也解，知人欲去，骧首频嘶。", "马蹄动是三千里，后会莫相违。", "切须更把，丁香珍重，待我重期。"]'),
('song-ci-951','南乡子','赵长卿','宋','宋词','song-ci','南乡子','[]','楚楚窄衣裳。',70,'宋词/ci.song.10000.json','["楚楚窄衣裳。", "腰身占却，多少风光。", "共说春来春去事，凄凉。", "懒对菱花晕晓妆。", "闲立近红芳。", "游峰戏蝶，误采真香。", "何事不归巫峡去，思量。", "故来尘世断人肠。"]'),
('song-ci-952','南乡子','赵长卿','宋','宋词','song-ci','南乡子','[]','月转水晶盘。',66,'宋词/ci.song.10000.json','["月转水晶盘。", "楼上初闻一鼓残。", "又是去年天气好，栏干。", "风动梅梢玉斗寒。", "无奈壮情阑。", "对酒如何欲强欢。", "谁道破愁须仗酒，君看。", "酒到愁多破亦难。"]'),
('song-ci-953','谒金门','赵长卿','宋','宋词','song-ci','谒金门','[]','灯乍灭。',53,'宋词/ci.song.10000.json','["灯乍灭。", "忽见一天明月。", "恰舞霓裳歌未歇。", "露寒回绛阙。", "羽服明晖玉雪。", "笑语轻参环玦。", "香泽恼人情不彻。", "夜长窗自白。"]'),
('song-ci-954','点绛唇','赵长卿','宋','宋词','song-ci','点绛唇','[]','云亸宫鬟，淡黄衫子轻香透。',50,'宋词/ci.song.10000.json','["云亸宫鬟，淡黄衫子轻香透。", "晚凉时候。", "睡起新妆就。", "冰枕生寒，玉浸纤纤手。", "沈吟久。", "眉山敛秀。", "爱道奴家瘦。"]'),
('song-ci-955','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','春山已蹙眉峰绿。',52,'宋词/ci.song.10000.json','["春山已蹙眉峰绿。", "春心骀荡难拘束。", "惆怅为春伤。", "惜花心更狂。", "对花深有意。", "且向花前醉。", "花作有情香。", "与人相久长。"]'),
('song-ci-956','画堂春','赵长卿','宋','宋词','song-ci','画堂春','[]','当时巧笑记相逢。',57,'宋词/ci.song.10000.json','["当时巧笑记相逢。", "玉梅枝上玲珑。", "酒杯流处已愁浓。", "寒雁横空。", "去程无记更从容。", "到归来好事匆匆。", "一时分付不言中。", "此恨难穷。"]'),
('song-ci-957','如梦令','赵长卿','宋','宋词','song-ci','如梦令','[]','居士年来病酒。',40,'宋词/ci.song.10000.json','["居士年来病酒。", "肉食百不宜口。", "蒲合与波薐，更着同蒿葱韭。", "亲手。", "亲手。", "分送卧龙诗友。"]'),
('song-ci-958','如梦令','赵长卿','宋','宋词','song-ci','如梦令','[]','别恨眉尖无数。',40,'宋词/ci.song.10000.json','["别恨眉尖无数。", "后夜王孙何处。", "歌馆与妆楼，目断行云凝伫。", "凝伫。", "凝伫。", "忆泪千行红雨。"]'),
('song-ci-959','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','隔江一带春山好。',52,'宋词/ci.song.10000.json','["隔江一带春山好。", "平林新绿春光老。", "休去倚阑干。", "飞红不忍看。", "东流何处去。", "便是归舟路。", "芳草外斜阳。", "行人更断肠。"]'),
('song-ci-960','长相思','赵长卿','宋','宋词','song-ci','长相思','[]','敛愁眉。',44,'宋词/ci.song.10000.json','["敛愁眉。", "恨依依。", "肠断关情怨别离。", "云中过雁悲。", "瘦因谁。", "病因谁。", "屈指无言忖后期。", "此时人怎知。"]'),
('song-ci-961','柳梢青','赵长卿','宋','宋词','song-ci','柳梢青','[]','潇洒仙源。',61,'宋词/ci.song.10000.json','["潇洒仙源。", "夭桃秾李，曾对华筵。", "歌媚惊尘，舞弯低月，满劝金船。", "鉴湖烟水连天。", "政归棹、红妆斗妍。", "花雾香中，人询居士，切莫多传。"]'),
('song-ci-962','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','不羡八千椿，不羡三偷桃客。',53,'宋词/ci.song.10000.json','["不羡八千椿，不羡三偷桃客。", "也不羡他龟鹤，一总为凡物。", "羡君恰似老人星，长明无休息。", "好与中兴贤主，立维城勋绩。"]'),
('song-ci-963','朝中措','赵长卿','宋','宋词','song-ci','朝中措','[]','南楼风物一番新。',57,'宋词/ci.song.10000.json','["南楼风物一番新。", "春暮畀斯民。", "岂但仁人恺弟，更兼政事如神。", "人生最贵，荣登五马，千里蒙恩。", "祗恐促归廊庙，去思有脚阳春。"]'),
('song-ci-964','朝中措','赵长卿','宋','宋词','song-ci','朝中措','[]','文章学业继家声。',57,'宋词/ci.song.10000.json','["文章学业继家声。", "名誉压群英。", "早岁掀腾膴仕，如公富贵难并。", "定膺丹诏，朱轮迅召，陶冶苍生。", "自是盐梅姿质，伫看大手调羹。"]'),
('song-ci-965','朝中措','赵长卿','宋','宋词','song-ci','朝中措','[]','先生德行冠南丰。',57,'宋词/ci.song.10000.json','["先生德行冠南丰。", "锦绣作心胸。", "暂屈徒劳州县，文章后进宗工。", "督邮纲纪，才高幕府，雅望尤崇。", "此去定膺光宠，且须满醉西东。"]'),
('song-ci-966','念奴娇','赵长卿','宋','宋词','song-ci','念奴娇','[]','桂华蟾魄，到中秋、祗有人闻一六。',120,'宋词/ci.song.10000.json','["桂华蟾魄，到中秋、祗有人闻一六。", "浩渺清风因唤起，千里吹飞鸿鹄。", "碧落翻花，瑶空隐瑞，声节琅玕筑。", "板怀玉燕，此时嘉梦重育。", "始信名在丹台，曈方八百，子已三千熟。", "麟脯灵瓜那更有，琼斝神仙醽醁。", "秋水春山，柳腰花面，一醉霓裳曲。", "长生清净，自然何用辟谷。"]'),
('song-ci-967','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','江上一江楼，楼上远山横翠。',53,'宋词/ci.song.10000.json','["江上一江楼，楼上远山横翠。", "还更腰金骑鹤，引竹西歌吹。", "寿君春酒遣双壶，满引见深意。", "肯向龟荷香里，唤侬来同醉。"]'),
('song-ci-968','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','剑水霭欢声，喜庆间生人杰。',53,'宋词/ci.song.10000.json','["剑水霭欢声，喜庆间生人杰。", "一段葱葱佳气，扇熏风时节。", "今朝银艾佐琴堂，争把寿香爇。", "去去凤皇池上，见龟巢连叶。"]'),
('song-ci-969','柳长春・踏莎行','赵长卿','宋','宋词','song-ci','柳长春・踏莎行','[]','梅喜先春，雁惊未腊。',68,'宋词/ci.song.10000.json','["梅喜先春，雁惊未腊。", "于门瑞气浮周匝。", "正当月应上弦时，长庚梦与良辰合。", "螺水恩浓，旴江德洽。", "寿杯劝处燃红蜡。", "明年此际祝遐龄，贺宾一一趋东阁。"]'),
('song-ci-970','武陵春','赵长卿','宋','宋词','song-ci','武陵春','[]','又是新逢三五夜，瑞气霭氤氲。',56,'宋词/ci.song.10000.json','["又是新逢三五夜，瑞气霭氤氲。", "万点灯和月色新。", "桃李倍添春。", "花县主人情思好，行乐逐良辰。", "满引千锺酒又醇。", "歌韵动梁尘。"]'),
('song-ci-971','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','天祐炎图生国瑞，蓝田暂屈英僚。',70,'宋词/ci.song.10000.json','["天祐炎图生国瑞，蓝田暂屈英僚。", "始知文宿降璇霄。", "中元前五日，七夕后三朝。", "江斅风流临此政，少年潇洒奇标。", "行看峻擢相熙朝。", "功名前稷契，寿算等松乔。"]'),
('song-ci-972','喜迁莺','赵长卿','宋','宋词','song-ci','喜迁莺','[]','商颷轻透。',128,'宋词/ci.song.10000.json','["商颷轻透。", "动帘幕飞梧，乱飘庭甃。", "瑞气氤氲，沈檀初爇，烟喷宝台金兽。", "黄花美酒。", "天教占得，先他时候。", "诞元老，庆有声，此夕降生华胄。", "欢笑。", "宜称寿。", "弦管鼎沸，宫商方频奏。", "满捧瑶卮，华堂歌舞，拍转金钗斜溜。", "朱颜绿鬓，殷勤深愿，镇长如旧。", "叹滨海，道难留，指日荣迁飞骤。"]'),
('song-ci-973','鹊桥仙','赵长卿','宋','宋词','song-ci','鹊桥仙','[]','云峰初敛，秋荣如洗，庭院金风初扇。',68,'宋词/ci.song.10000.json','["云峰初敛，秋荣如洗，庭院金风初扇。", "葱葱佳气霭侯门，信天上、麒麟乍见。", "祝君此去，飞黄腾踏，日侍凝旒邃冕。", "和羹调味早归来，坐看取、蓬莱清浅。"]'),
('song-ci-974','柳梢青','赵长卿','宋','宋词','song-ci','柳梢青','[]','晴雪楼台，试灯帘幕，适是元宵。',60,'宋词/ci.song.10000.json','["晴雪楼台，试灯帘幕，适是元宵。", "罗绮娇春，帝城风景，今夜应饶。", "争知我系如匏，便そ月良天任教。", "早闭柴门，从他箫鼓，细打轻敲。"]'),
('song-ci-975','贺新郎','赵长卿','宋','宋词','song-ci','贺新郎','[]','世谛人多错。',141,'宋词/ci.song.10000.json','["世谛人多错。", "阿谁将、虚名微利，放教轻著。", "万事莫非前定了，选甚微如饮酌。", "算徒诧、龙韬豹略。", "纵使龙头安尺木，更从教、豹变生三角。", "浑是梦，恍如昨。", "吾庐自笑常虚廓。", "对残编、磨穿枯砚，生涯微薄。", "负郭田园能有几，随分安贫守约。", "要不改、箪瓢颜乐。", "西掖百扉终须到，且嘲风咏月常相谑。", "更要甚，万金药。"]'),
('song-ci-976','东坡引','赵长卿','宋','宋词','song-ci','东坡引','[]','茅斋无客至。',68,'宋词/ci.song.10000.json','["茅斋无客至。", "冰砚冻寒泚。", "南枝喜入新诗里。", "恼人频嚼蕊。", "恼人频嚼蕊。", "因思去腊江头醉。", "倚动客兴伤春意。", "经年自叹人如寄。", "光阴如拈指。", "光阴如拈指。"]'),
('song-ci-977','满庭芳','赵长卿','宋','宋词','song-ci','满庭芳','[]','风力驱寒，云荣呈瑞，晓来到处花飞。',117,'宋词/ci.song.10000.json','["风力驱寒，云荣呈瑞，晓来到处花飞。", "遍装琼树，春意到南枝。", "便是渔蓑旧画，纶竿重、横玉低垂。", "今宵里，香闺邃馆，幽赏事偏宜。", "风流金马客，歌鬟醉拥，乌帽斜敧。", "问人间何处，鹏运天池。", "且共周郎按曲，音微误、首己先回。", "同心事，丹山路稳，长伴彩鸾归。"]'),
('song-ci-978','杏花天','赵长卿','宋','宋词','song-ci','杏花天','[]','乍凉淅淅风生幕。',65,'宋词/ci.song.10000.json','["乍凉淅淅风生幕。", "人独在、朱栏翠阁。", "吹箫信杳炉香薄。", "眉上新愁又觉。", "从前事、拟将拼却。", "梦不断、花梢柳萼。", "一杯睡起谁同酌。", "斜日阴阴转角。"]'),
('song-ci-979','临江仙','赵长卿','宋','宋词','song-ci','临江仙','[]','远岫螺头湿翠，流霞赪尾疏明。',68,'宋词/ci.song.10000.json','["远岫螺头湿翠，流霞赪尾疏明。", "断虹斜界雨新晴。", "烟村灯火晚，江浦画难成。", "我向其间泛叶，终朝露渚风汀。", "老来心事最关情。", "不堪三弄笛，吹作断肠声。"]'),
('song-ci-980','辊绣球','赵长卿','宋','宋词','song-ci','辊绣球','[]','流水奏鸣琴，风月净、天无星斗。',81,'宋词/ci.song.10000.json','["流水奏鸣琴，风月净、天无星斗。", "翠岚堆里，苍岩深处，满林霜腻，暗香冻了，那禁频嗅。", "马上再三回首。", "因记省、去年时候。", "十分全似，那人风韵，柔腰弄影，冰腮退粉，做成清瘦。"]'),
('song-ci-981','眼儿媚','赵长卿','宋','宋词','song-ci','眼儿媚','[]','南枝消息杳然间。',58,'宋词/ci.song.10000.json','["南枝消息杳然间。", "寂寞倚雕栏。", "紫腰艳艳，青腰袅袅，风月俱闲。", "佳人环佩玉阑珊。", "作恶探花还。", "玉纤拈粟，樱唇呵粉，愁点眉弯。"]'),
('song-ci-982','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','日高犹恋珊瑚枕。',52,'宋词/ci.song.10000.json','["日高犹恋珊瑚枕。", "羞红不忿花如锦。", "双燕运芹泥。", "燕归人未归。", "纵饶梳洗罢。", "朱户何曾跨。", "寂寞小房栊。", "回文和泪封。"]'),
('song-ci-983','鹧鸪天','赵长卿','宋','宋词','song-ci','鹧鸪天','[]','落魄东吴二十春。',64,'宋词/ci.song.10000.json','["落魄东吴二十春。", "风流诗句得清新。", "今年却恨花星照，再见温卿与远真。", "分楚佩，染巫云。", "赤绳结得短花茵。", "若非京口初相识，安得毗陵作故人。"]'),
('song-ci-984','浪淘沙','赵长卿','宋','宋词','song-ci','浪淘沙','[]','绿树转鸣禽。',64,'宋词/ci.song.10000.json','["绿树转鸣禽。", "已是春深。", "杨花庭院日阴阴。", "帘外飞来双语燕，不寄归音。", "旧事懒追寻。", "空惹芳心。", "天涯消息远沈沈。", "记得年时中酒后，直至而今。"]'),
('song-ci-985','谒金门','赵长卿','宋','宋词','song-ci','谒金门','[]','春睡足。',53,'宋词/ci.song.10000.json','["春睡足。", "帘卷翠屏山曲。", "芳草沿阶横地轴。", "垂杨相映绿。", "暗忆旧欢难续。", "又是禁烟传烛。", "陌上踏青新结束。", "秋千谁共促。"]'),
('song-ci-986','侍香金童','赵长卿','宋','宋词','song-ci','侍香金童','[]','一种春光，占断东君惜。',79,'宋词/ci.song.10000.json','["一种春光，占断东君惜。", "算秾李、昭华争并得。", "粉腻酥融娇欲滴。", "端的尊前，旧曾相识。", "向夜阑、酒醒霜浓寒又力。", "但只与、冰姿添夜色。", "绣幕银屏人寂寂。", "只许刘郎，暗传消息。"]'),
('song-ci-987','菩萨蛮','赵长卿','宋','宋词','song-ci','菩萨蛮','[]','新晴庭户春阴薄。',52,'宋词/ci.song.10000.json','["新晴庭户春阴薄。", "东风不度重帘幕。", "第几小兰房。", "雏莺初弄黄。", "悄寒春未透。", "不解寻花柳。", "只恐渐春深。", "愁生求友心。"]'),
('song-ci-988','清平乐','赵长卿','宋','宋词','song-ci','清平乐','[]','紫箫声断。',54,'宋词/ci.song.10000.json','["紫箫声断。", "窗底春愁乱。", "试著春衫羞自看。", "窄似年时一半。", "一春长病厌厌。", "新来愁病重添。", "香冷倦熏金鸭，日高不卷珠帘。"]'),
('song-ci-989','好事近','赵长卿','宋','宋词','song-ci','好事近','[]','齿颊带馀香，謦咳总成珠玉。',53,'宋词/ci.song.10000.json','["齿颊带馀香，謦咳总成珠玉。", "剪碎袖罗花片，点金觥春绿。", "玉鱼花露自清凉，涓涓在郎腹。", "犹胜望梅消渴，对文君眉蹙。"]'),
('song-ci-990','品令','赵长卿','宋','宋词','song-ci','品令','[]','好事客。',61,'宋词/ci.song.10000.json','["好事客。", "宫商内、吟得风清月白。", "主人幸有豪家意，后堂煞有春色。", "花压金翘俏相映，酒满玉纤无力。", "你若待我些儿酒，尽吃得、尽吃得。"]'),
('song-ci-991','武陵春','赵长卿','宋','宋词','song-ci','武陵春','[]','落了丹枫残了菊，秋色苦无多。',56,'宋词/ci.song.10000.json','["落了丹枫残了菊，秋色苦无多。", "谁唤西风泣泪罗，吹恨入星河。", "碧枝头金粟闹，曾扌乖翠云窝。", "重揉檀英忆两娥。", "无奈冷香何。"]'),
('song-ci-992','水调歌头','罗愿','宋','宋词','song-ci','水调歌头','[]','秋宇净如水，月镜不安台。',114,'宋词/ci.song.10000.json','["秋宇净如水，月镜不安台。", "郁孤高处张乐，语笑脱氛埃。", "檐外白毫千丈，坐上银河万斛，心境两佳哉。", "俯仰共清绝，底处著风雷。", "问天公，邀月姊，愧凡才。", "婆娑人世，羞见蓬鬓漾金罍。", "来岁公归何处，照耀彩衣簪橐，禁直且休催。", "一曲庾江上，千古继韶陔。"]'),
('song-ci-993','失调名','罗愿','宋','宋词','song-ci','失调名','[]','九月江南秋色，黄雀雨，鲤鱼风。',15,'宋词/ci.song.10000.json','["九月江南秋色，黄雀雨，鲤鱼风。"]'),
('song-ci-994','醉翁操','楼钥','宋','宋词','song-ci','醉翁操','[]','茫茫。',110,'宋词/ci.song.10000.json','["茫茫。", "苍苍。", "青山绕、千顷波光。", "新秋露风荷吹香。", "悠颺心地け然，生清凉。", "古岸摇垂杨。", "时有白鹭飞来双。", "隐君如在，鹤与翱翔。", "老仙何处，尚有流风未忘。", "琴与君兮宫商。", "酒与君兮杯觞。", "清欢殊未央。", "西山忽斜阳。", "欲去且徜徉。", "更将霜鬓临沧浪。"]'),
('song-ci-995','醉翁操','楼钥','宋','宋词','song-ci','醉翁操','[]','冷然。',111,'宋词/ci.song.10000.json','["冷然。", "清圆。", "谁弹。", "向屋山。", "何言。", "清风至阴德之天。", "悠颺馀响婵娟。", "方昼眠。", "迥立八风前。", "八音相宣知孰贤。", "有时悲壮，铿若龙泉。", "有时幽杳，彷佛猿吟鹤怨。", "忽若巍巍山巅。", "荡荡几如流川。", "聊将娱暮年。", "听之身欲仙。", "弦索满人间。", "未有逸韵如此弦。"]'),
('song-ci-996','导引','楼钥','宋','宋词','song-ci','导引','[]','孝宗纯孝，前圣更何加。',59,'宋词/ci.song.10000.json','["孝宗纯孝，前圣更何加。", "高蹈处重华。", "丹成仙去龙輴远，越岸暮山遐。", "波臣先为卷寒沙。", "来往护灵槎。", "九虞礼举神祗乐，万世佑皇家。"]'),
('song-ci-997','导引','楼钥','宋','宋词','song-ci','导引','[]','吾皇尽孝，宗庙务崇尊。',59,'宋词/ci.song.10000.json','["吾皇尽孝，宗庙务崇尊。", "巨典备弥文。", "巍巍东向开基主，七世祔神孙。", "追思九闰整乾坤。", "环宇慕洪恩。", "从今密迩高宗室，千载事如存。"]'),
('song-ci-998','失调名','张良臣','宋','宋词','song-ci','失调名','[]','昨日豆花篱下过，忽然迎面好风吹。',22,'宋词/ci.song.10000.json','["昨日豆花篱下过，忽然迎面好风吹。", "独自立多时。"]'),
('song-ci-999','西江月','张良臣','宋','宋词','song-ci','西江月','[]','四壁空围恨玉，十香浅捻啼绡。',58,'宋词/ci.song.10000.json','["四壁空围恨玉，十香浅捻啼绡。", "殷云度雨井桐凋。", "雁雁无书又到。", "别后钗分燕股，病馀镜减鸾腰。", "蛮江豆蔻影连梢。", "不道参横易晓。"]'),
('song-ci-0','采桑子','张良臣','宋','宋词','song-ci','采桑子','[]','佳人满劝金蕉叶，夜玉春温。',52,'宋词/ci.song.11000.json','["佳人满劝金蕉叶，夜玉春温。", "别后黄昏。", "燕子楼高月一痕。", "年年依旧梨花雨，粉泪空存。", "流水孤村。", "不著寒鸦也断魂。"]'),
('song-ci-1','水调歌头','舒邦佐','宋','宋词','song-ci','水调歌头','[]','问讯金华伯，自是地行仙。',114,'宋词/ci.song.11000.json','["问讯金华伯，自是地行仙。", "只为朱轮画戟，句引到湘川。", "用个狎鸥心地，做就烹鲜时政，民化我何言。", "但贵衡阳纸，纸落尽云烟。", "对湖天，梅索笑，月还圆。", "旧时岳生申甫，重到是前缘。", "快洗瑶觥一醉，唤个鹤仙起舞，骑取上花砖。", "春秋更多少，庄木八千年。"]'),
('song-ci-2','杏花天','张孝忠','宋','宋词','song-ci','杏花天','[]','爱寻水竹添情况。',65,'宋词/ci.song.11000.json','["爱寻水竹添情况。", "任云卧、溪边石上。", "衔杯乐圣成游荡。", "不为弓弯舞样。", "北湖迥、风飘彩舫。", "□笑击、冯夷薄相。", "致身福地何萧爽。", "莫道居夷太枉。"]'),
('song-ci-3','杏花天','张孝忠','宋','宋词','song-ci','杏花天','[]','看花随柳湖边去。',65,'宋词/ci.song.11000.json','["看花随柳湖边去。", "似邂逅、水晶宫住。", "刘郎笔落惊风雨。", "酒社诗盟心许。", "玉关外、不辞马武。", "便好展、云霄稳步。", "郴江自绕郴山路。", "欲问功名何处。"]'),
('song-ci-4','破阵子','张孝忠','宋','宋词','song-ci','破阵子','[]','占气中涵清淑，徵诗古富篇章。',72,'宋词/ci.song.11000.json','["占气中涵清淑，徵诗古富篇章。", "杖屦闲随鱼□乐，怀抱清如湖水凉。", "何殊吴越乡。", "风柳春容袅袅，水花月影汪汪。", "且把清尊浇磊磈，莫为浮名愁肺肠。", "星星白发长。"]'),
('song-ci-5','玉楼春','张孝忠','宋','宋词','song-ci','玉楼春','[]','绿波春早青烟暮。',64,'宋词/ci.song.11000.json','["绿波春早青烟暮。", "翠幕船如天上去。", "深杯浊酒醉贤人，隔岸幽花怜静女。", "浮云散乱流萍聚。", "恨满韩张离合处。", "欲招骑龙帝乡人，来咏叉鱼春岸句。"]'),
('song-ci-6','鹧鸪天','张孝忠','宋','宋词','song-ci','鹧鸪天','[]','豆蔻梢头春意浓。',64,'宋词/ci.song.11000.json','["豆蔻梢头春意浓。", "薄罗衫子柳腰风。", "人间乍识瑶池似，天上浑疑月殿空。", "眉黛小，髻云松。", "背人欲整又还慵。", "多应没个藏娇处，满镜桃花带雨红。"]'),
('song-ci-7','菩萨蛮','张孝忠','宋','宋词','song-ci','菩萨蛮','[]','娇红隐映花稍雾。',52,'宋词/ci.song.11000.json','["娇红隐映花稍雾。", "金莲容与歌声度。", "得句写香笺。", "江山此意传。", "醉当春好处。", "不道因风絮。", "去并锦闱眠。", "青绫被底仙。"]'),
('song-ci-8','西江月','张孝忠','宋','宋词','song-ci','西江月','[]','堂上簪缨交错，花间帘幕高张。',58,'宋词/ci.song.11000.json','["堂上簪缨交错，花间帘幕高张。", "与君一咏一飞觞。", "莫笑诗狂饮畅。", "满路光风转蕙，吟边宫柳斜行。", "新词妙绝动宫墙。", "紫诰黄麻天上。"]'),
('song-ci-9','霜天晓角','张孝忠','宋','宋词','song-ci','霜天晓角','[]','楚山浮碧。',53,'宋词/ci.song.11000.json','["楚山浮碧。", "江汉无终极。", "鄂渚几行云树，天何意、限南北。", "使君觞醉客。", "健倒曾何惜。", "三国英雄谁在，斜阳外、尽陈迹。"]'),
('song-ci-10','点绛唇','方有开','宋','宋词','song-ci','点绛唇','[]','七里滩边，江光漠漠山如戟。',50,'宋词/ci.song.11000.json','["七里滩边，江光漠漠山如戟。", "渔舟一叶。", "径入寒烟碧。", "笑我尘劳，羞对双台石。", "身如织。", "年年行役。", "鱼鸟浑相识。"]'),
('song-ci-11','满江红','方有开','宋','宋词','song-ci','满江红','[]','跳出红尘，都不顾、是非荣辱。',115,'宋词/ci.song.11000.json','["跳出红尘，都不顾、是非荣辱。", "垂钓处、月明风细，水清山绿。", "七里滩头帆落尽，长山泷口潮回速。", "问有谁、特为上钩来，刘文叔。", "貂蝉贵，无人续。", "金带重，难拘束。", "这白麻黄纸，岂曾经目。", "昨夜客星侵帝座，且容伸脚加君腹。", "问高风、今古有谁同，先生独。"]'),
('song-ci-12','贺新郎','许及之','宋','宋词','song-ci','贺新郎','[]','旧俗传荆楚。',142,'宋词/ci.song.11000.json','["旧俗传荆楚。", "正江城、梅炎藻夏，做成重午。", "门艾钗符关何事，付与痴儿呆女。", "耳不听、湖边鼍鼓。", "独炷炉香熏衣润，对潇潇、翠竹都忘暑。", "时展卷，诵骚语。", "新愁不障西山雨。", "问楼头、登临倦客，有谁怀古。", "回首独醒人何在，空把清尊酹与。", "漾不到、潇湘江渚。", "我又相将湖南去，已安排、吊屈嘲渔父。", "君有语，但分付。"]'),
('song-ci-13','水调歌头','傅大询','宋','宋词','song-ci','水调歌头','[]','草草三间屋，爱竹旋添栽。',114,'宋词/ci.song.11000.json','["草草三间屋，爱竹旋添栽。", "碧沙窗户，眼前都是翠云堆。", "一月山翁高卧，踏雪水村清冷，木落远山开。", "唯有平安竹，留得伴寒梅。", "唤家童，开门看，有谁来。", "客来一笑，清话煮茗更传杯。", "有酒只愁无客，有客又愁无酒，酒熟且徘徊。", "明日人间事，天自有安排。"]'),
('song-ci-14','锦堂春・锦堂春慢','傅大询','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','梅要疏开，雪教迟下，怕他寒入江天。',106,'宋词/ci.song.11000.json','["梅要疏开，雪教迟下，怕他寒入江天。", "有月桥仙客，相伴婵娟。", "巷陌升平气象，一时都在鸣弦。", "望东家锦里，雁到云边。", "书到云边。", "尊前翠眉环唱，道新腔字稳，花折声圆。", "此去凤池游戏，碧波添插金莲。", "看长生叶上，龟寿千年，人寿千年。"]'),
('song-ci-15','柳梢青','傅大询','宋','宋词','song-ci','柳梢青','[]','春到江南，今年寒少，早有疏梅。',61,'宋词/ci.song.11000.json','["春到江南，今年寒少，早有疏梅。", "相伴双松，吟哦风月，着意花开。", "天香甚处安排。", "便何似、调羹去来。", "劲节仙姿，玉堂难老，身在蓬莱。"]'),
('song-ci-16','念奴娇','傅大询','宋','宋词','song-ci','念奴娇','[]','江梅破腊，把一枝来报，□春消息。',120,'宋词/ci.song.11000.json','["江梅破腊，把一枝来报，□春消息。", "锦帐银瓶龙麝暖，画烛光摇金碧。", "雨径桃花，一溪流水，路入神仙宅。", "云裳羽佩，洞天相会今夕。", "堂下乐问灵鼍，玉人清唱，舞袖低回雪。", "富贵风流须道是，天上人间难得。", "玉镜台边，琼浆盏畔，共说春心切。", "百年偕老，凤凰楼上风月。"]'),
('song-ci-17','行香子','傅大询','宋','宋词','song-ci','行香子','[]','玉佩簪缨。',88,'宋词/ci.song.11000.json','["玉佩簪缨。", "罗袜生尘。", "问何时、来到湘滨。", "尧蓂五叶，二月阳春。", "一霎时风，一霎时雨，一霎时晴。", "有子鸣琴。", "有路登瀛。", "戏斑衣、温酒重斟。", "蟠桃难老，相伴长生。", "一千年花，一千年果，一千年人。"]'),
('song-ci-18','贺新郎','刘德秀','宋','宋词','song-ci','贺新郎','[]','雨沐秋荣薄。',142,'宋词/ci.song.11000.json','["雨沐秋荣薄。", "莹湖光、琉璃千顷，浪平如削。", "步绕湖边佳绝处，时涌琼楼珠阁。", "记一一、经行皆昨。", "十万人家空翠里，借姮娥、玉鉴相依约。", "卷雾箔，飞烟幕。", "天机云锦才收却。", "放芙蓉、岸花十里，翠红成幄。", "向晚买舟撑月去，笑引银汉共酌。", "醉欲起、骑鲸碧落。", "试唤坡仙哦妙句，问淡妆、此夕如何著。", "只云月，是梳掠。"]'),
('song-ci-19','水调歌头','吴镒','宋','宋词','song-ci','水调歌头','[]','澄彻北湖水，圆镜莹青铜。',114,'宋词/ci.song.11000.json','["澄彻北湖水，圆镜莹青铜。", "客槎星汉天上，隐隐暗朝通。", "六月浮云落日，十顷增冰积雪，胜绝与谁同。", "罗袜步新月，翠袖倚凉风。", "子韩子，叫虞帝，傲祝融。", "御风凌雾来去，邂逅此从容。", "欲问骑驎何处，试举叉鱼故事，惊起碧潭龙。", "乞我飞霞佩，从子广寒宫。"]'),
('song-ci-20','水调歌头','吴镒','宋','宋词','song-ci','水调歌头','[]','三楚上游地，五岭翠眉横。',114,'宋词/ci.song.11000.json','["三楚上游地，五岭翠眉横。", "杜诗韩笔难尽，身到眼增明。", "最好流泉百道，НН绕城萦市，唯见洛阳城。", "化鹤三千岁，橘井尚凄清。", "阆风客，紫贝阙，白玉京。", "不堪天上官府，时此驻霓旌。", "岁晚朔云边雪，压尽蛮烟瘴雨，过雁落寒汀。", "况有如泉酒，细与故人倾。"]'),
('song-ci-21','水调歌头','林淳','宋','宋词','song-ci','水调歌头','[]','潇洒东湖上，夜雨洗清秋。',114,'宋词/ci.song.11000.json','["潇洒东湖上，夜雨洗清秋。", "朝来尘霁，凝望千里兴悠悠。", "山色揉蓝深染，波影青铜新铸，□冷翠光浮。", "蓑笠真吾事，聊整钓鱼钩。", "坐中客，凌王谢，更风流。", "一觞一咏，豪俊谈笑气吞牛。", "花月连环长好，到处名园池□，遇景且遨游。", "试问陶元亮，底事赋归休。"]'),
('song-ci-22','鹧鸪天','林淳','宋','宋词','song-ci','鹧鸪天','[]','天近袄知雨露浓。',64,'宋词/ci.song.11000.json','["天近袄知雨露浓。", "湖山无日不春风。", "闲花野草皆掀舞，曾在君王顾盼中。", "时易得，会难逢。", "朝为逆旅暮三公。", "蛟龙得雨飞无便，鸡犬腾云夙有功。"]'),
('song-ci-23','柳梢青','林淳','宋','宋词','song-ci','柳梢青','[]','富贵园林。',61,'宋词/ci.song.11000.json','["富贵园林。", "清虚清馆，随意登临。", "物外风光，云明花媚，鸟语烟深。", "徐徐缓辔微吟。", "迤逦度、松间柳阴。", "览遍幽奇，小舟归晚，月映波心。"]'),
('song-ci-24','浣溪沙','林淳','宋','宋词','song-ci','浣溪沙','["\u897f\u6e56"]','却忆西湖烂漫游。',48,'宋词/ci.song.11000.json','["却忆西湖烂漫游。", "水涵山影翠光浮。", "轻舟短棹不惊鸥。", "带露精神花妩媚，依风情态柳温柔。", "莺歌燕语巧相留。"]'),
('song-ci-25','阮郎归','王炎2','宋','宋词','song-ci','阮郎归','[]','落花时节近清明。',56,'宋词/ci.song.11000.json','["落花时节近清明。", "南园芳草青。", "东风料峭雨难晴。", "那堪中宿酲。", "回首处，自销凝。", "谁知人瘦生。", "倚阑无语不禁情。", "杜鹃啼数声。"]'),
('song-ci-26','青玉案','王炎2','宋','宋词','song-ci','青玉案','[]','深红数点吹花絮。',80,'宋词/ci.song.11000.json','["深红数点吹花絮。", "又燕子、飞来语。", "远水平芜春欲暮。", "年年长是，清明时候，故遣人憔悴。", "竹鸡啼罢山村雨。", "正寥落、无情绪。", "猛省从前多少事。", "绿杨堤上，楼台如画，此景今何处。"]'),
('song-ci-27','浪淘沙令','王炎2','宋','宋词','song-ci','浪淘沙令','[]','流水绕孤村。',64,'宋词/ci.song.11000.json','["流水绕孤村。", "杨柳当门。", "昔年此地往来频。", "认得绿杨携手处，笑语如存。", "往事不堪论。", "强对清尊。", "梅花香里月黄昏。", "白首重来谁是伴，独自销魂。"]'),
('song-ci-28','木兰花慢','王炎2','宋','宋词','song-ci','木兰花慢','[]','缃桃花树下，记罗袜、昔经行。',123,'宋词/ci.song.11000.json','["缃桃花树下，记罗袜、昔经行。", "至今日重来，人惟独自，花亦凋零。", "青鸟杳无信息，遍人间、何处觅云軿。", "红锦织残旧字，玉箫吹断馀声。", "销凝。", "衣故几时更。", "又谁复卿卿。", "念镜里琴中，离鸾有恨，别鹄无情。", "齐眉处同笑语，但有时、梦见似平生。", "愁对婵娟三五，素光暂缺还盈。"]'),
('song-ci-29','清平乐','王炎2','宋','宋词','song-ci','清平乐','[]','呢喃燕语。',54,'宋词/ci.song.11000.json','["呢喃燕语。", "共诉春归去。", "春去从他留不住。", "落尽枝头红雨。", "老翁袖手优游。", "闲愁不到眉头。", "过了麦黄椹紫，归期只在新秋。"]'),
('song-ci-30','清平乐','王炎2','宋','宋词','song-ci','清平乐','[]','儿曹耳语。',54,'宋词/ci.song.11000.json','["儿曹耳语。", "借问何处去。", "家在翠微深处住。", "生计一犁春雨。", "客中且恁浮游。", "莫将事挂心头。", "纵使人生满百，算来更几春秋。"]'),
('song-ci-31','浪淘沙','王炎2','宋','宋词','song-ci','浪淘沙','[]','月色十分圆。',64,'宋词/ci.song.11000.json','["月色十分圆。", "风露娟娟。", "木犀香里凭阑干。", "河汉横斜天似水，玉鉴光寒。", "草草具杯盘。", "相对苍颜。", "素娥莫惜少留连。", "秋气平分蟾兔满，动是经年。"]'),
('song-ci-32','卜算子','王炎2','宋','宋词','song-ci','卜算子','[]','渡口唤扁舟，雨后青绡皱。',52,'宋词/ci.song.11000.json','["渡口唤扁舟，雨后青绡皱。", "轻暖相重护病躯，料峭还寒透。", "老大自伤春，非为花枝瘦。", "那得心情似少年，双燕归时候。"]'),
('song-ci-33','卜算子','王炎2','宋','宋词','song-ci','卜算子','[]','散策问芳菲，春半花犹未。',52,'宋词/ci.song.11000.json','["散策问芳菲，春半花犹未。", "蓓蕾枝头怯苦寒，恰似人憔悴。", "人莫恨花迟，天自催寒去。", "雨意才收日气浓，玉靥红如醉。"]'),
('song-ci-34','江城子','王炎2','宋','宋词','song-ci','江城子','[]','清波渺渺日晖晖。',86,'宋词/ci.song.11000.json','["清波渺渺日晖晖。", "柳依依。", "草离离。", "老大逢春，情绪有谁知。", "帘箔四垂庭院静，人独处，燕双飞。", "怯寒未敢试春衣。", "踏青时。", "懒追随。", "野蔌山淆，村酿可从宜。", "不向花边拼一醉，花不语，笑人痴。"]'),
('song-ci-35','虞美人','王炎2','宋','宋词','song-ci','虞美人','[]','镜中失画双青鬓。',66,'宋词/ci.song.11000.json','["镜中失画双青鬓。", "懒更占花信。", "小梅半谢雨垂垂。", "未许轻红破蕾、缀桃枝。", "社前归燕穿帘语。", "似说人憔悴。", "自缘老去少欢悰。", "不是春寒料峭、怯东风。"]'),
('song-ci-36','南乡子','王炎2','宋','宋词','song-ci','南乡子','[]','云淡日昽明。',66,'宋词/ci.song.11000.json','["云淡日昽明。", "久雨潺潺乍得晴。", "社近东皋农务急，催耕。", "又见菖蒲出水清。", "池面縠纹平。", "掠水迎风燕羽轻。", "试出访寻春色看，相迎。", "巧笑花枝似有情。"]'),
('song-ci-37','忆秦娥','王炎2','宋','宋词','song-ci','忆秦娥','[]','胭脂点。',56,'宋词/ci.song.11000.json','["胭脂点。", "海棠落尽青春晚。", "青春晚。", "少年游乐，而今慵懒。", "春光不可无人管。", "花边酌酒随深浅。", "随深浅。", "牡丹红透，荼䕷香远。"]'),
('song-ci-38','临江仙','王炎2','宋','宋词','song-ci','临江仙','[]','欲近上元人意好，月如人意团圆。',70,'宋词/ci.song.11000.json','["欲近上元人意好，月如人意团圆。", "暖风催趣养花天。", "三山来鹤驾，万户识凫仙。", "手种河阳桃李树，暂时来看春妍。", "彩衣一笑棹觥船。", "明年当此日，人到凤池边。"]'),
('song-ci-39','好事近','王炎2','宋','宋词','song-ci','好事近','[]','时节近元宵，天意人情都好。',53,'宋词/ci.song.11000.json','["时节近元宵，天意人情都好。", "烟柳露桃枝上，觉今年春早。", "遏云一曲凤将雏，疑是在蓬岛。", "玉笋扶杯潋滟，愿黑头难老。"]'),
('song-ci-40','水调歌头','王炎2','宋','宋词','song-ci','水调歌头','[]','爱日护轻暖，酝造小春时。',113,'宋词/ci.song.11000.json','["爱日护轻暖，酝造小春时。", "桃溪云敛，一点郎星吐青辉。", "炼玉颜容难老，点漆精神如旧，不用摘霜髭。", "厌薄蓬莱景，戏踏两凫飞。", "潘花底，陶柳外，细民肥。", "万家喜色，融瑞气拥牙绯。", "凭仗春葱洗玉，领略朱樱度曲，引满又何辞。", "只待琴歌毕，安步上丹墀。"]'),
('song-ci-41','念奴娇','王炎2','宋','宋词','song-ci','念奴娇','[]','晓来雨过，正海棠枝上，胭脂如滴。',120,'宋词/ci.song.11000.json','["晓来雨过，正海棠枝上，胭脂如滴。", "桃杏不敢来比似，信是倾城倾国。", "藏韵收香，谁能描貌，阁尽诗人笔。", "从教睡去，为留银烛终夕。", "不待过了清明，绿阴结子，无处寻春色。", "簌簌轻红飞一片，便觉临风凄恻。", "莫道无情，嫣然一笑，也似曾相识。", "惜花无主，自怜身是行客。"]'),
('song-ci-42','浪淘沙令','王炎2','宋','宋词','song-ci','浪淘沙令','[]','秋色满东篱。',64,'宋词/ci.song.11000.json','["秋色满东篱。", "露滴风吹。", "凭谁折取泛芳卮。", "长是年年重九日，苦恨开迟。", "因记得当时。", "共拈纤枝。", "而今寂寞凤孤飞。", "不似旧来心绪好，惟有花知。"]'),
('song-ci-43','采桑子','王炎2','宋','宋词','song-ci','采桑子','[]','一番飞次春风巧，细看工夫。',52,'宋词/ci.song.11000.json','["一番飞次春风巧，细看工夫。", "点缀红酥。", "此际多应别处无。", "玉人不与花为主，辜负芳菲。", "香透帘帏。", "谁向钗头插一枝。"]'),
('song-ci-44','好事近','王炎2','宋','宋词','song-ci','好事近','[]','玉颊映红绡，才报东风消息。',53,'宋词/ci.song.11000.json','["玉颊映红绡，才报东风消息。", "虽则清臞如许，有生香真色。", "相看动是隔年期，忍不饮涓滴。", "莫待轻飞一片，却说花堪惜。"]'),
('song-ci-45','临江仙','王炎2','宋','宋词','song-ci','临江仙','[]','雪片幻成肌骨，月华借与精神。',68,'宋词/ci.song.11000.json','["雪片幻成肌骨，月华借与精神。", "一声羌笛怨黄昏。", "吹香飘缟袂，脱迹委红裙。", "枝上青青结子，子中白白藏仁。", "那时别是一家春。", "劈泥尝煮酒，拂席卧清阴。"]'),
('song-ci-46','卜算子','王炎2','宋','宋词','song-ci','卜算子','[]','腻玉染深红，艳丽难常好。',52,'宋词/ci.song.11000.json','["腻玉染深红，艳丽难常好。", "已是人间祓禊时，花亦随春老。", "唤起曲生来，醉赏惟宜早。", "此去阴晴十日间，点点粘芳草。"]'),
('song-ci-47','木兰花慢','王炎2','宋','宋词','song-ci','木兰花慢','[]','博山香雾冷，新雨过、怯单衣。',124,'宋词/ci.song.11000.json','["博山香雾冷，新雨过、怯单衣。", "正飞絮濛濛，平芜杳杳，家在天涯。", "春难住、人易老，又等闲过了踏青时。", "枝上红稀绿暗，杜鹃刚向人啼。", "依依。", "谩叹歌生弹铗，尘满弦徽。", "想北山猿鹤，南溪鸥鹭，怪我归迟。", "青云事、今已晚，倚小窗、谁与话襟期。", "对酒有愁可解，擘笺无怨休题。"]'),
('song-ci-48','小重山','王炎2','宋','宋词','song-ci','小重山','[]','日脚才添一线长。',70,'宋词/ci.song.11000.json','["日脚才添一线长。", "葭灰吹玉管，转新阳。", "老来添得鬓边霜。", "年华换，归思满沧浪。", "唤客对凝香。", "公庭凫骛散，缓行觞。", "何须红袖立成行。", "清淡好，胜似听丝簧。"]'),
('song-ci-49','阮郎归','王炎2','宋','宋词','song-ci','阮郎归','[]','几回幽梦绕家山。',56,'宋词/ci.song.11000.json','["几回幽梦绕家山。", "怯闻梅弄残。", "潇潇黄落客毡寒。", "不禁衣带宽。", "身外事，意阑珊。", "人间行路难。", "寻思百计不如闲。", "休贪朱两轓。"]'),
('song-ci-50','临江仙','王炎2','宋','宋词','song-ci','临江仙','[]','试问休官林下去，何人得似高年。',70,'宋词/ci.song.11000.json','["试问休官林下去，何人得似高年。", "壶中不记岁时迁。", "吹箫新有伴，餐玉共求仙。", "有客尊前曾得见，月眉云鬓娟娟。", "断肠刺史独无眠。", "谁能闻一曲，偷向笛中传。"]'),
('song-ci-51','临江仙','王炎2','宋','宋词','song-ci','临江仙','[]','思忆故园花又发，等闲过了流年。',70,'宋词/ci.song.11000.json','["思忆故园花又发，等闲过了流年。", "休论升擢与平迁。", "拂衣归去好，无事即神仙。", "况是老人头雪白，羞看红粉婵娟。", "鸾孤凤只且随缘。", "莫将桃叶曲，留与世人传。"]'),
('song-ci-52','水调歌头','王炎2','宋','宋词','song-ci','水调歌头','[]','新涨鸭头绿，春满白苹洲。',114,'宋词/ci.song.11000.json','["新涨鸭头绿，春满白苹洲。", "小停画鹢，莫便折柳话离愁。", "飘渺觚棱在望，不用东风借便，一瞬到皇州。", "别酒十分酌，何惜覆瑶舟。", "从此去，上华顶，入清流。", "人门如许，自合唾手复公侯。", "老我而今衰谢，梦绕故园松菊，底事更迟留。", "早晚挂冠去，江上狎浮鸥。"]'),
('song-ci-53','南柯子・南歌子','王炎2','宋','宋词','song-ci','南柯子・南歌子','[]','天末家何许，津头客未归。',62,'宋词/ci.song.11000.json','["天末家何许，津头客未归。", "柳梢绿暗早莺啼。", "蝴蝶不知春去、绕园飞。", "选胜多游冶，当垆有丽姝。", "青翰载酒泛晴晖。", "不忍十分寥落、负花时。"]'),
('song-ci-54','好事近','王炎2','宋','宋词','song-ci','好事近','[]','闲日似年长，又在他乡春暮。',53,'宋词/ci.song.11000.json','["闲日似年长，又在他乡春暮。", "柳外一声鶗鴂，怨落花飞絮。", "苎罗只似旧时村，佳人在何处。", "试问鸱夷因甚，载轻颦同去。"]'),
('song-ci-55','朝中措','王炎2','宋','宋词','song-ci','朝中措','[]','杜鹃声断日曈昽。',57,'宋词/ci.song.11000.json','["杜鹃声断日曈昽。", "过雨湿残红。", "老色菱花影里，客愁蕉叶香中。", "柳梢飞絮，桃梢结子，断送春风。", "莫恨春无觅处，明年还在芳丛。"]'),
('song-ci-56','南柯子・南歌子','王炎2','宋','宋词','song-ci','南柯子・南歌子','[]','对镜鸾休舞，求凰凤自飞。',62,'宋词/ci.song.11000.json','["对镜鸾休舞，求凰凤自飞。", "珠钿翠珥密封题。", "中有鸾笺细字、没人知。", "环佩灯前结，辎軿月下归。", "笑他织女夜鸣机。", "空与牛郎相望、不相随。"]'),
('song-ci-57','朝中措','王炎2','宋','宋词','song-ci','朝中措','[]','蔷薇露染玉肌肤。',57,'宋词/ci.song.11000.json','["蔷薇露染玉肌肤。", "欲试缕金衣。", "一种出尘态度，偏宜月伴风随。", "初疑邂逅，湘妃洛女，似是还非。", "只恐乘云轻举，翩然飞度瑶池。"]'),
('song-ci-58','西江月','王炎2','宋','宋词','song-ci','西江月','[]','蔌蔌落红都尽，依然见此清姝。',58,'宋词/ci.song.11000.json','["蔌蔌落红都尽，依然见此清姝。", "水沈为骨玉为肤。", "留得春光少住。", "鸳帐巧藏翠幔，燕钗斜亸纤枝。", "休将往事更寻思。", "且为浓香一醉。"]'),
('song-ci-59','柳梢青','王炎2','宋','宋词','song-ci','柳梢青','[]','葭管风微。',61,'宋词/ci.song.11000.json','["葭管风微。", "莱衣香软，歌凤将雏。", "笑酌流霞，问人何处，别有瑶池。", "相将月佩霞裾。", "领凫舄、归朝玉墀。", "管取长年，进封大国，稳住清都。"]'),
('song-ci-60','踏莎行','王炎2','宋','宋词','song-ci','踏莎行','[]','木落天寒，年华又暮。',68,'宋词/ci.song.11000.json','["木落天寒，年华又暮。", "老来多病须调护。", "诗编酒榼总无缘，闲中赢得瞢腾睡。", "尘暗犀梳，香消翠被。", "悄无音信来青羽。", "新愁正上自眉峰，黄昏庭院潇潇雨。"]'),
('song-ci-61','清平乐','王炎2','宋','宋词','song-ci','清平乐','[]','一杯椒醑。',54,'宋词/ci.song.11000.json','["一杯椒醑。", "惜饮难成醉。", "爆竹声中人未睡。", "共道今宵守岁。", "不如且就衾裯。", "谁能细数更筹。", "三百六旬过了，明朝却是年头。"]'),
('song-ci-62','南柯子・南歌子','王炎2','宋','宋词','song-ci','南柯子・南歌子','[]','山冥云阴重，天寒雨意浓。',62,'宋词/ci.song.11000.json','["山冥云阴重，天寒雨意浓。", "数枝幽艳湿啼红。", "莫为惜花惆怅、对东风。", "蓑笠朝朝出，沟塍处处通。", "人间辛苦是三农。", "要得一犁水足、望年丰。"]'),
('song-ci-63','夜行船','王炎2','宋','宋词','song-ci','夜行船','[]','淡饭粗衣随分过。',72,'宋词/ci.song.11000.json','["淡饭粗衣随分过。", "新成就、庵寮一个。", "静处藏身，十分自在，只恁麽、有何不可。", "过眼空花都看破。", "红尘外、独行独坐。", "也没筹量，也没系绊，更觅甚、三乘四果。"]'),
('song-ci-64','临江仙','王炎2','宋','宋词','song-ci','临江仙','[]','鶗鴂一声春事了，不知苦劝谁归。',70,'宋词/ci.song.11000.json','["鶗鴂一声春事了，不知苦劝谁归。", "花梢香露染蔷薇。", "小梅酸著齿，酒榼正堪携。", "鸭绿一篙新雨过，远山半出修眉。", "仙翁理棹欲来时。", "绕檐乌鹊喜，报与主人知。"]'),
('song-ci-65','蓦山溪','王炎2','宋','宋词','song-ci','蓦山溪','[]','莺啼花谢，断送春归去。',102,'宋词/ci.song.11000.json','["莺啼花谢，断送春归去。", "雨后听鹃声，恰似诉、留春不住。", "韶光易迈，暗被老相催，无个事，没些愁，方是安身处。", "载松种菊，相对为宾主。", "终日掩柴扉，但只有、清风时度。", "不忺把酒，又不喜观书，饥时饭，饱时茶，困即齁齁睡。"]'),
('song-ci-66','忆秦娥','王炎2','宋','宋词','song-ci','忆秦娥','[]','头如雪。',56,'宋词/ci.song.11000.json','["头如雪。", "尘缘滚滚无休歇。", "无休歇。", "买田筑屋，是何时节。", "从今事事都休说。", "巢安寮里藏疏拙。", "藏疏拙。", "许谁为伴，溪山风月。"]'),
('song-ci-67','满江红','王炎2','宋','宋词','song-ci','满江红','[]','宦海浮沉，名与字、不能彰彻。',115,'宋词/ci.song.11000.json','["宦海浮沉，名与字、不能彰彻。", "青云上、诸公衮衮，难登狭劣。", "结绶弹冠成底事，解颐折角皆虚说。", "待黄粱、梦觉始归来，非明哲。", "易消释，空中雪。", "多亏缺，天边月。", "算人生必有，衰羸时节。", "恁是一阳来复后，梅花柳眼先春发。", "料明年、又老似今年，当休歇。"]'),
('song-ci-68','玉楼春','王炎2','宋','宋词','song-ci','玉楼春','[]','往年糊口谋升斗。',64,'宋词/ci.song.11000.json','["往年糊口谋升斗。", "朱墨尘埃粘两袖。", "黄粱梦断始归来，依旧琴书当左右。", "而今藏取持螯手。", "林下独居闲散又。", "问之何以得长年，寡欲少思安老朽。"]'),
('song-ci-69','玉楼春','王炎2','宋','宋词','song-ci','玉楼春','[]','大都四绪阴晴半。',64,'宋词/ci.song.11000.json','["大都四绪阴晴半。", "天上油云舒又卷。", "若还心也似云闲，老色何由来上面。", "生平辛苦今潇散。", "得丧荣枯皆历遍。", "人言不死是神仙，我但耳闻非眼见。"]'),
('song-ci-70','如梦令','杨冠卿','宋','宋词','song-ci','如梦令','[]','满院落花春寂。',40,'宋词/ci.song.11000.json','["满院落花春寂。", "风絮一帘斜日。", "翠钿晓寒轻，独倚千秋无力。", "无力。", "无力。", "蹙破远山愁碧。"]'),
('song-ci-71','生查子','杨冠卿','宋','宋词','song-ci','生查子','[]','娇莺恰恰啼，过水翻回去。',48,'宋词/ci.song.11000.json','["娇莺恰恰啼，过水翻回去。", "欲共诉芳心，故绕池边树。", "人去绮窗闲，弦断秦筝柱。", "百啭听新声，总是伤心处。"]'),
('song-ci-72','生查子','杨冠卿','宋','宋词','song-ci','生查子','[]','消瘦不胜寒，独立江南路。',48,'宋词/ci.song.11000.json','["消瘦不胜寒，独立江南路。", "罗袜暗生尘，不见凌波步。", "兰佩解鸣珰，往事凭谁诉。", "一纸彩云笺，好寄青鸾去。"]'),
('song-ci-73','生查子','杨冠卿','宋','宋词','song-ci','生查子','[]','潇湘日暮时，倚棹蒹葭浦。',48,'宋词/ci.song.11000.json','["潇湘日暮时，倚棹蒹葭浦。", "不见独醒人，愁对湘妃语。", "璧月送归云，一叶莲舟举。", "宝瑟奏清商，波底鱼龙舞。"]'),
('song-ci-74','浣溪沙','杨冠卿','宋','宋词','song-ci','浣溪沙','[]','洞口春深长薜萝。',48,'宋词/ci.song.11000.json','["洞口春深长薜萝。", "幽栖地僻少经过。", "一溪新绿涨晴波。", "惊梦觉来啼鸟近，惜春归去落花多。", "东风独倚奈愁何。"]'),
('song-ci-75','浣溪沙','杨冠卿','宋','宋词','song-ci','浣溪沙','[]','银叶香销暑簟清。',48,'宋词/ci.song.11000.json','["银叶香销暑簟清。", "枕鸳醉倚玉钗横。", "起来红日半窗明。", "多病情怀无可奈，惜花天气恼馀酲。", "瑶琴谁弄晓莺声。"]'),
('song-ci-76','霜天晓角','杨冠卿','宋','宋词','song-ci','霜天晓角','[]','渔舟簇簇。',54,'宋词/ci.song.11000.json','["渔舟簇簇。", "西塞山前宿。", "流水落红香远，春江涨、葡萄绿。", "蕲竹。", "奏新曲。", "惊回幽梦独。", "却把渔竿远去，骑鲸背、钓璜玉。"]'),
('song-ci-77','卜算子','杨冠卿','宋','宋词','song-ci','卜算子','[]','苍生喘未苏，贾笔论孤愤。',52,'宋词/ci.song.11000.json','["苍生喘未苏，贾笔论孤愤。", "文采风流今尚存，毫发无遗恨。", "凄恻近长沙，地僻秋将尽。", "长使英雄泪满襟，天意高难问。"]'),
('song-ci-78','垂丝钓','杨冠卿','宋','宋词','song-ci','垂丝钓','[]','翠帘昼卷。',81,'宋词/ci.song.11000.json','["翠帘昼卷。", "庭花日影初转。", "酒力未醒，眉黛还敛。", "停歌扇。", "背画阑倚遍。", "情无限。", "怅韶华又晚。", "锦鞯去后，愁宽珠袖金钏。", "碧云信远。", "难托西楼雁。", "空写银筝怨。", "肠欲断。", "更落红万点。"]'),
('song-ci-79','菩萨蛮','杨冠卿','宋','宋词','song-ci','菩萨蛮','[]','飞云障碧江天暮。',52,'宋词/ci.song.11000.json','["飞云障碧江天暮。", "杏花帘幕黄昏雨。", "翠袖怯春寒。", "有人愁倚阑。", "天涯芳草路。", "目送征鸿去。", "人远玉关长。", "尺书难寄将。"]'),
('song-ci-80','菩萨蛮','杨冠卿','宋','宋词','song-ci','菩萨蛮','[]','春山愁对修眉绿。',52,'宋词/ci.song.11000.json','["春山愁对修眉绿。", "春衫谁为裁冰縠。", "日暮倚阑干。", "不禁烟雾寒。", "湖边归去路。", "犹记传觞处。", "往事等空花。", "客心惊岁华。"]'),
('song-ci-81','菩萨蛮','杨冠卿','宋','宋词','song-ci','菩萨蛮','[]','冰肌玉衬香绡薄。',52,'宋词/ci.song.11000.json','["冰肌玉衬香绡薄。", "无言独倚阑干角。", "相见又还休。", "可堪归去愁。", "碧波溪上路。", "几阵黄昏雨。", "归去断人肠。", "纱厨枕簟凉。"]'),
('song-ci-82','菩萨蛮','杨冠卿','宋','宋词','song-ci','菩萨蛮','[]','玉妃夜宴瑶池冷。',52,'宋词/ci.song.11000.json','["玉妃夜宴瑶池冷。", "翩然飞下霓旌影。", "天阔水云长。", "风飘舞袖香。", "姑山人似旧。", "清压红梅瘦。", "同凭玉阑干。", "光摇银海寒。"]'),
('song-ci-83','好事近','杨冠卿','宋','宋词','song-ci','好事近','[]','晚起倦梳妆，斜压翠鬟云鬓。',53,'宋词/ci.song.11000.json','["晚起倦梳妆，斜压翠鬟云鬓。", "手拈花枝辄笑，问青鸾音信。", "绣帘慵卷玉钩垂，风篁奏馀韵。", "灯火黄昏院落，报雕鞍人近。"]'),
('song-ci-84','好事近','杨冠卿','宋','宋词','song-ci','好事近','[]','细雨落檐花，帘卷金泥红湿。',53,'宋词/ci.song.11000.json','["细雨落檐花，帘卷金泥红湿。", "楼外远山横翠，染修眉愁碧。", "旧游春梦了无痕，香尘暗瑶瑟。", "凭仗青鸾飞去，问新来消息。"]'),
('song-ci-85','谒金门','杨冠卿','宋','宋词','song-ci','谒金门','[]','伤漂泊。',53,'宋词/ci.song.11000.json','["伤漂泊。", "负了花前期约。", "寒食清明都过却。", "愁怀无处著。", "晴日柳阴池阁。", "风絮斜穿帘幕。", "帘外秋千闲彩索。", "断肠人寂寞。"]'),
('song-ci-86','忆秦娥','杨冠卿','宋','宋词','song-ci','忆秦娥','[]','东风恶。',56,'宋词/ci.song.11000.json','["东风恶。", "雪花乱舞穿帘幕。", "穿帘幕。", "寒侵绿绮，音断弦索。", "宫梅已破香红萼。", "梅妆想称伊梳掠。", "伊梳掠。", "十分全似，旧时京洛。"]'),
('song-ci-87','忆秦娥','杨冠卿','宋','宋词','song-ci','忆秦娥','[]','云垂幕。',56,'宋词/ci.song.11000.json','["云垂幕。", "江天雪似杨花落。", "杨花落。", "翠衾不暖，晓寒偏觉。", "起来独倚西楼角。", "客怀无耐伤离索。", "伤离索。", "蛮笺欲寄，塞鸿难托。"]'),
('song-ci-88','清平乐','杨冠卿','宋','宋词','song-ci','清平乐','[]','翠团嘉树。',54,'宋词/ci.song.11000.json','["翠团嘉树。", "杜宇呼春去。", "帘卷金泥凝望处。", "几点红薇香雨。", "等闲过了花时。", "殷勤来问酴醿。", "恰有一枝春在，画楼红日林西。"]'),
('song-ci-89','柳梢青','杨冠卿','宋','宋词','song-ci','柳梢青','[]','红药翻阶。',61,'宋词/ci.song.11000.json','["红药翻阶。", "天香国艳，辉映楼台。", "解语浑如，三千粉黛，十二金钗。", "青鞋踏破苍苔。", "趁舞蝶、游蜂去来。", "宿粉偷香，也应难似，年少情怀。"]'),
('song-ci-90','柳梢青','杨冠卿','宋','宋词','song-ci','柳梢青','[]','金蕊飘残。',61,'宋词/ci.song.11000.json','["金蕊飘残。", "江城秋晚，月冷霜寒。", "一种幽芳，雕冰镂玉，舞凤翔鸾。", "悠然静对南山。", "笑琼沼、鸳飞翠澜。", "小玉惊呼，太真娇困，俯槛慵看。"]'),
('song-ci-91','柳梢青','杨冠卿','宋','宋词','song-ci','柳梢青','[]','归梦迢迢。',61,'宋词/ci.song.11000.json','["归梦迢迢。", "分明曾见，舞遍云韶。", "解道相思，愁宽金钏，瘦损宫腰。", "觉来情绪无聊。", "正戍角、声翻丽谯。", "楚塞山长，巫阳人远，斗帐香消。"]'),
('song-ci-92','西江月','杨冠卿','宋','宋词','song-ci','西江月','[]','妙墨龙蛇飞动，新词雪月交光。',58,'宋词/ci.song.11000.json','["妙墨龙蛇飞动，新词雪月交光。", "论文齿颊带冰霜。", "凤阁从来宫样。", "寿菊丛开三径，清姿高压群芳。", "折花聊尔问行藏。", "会见横飞直上。"]'),
('song-ci-93','西江月','杨冠卿','宋','宋词','song-ci','西江月','[]','罗袜浪传仙子，宫梅休写华光。',58,'宋词/ci.song.11000.json','["罗袜浪传仙子，宫梅休写华光。", "人言寿客饱经霜。", "不趁凡花入样。", "万玉森罗素节，一枝剩有馀芳。", "孤高肯使蝶蜂藏。", "特立甘泉顶上。"]'),
('song-ci-94','西江月','杨冠卿','宋','宋词','song-ci','西江月','[]','昨梦钧天帝所，曾陪奏赋明光。',58,'宋词/ci.song.11000.json','["昨梦钧天帝所，曾陪奏赋明光。", "玉除金蕊映秋霜。", "尽道宫花别样。", "娇额涂黄牢就，金莲衬步齐芳。", "舞鸾仪凤巧难藏。", "羞杀繁红陌上。"]'),
('song-ci-95','东坡引','杨冠卿','宋','宋词','song-ci','东坡引','[]','绿波芳草路。',67,'宋词/ci.song.11000.json','["绿波芳草路。", "别离记南浦。", "香云翦赠青丝缕。", "钗分金半股。", "钗分金半股。", "阳关一曲声凄楚。", "惹起离筵愁绪。", "梦魂拟逐征鸿去。", "行云无定据。", "行云无定据。"]'),
('song-ci-96','鹧鸪天','杨冠卿','宋','宋词','song-ci','鹧鸪天','[]','岁月如驰乌兔飞。',64,'宋词/ci.song.11000.json','["岁月如驰乌兔飞。", "情怀著酒强支持。", "经年不见宫妆面，秾碧谁斟翡翠卮。", "江路晚，夕阳低。", "奚奴空负锦囊归。", "欲凭驿使传芳信，未放东风第一枝。"]'),
('song-ci-97','小重山','杨冠卿','宋','宋词','song-ci','小重山','[]','一笑回眸百媚生。',70,'宋词/ci.song.11000.json','["一笑回眸百媚生。", "娇羞佯不语，艳波横。", "缓移莲步绕阶行。", "凝情久，幽怨托银筝。", "些事那回曾。", "水晶双枕冷，簟纹平。", "窥人燕子苦无情。", "惊梦断，何处觅云行。"]'),
('song-ci-98','蝶恋花','杨冠卿','宋','宋词','song-ci','蝶恋花','[]','舞处曾看花满面。',70,'宋词/ci.song.11000.json','["舞处曾看花满面。", "独倚东风，往事思量遍。", "绿怨红愁春不管。", "天涯芳草人肠断。", "一纸云笺鱼雁远。", "归凤求凰，谁识琴心怨。", "臂枕香消眉黛敛。", "也应为我宽金钏。"]'),
('song-ci-99','蝶恋花','杨冠卿','宋','宋词','song-ci','蝶恋花','[]','月冷花寒宫漏促。',70,'宋词/ci.song.11000.json','["月冷花寒宫漏促。", "人在虚檐，玉体温无粟。", "弦断鸾胶还再续。", "娇云时霎情难足。", "解道双鸳愁独宿。", "宿翠偎红，蛱蝶元相逐。", "蓬海路遥天六六。", "终须伴我骑黄鹄。"]'),
('song-ci-100','水调歌头','杨冠卿','宋','宋词','song-ci','水调歌头','[]','春涨一篙绿，江阔暮涛寒。',114,'宋词/ci.song.11000.json','["春涨一篙绿，江阔暮涛寒。", "龙骧万斛飞举，鲸饮酒杯宽。", "醉倚舵楼清啸，目送孤鸿杳霭，景意与俱闲。", "恍若驭风去，蓬岛旧家山。", "记吾庐，环翠竹，拱苍官。", "碧云信杳，谁为日日报平安。", "桂棹桃溪归后，流水落红香寂，春事想阑珊。", "赖有锦囊句，写向此中看。"]'),
('song-ci-101','水调歌头','杨冠卿','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','形胜访淮楚，骑鹤到扬州。',114,'宋词/ci.song.11000.json','["形胜访淮楚，骑鹤到扬州。", "春风十里帘幕，香霭小红楼。", "楼外长江今古，谁是济川舟楫，烟浪拍天浮。", "喜见紫芝宇，儒雅更风流。", "气吞虹，才倚马，烂银钩。", "功名年少馀事，雕鹗几横秋。", "行演丝纶天上，环倚玉皇香案，仙袂揖浮丘。", "落笔惊风雨，润色焕皇猷。"]'),
('song-ci-102','水调歌头','杨冠卿','宋','宋词','song-ci','水调歌头','[]','年少青云客，怀抱百忧宽。',114,'宋词/ci.song.11000.json','["年少青云客，怀抱百忧宽。", "北窗醉卧春晓，归梦趁吴帆。", "来访鸱夷仙迹，极目平湖烟浪，万象一毫端。", "云海渺空阔，咫尺是蓬山。", "佩飞霞，囊古锦，几凭阑。", "赤城应有居士，凤举更龙蟠。", "待向玉霄东望，相与神游八极，身未似云闲。", "长剑倚天外，功业镜频看。"]'),
('song-ci-103','水调歌头','杨冠卿','宋','宋词','song-ci','水调歌头','[]','曳杖罗浮去，辽鹤正南翔。',114,'宋词/ci.song.11000.json','["曳杖罗浮去，辽鹤正南翔。", "青鸾为报消息，岩壑久相望。", "无奈渔溪欸乃，唤起苹洲昨梦，风雨趁归航。", "万里家何许，天阔水云长。", "历五湖，转湘楚，下三江。", "兴亡千古馀恨，收拾付诗囊。", "重到然犀矶渚，不见骑鲸仙子，客意转凄凉。", "举酒酹江月，襟袖泪淋浪。"]'),
('song-ci-104','水龙吟','杨冠卿','宋','宋词','song-ci','水龙吟','[]','渡江天马龙飞，翠华小住兴王地。',129,'宋词/ci.song.11000.json','["渡江天马龙飞，翠华小住兴王地。", "石城锺阜，雄依天堑，鼎安神器。", "鳷鹊楼高，建章宫阔，玉绳低坠。", "望郁葱佳气，非烟非雾，方呈瑞、璇霄际。", "貔虎云屯羽卫。", "壮金汤、更隆国势。", "天骄胆落，狼烽昼熄，玉门晏闭。", "祗谒陵园，长安□远，中兴可冀。", "笑六朝旧事，空随流水，千古恨、无人记。"]'),
('song-ci-105','贺新郎','杨冠卿','宋','宋词','song-ci','贺新郎','[]','薄暮垂虹去。',142,'宋词/ci.song.11000.json','["薄暮垂虹去。", "正江天、残霞冠日，乱鸿遵渚。", "万顷云涛风浩荡，笑整羽轮飞渡。", "问弱水、神仙何处。", "翳凤骑麟思往事，记朝元、金殿闻钟鼓。", "环佩响，翠鸾舞。", "梦中失却江南路。", "待西风、长城饮马，朔庭张弩。", "目尽青天何时到，赢得儿童好语。", "怅未复、长陵抔土。", "西子五湖归去后，泛仙舟、尚许寻盟否。", "风袂逐，片帆举。"]'),
('song-ci-106','六州','崔敦诗','宋','宋词','song-ci','六州','[]','商秋吉，嘉会协中辛。',147,'宋词/ci.song.11000.json','["商秋吉，嘉会协中辛。", "涓路寝，修禋祀，圣德昭清。", "端志虑，罄竭斋精。", "锦绣排天仗，羽卫滨纷。", "朝太室、返中宸。", "被衮接神明。", "时平天时俱清晏，兼丰年和气，品物达芳馨。", "瞻熉座，舂容娭燕三灵。", "奠瑶爵，荐量币，清思呦冥冥。", "望昆仑。", "嘉祥塞絪緼。", "诚殚礼洽庆休成。", "润泽被生民。", "端门肆眚，昕庭称贺，俱将景福万寿、祝双亲。"]'),
('song-ci-107','十二时・忆少年','崔敦诗','宋','宋词','song-ci','十二时・忆少年','[]','勋华并、天胙昌期。',155,'宋词/ci.song.11000.json','["勋华并、天胙昌期。", "圣德茂重离。", "英明经远，浚哲昭微。", "宝俭更深慈。", "观万国、累洽重熙。", "对明时。", "报礼秩神祗。", "玉帛奏华夷。", "雍肃显相，百辟各钦祗。", "奄嘉虞英璧奠华滋。", "神安坐、景气澄虚。", "极光焰、烛长丽。", "展诗应律，万舞逶迟。", "三献洽皇仪。", "垂露浸庆祜来宜。", "礼无违。", "鸣鸾临帝阙，飞凤下天倪。", "清和寰宇，霈泽一朝驰。", "醇化无为。", "万祀巩洪基。"]'),
('song-ci-108','柳梢青','赵汝愚','宋','宋词','song-ci','柳梢青','[]','水月光中，烟霞影里，涌出楼台。',61,'宋词/ci.song.11000.json','["水月光中，烟霞影里，涌出楼台。", "空外笙箫，云间笑语，人在蓬莱。", "天香暗逐风回。", "正十里、荷花盛开。", "买个扁舟，山南游遍，山北归来。"]'),
('song-ci-109','摸鱼儿','辛弃疾','宋','宋词','song-ci','摸鱼儿','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','更能消、几番风雨。',140,'宋词/ci.song.11000.json','["更能消、几番风雨。", "匆匆春又归去。", "惜春长恨花开早，何况落红无数。", "春且住。", "见说道、天涯芳草迷归路。", "怨春不语。", "算只有殷勤，画檐珠网，尽日惹飞絮。", "长门事，准拟佳期又误。", "蛾眉曾有人妒。", "千金纵买相如赋，脉脉此情谁诉。", "君莫舞。", "君不见、玉环飞燕皆尘土。", "闲愁最苦。", "休去倚危楼，斜阳正在，烟柳断肠处。"]'),
('song-ci-110','摸鱼儿','辛弃疾','宋','宋词','song-ci','摸鱼儿','[]','望飞来、半空鸥鹭。',140,'宋词/ci.song.11000.json','["望飞来、半空鸥鹭。", "须臾动地鼙鼓。", "截江组练驱山去，鏖战未收貔虎。", "朝又暮。", "诮惯得、吴儿不怕蛟龙怒。", "风波平步。", "看红旆惊飞，跳鱼直上，蹙踏浪花舞。", "凭谁问，万里长鲸吞吐。", "人间儿戏千弩。", "滔天力倦知何事，白马素车东去。", "堪恨处。", "人道是、子胥冤愤终千古。", "功名自误。", "谩教得陶朱，五湖西子，一舸弄烟雨。"]'),
('song-ci-111','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','三径初成，鹤怨猿惊，稼轩未来。',139,'宋词/ci.song.11000.json','["三径初成，鹤怨猿惊，稼轩未来。", "甚云山自许，平生意气，衣冠人笑，抵死尘埃。", "意倦须还，身闲贵早，岂为莼羹鲈鲙哉。", "秋江上，看惊弦雁避，骇浪船回。", "东冈更葺茅斋。", "好都把轩窗临水开。", "要小舟行钓，先应种柳，疏篱护竹，莫碍观梅。", "秋菊堪餐，春兰可佩，留待先生手自栽。", "沈吟久，怕君恩未许，此意徘徊。"]'),
('song-ci-112','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','伫立潇湘，黄鹄高飞，望君不来。',139,'宋词/ci.song.11000.json','["伫立潇湘，黄鹄高飞，望君不来。", "被东风吹堕，西江对语，急呼斗酒，旋拂征埃。", "却怪英姿，有如君者，犹欠封侯万里哉。", "空赢得，道江南佳句，只有方回。", "锦帆画舫行斋。", "怅雪浪粘天江影开。", "记我行南浦，送君折柳，君逢驿使，为我攀梅。", "落帽山前，呼鹰台下，人道花须满县栽。", "都休问，看云霄高处，鹏翼徘徊。"]'),
('song-ci-113','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','渡江天马南来，几人真是经纶手。',126,'宋词/ci.song.11000.json','["渡江天马南来，几人真是经纶手。", "长安父老，新亭风景，可怜依旧。", "夷甫诸人，神州沈陆，几曾回首。", "算平戎万里，功名本是，真儒事、君知否。", "况有文章山斗。", "对桐阴、满庭清昼。", "当年堕地，而今试看，风云奔走。", "绿野风烟，平泉草木，东山歌酒。", "待他年，整顿乾坤事了，为先生寿。"]'),
('song-ci-114','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','玉皇殿阁微凉，看公重试薰风手。',126,'宋词/ci.song.11000.json','["玉皇殿阁微凉，看公重试薰风手。", "高门画戟，桐阴阁道，青青如旧。", "兰佩芳空，蛾眉谁妒，无言搔首。", "甚年年却有，呼韩塞上，人争问、公安否。", "金印明年如斗。", "向中州、锦衣行昼。", "依然盛事，貂蝉前后，凤麟飞走。", "富贵浮云，我评轩冕，不如杯酒。", "待从公，痛饮八千馀岁，伴庄椿寿。"]'),
('song-ci-115','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','楚天千里清秋，水随天去秋无际。',126,'宋词/ci.song.11000.json','["楚天千里清秋，水随天去秋无际。", "遥岑远目，献愁供恨，玉簪螺髻。", "落日楼头，断鸿声里，江南游子。", "把吴钩看了，栏干拍遍，无人会、登临意。", "休说鲈鱼堪鲙。", "尽西风、季鹰归未。", "求田问舍，怕应羞见，刘郎才气。", "可惜流年，忧愁风雨，树犹如此。", "倩何人，唤取盈盈翠袖，搵英雄泪。"]'),
('song-ci-116','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','笳鼓归来，举鞭问、何如诸葛。',115,'宋词/ci.song.11000.json','["笳鼓归来，举鞭问、何如诸葛。", "人道是、匆匆五月，渡泸深入。", "白羽风生貔虎噪，青溪路断猩鼯泣。", "早红尘、一骑落平冈，捷书急。", "三万卷，龙韬客。", "浑未得，文章力。", "把诗书马上，笑驱锋镝。", "金印明年如斗大，貂蝉却自兜鍪出。", "待刻公、勋业到□云，浯溪石。"]'),
('song-ci-117','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','瘴雨蛮烟，十年梦、尊前休说。',115,'宋词/ci.song.11000.json','["瘴雨蛮烟，十年梦、尊前休说。", "春正好、故园桃李，待君花发。", "儿女灯前和泪拜，鸡豚社里归时节。", "看依然、舌在齿牙牢，心如铁。", "治国手，封侯骨。", "腾汉漫，排阊阖。", "待十分做了，诗书勋业。", "常日念君归去好，而今却恨中年别。", "笑江头、明月更多情，今宵缺。"]'),
('song-ci-118','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','蜀道登天，一杯送、绣衣行客。',119,'宋词/ci.song.11000.json','["蜀道登天，一杯送、绣衣行客。", "还自叹、中年多病，不堪离别。", "东北看惊诸葛《表》，西南更草相如《檄》。", "把功名、收拾付君侯，如椽笔。", "儿女泪，君休滴。", "荆楚路，吾能说。", "要新诗准备，庐江山色。", "赤壁矶头千古浪，铜鞮陌上三更月。", "正梅花、万里雪深时，须相忆。"]'),
('song-ci-119','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','快上西楼，怕天放、浮云遮月。',115,'宋词/ci.song.11000.json','["快上西楼，怕天放、浮云遮月。", "但唤取、玉纤横笛，一声吹裂。", "谁做冰壶浮世界，最怜玉斧修时节。", "问常娥、孤冷有愁无，应华发。", "云液满，琼杯滑。", "长袖起，清歌咽。", "叹十常八九，欲磨还缺。", "若得长圆如此夜，人情未必看承别。", "把从前、离恨总成欢，归时说。"]'),
('song-ci-120','满江红','辛弃疾','宋','宋词','song-ci','满江红','["\u957f\u6c5f"]','鹏翼垂空，笑人世、苍然无物。',115,'宋词/ci.song.11000.json','["鹏翼垂空，笑人世、苍然无物。", "还又向、九重深处，玉阶山立。", "袖里珍奇光五色，他年要补天西北。", "且归来、谈笑护长江，波澄碧。", "佳丽地，文章伯。", "金缕唱，红牙拍。", "看尊前飞下，日边消息。", "料想宝香黄阁梦，依然画舫青溪笛。", "待如今、端的约锺山，长相识。"]'),
('song-ci-121','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','落日苍茫，风才定、片帆无力。',115,'宋词/ci.song.11000.json','["落日苍茫，风才定、片帆无力。", "还记得、眉来眼去，水光山色。", "倦客不知身近远，佳人已卜归消息。", "便归来、只是赋行云，襄王客。", "些个事，如何得。", "知有恨，休重忆。", "但楚天特地，暮云凝碧。", "过眼不如人意事，十常八九今头白。", "笑江州、司马太多情，青衫湿。"]'),
('song-ci-122','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','过眼溪山，怪都似、旧时曾识。',115,'宋词/ci.song.11000.json','["过眼溪山，怪都似、旧时曾识。", "是梦里、寻常行遍，江南江北。", "佳处径须携杖去，能消几两平生屐。", "笑尘埃、三十九年非，长为客。", "吴楚地，东南拆。", "英雄事，曹刘敌。", "被西风吹尽，了无陈迹。", "楼观才成人已去，旌旗未卷头先白。", "叹人间、哀乐转相寻，今犹昔。"]'),
('song-ci-123','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','湖海平生，算不负、苍髯如戟。',115,'宋词/ci.song.11000.json','["湖海平生，算不负、苍髯如戟。", "闻道是、君王著意，太平长策。", "此老自当兵十万，长安正在天西北。", "便凤凰、飞诏下天来，催归急。", "车马路，儿童泣。", "风雨暗，旌旗湿。", "看野梅官柳，东风消息。", "莫向蔗庵追语笑，只今松竹无颜色。", "问人间、谁管别离愁，杯中物。"]'),
('song-ci-124','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','笑拍洪崖，问千丈、翠岩谁削。',115,'宋词/ci.song.11000.json','["笑拍洪崖，问千丈、翠岩谁削。", "依旧是、西风白马，北村南郭。", "似整复斜僧屋乱，欲吞还吐林烟薄。", "觉人间、万事到秋来，都摇落。", "呼斗酒，同君酌。", "□小隐，寻幽约。", "且丁宁休负，北山猿鹤。", "有鹿从渠求鹿梦，非鱼定未知鱼乐。", "正仰看、飞鸟却应人，回头错。"]'),
('song-ci-125','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','曲几蒲团，方丈里、君来问疾。',115,'宋词/ci.song.11000.json','["曲几蒲团，方丈里、君来问疾。", "更夜雨、匆匆别去，一杯南北。", "万事莫侵闲鬓发，百年正要佳眠食。", "最难忘、此语重殷勤，千金直。", "西崦路，东岩石。", "携手处，今陈迹。", "望重来犹有，旧盟如日。", "莫信蓬莱风浪隔，垂天自有扶摇力。", "对梅花、一夜苦相思，无消息。"]'),
('song-ci-126','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','带湖吾甚爱，千丈翠奁开。',114,'宋词/ci.song.11000.json','["带湖吾甚爱，千丈翠奁开。", "先生杖屦无事，一日走千回。", "凡我同盟鸥鸟，今日既盟之后，来往莫相猜。", "白鹤在何处，尝试与偕来。", "破青萍，排翠藻，立苍苔。", "窥鱼笑汝痴计，不解举吾杯。", "废沼荒丘畴昔，明月清风此夜，人世几欢哀。", "东岸绿阴少，杨柳更须栽。"]'),
('song-ci-127','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','白日射金阙，虎豹九关开。',114,'宋词/ci.song.11000.json','["白日射金阙，虎豹九关开。", "见君谏疏频上，高论挽天回。", "千古忠肝义胆，万里蛮烟瘴雨，往事莫惊猜。", "政恐不免耳，消息日边来。", "笑吾庐，门掩草，径封苔。", "未应两手无用，要把蟹螯杯。", "说剑论诗馀事，醉舞狂歌欲倒，老子颇堪哀。", "白发宁有种，一一醒时栽。"]'),
('song-ci-128','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','折尽武昌柳，挂席上潇湘。',114,'宋词/ci.song.11000.json','["折尽武昌柳，挂席上潇湘。", "二年鱼鸟江上，笑我往来忙。", "富贵何时休问，离别中年堪恨，憔悴鬓成霜。", "丝竹陶写耳，急羽且飞觞。", "序兰亭，歌赤壁，绣衣香。", "使君千骑鼓吹，风采汉侯王。", "莫把骊驹频唱，可惜南楼佳处，风月已凄凉。", "在家贫亦好，此语试平章。"]'),
('song-ci-129','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','今日复何日，黄菊为谁开。',114,'宋词/ci.song.11000.json','["今日复何日，黄菊为谁开。", "渊明漫爱重九，胸次正崔嵬。", "酒亦关人何事，正自不能不尔，谁遣白衣来。", "醉把西风扇，随处障尘埃。", "为公饮，须一日，三百杯。", "此山高处东望，云气见蓬莱。", "翳凤骖鸾公去，落佩倒冠吾事，抱病且登台。", "归路有明月，人影共徘徊。"]'),
('song-ci-130','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','君莫赋幽愤，一语试相开。',114,'宋词/ci.song.11000.json','["君莫赋幽愤，一语试相开。", "长安车马道上，平地起崔嵬。", "我愧渊明久矣，独借此翁湔洗，素壁写归来。", "斜日透虚隙，一线万飞埃。", "断吾生，左持蟹，右持杯。", "买山自种云树，山下斸烟莱。", "百炼都成绕指，万事直须称好，人世几舆台。", "刘郎更堪笑，刚赋看花回。"]'),
('song-ci-131','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','造物故豪纵，千里玉鸾飞。',114,'宋词/ci.song.11000.json','["造物故豪纵，千里玉鸾飞。", "等闲更把，万斛琼粉盖颇黎。", "好卷垂虹千丈，只放冰壶一色，云海路应迷。", "老子旧游处，回首梦耶非。", "谪仙人，鸥鸟伴，两忘机。", "掀髯把酒一笑，诗在片帆西。", "寄语烟波旧侣，闻道莼鲈正美，休制芰荷衣。", "上界足官府，汗漫与君期。"]'),
('song-ci-132','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','落日塞尘起，胡骑猎清秋。',114,'宋词/ci.song.11000.json','["落日塞尘起，胡骑猎清秋。", "汉家组练十万，列舰耸高楼。", "谁道投鞭飞渡，忆昔鸣髇血污，风雨佛狸愁。", "季子正年少，匹马黑貂裘。", "今老矣，搔白首，过扬州。", "倦游欲去江上，手种橘千头。", "二客东南名胜，万卷诗书事业，尝试与君谋。", "莫射南山虎，直觅富民侯。"]'),
('song-ci-133','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','万事到白发，日月几西东。',114,'宋词/ci.song.11000.json','["万事到白发，日月几西东。", "羊肠九折歧路，老我惯经从。", "竹树前溪风月，鸡酒东家父老，一笑偶相逢。", "此乐竟谁觉，天外有冥鸿。", "味平生，公与我，定无同。", "玉堂金马，自有佳处著诗翁。", "好锁云烟窗户，怕入丹青图画，飞去了无踪。", "此语更痴绝，真有虎头风。"]'),
('song-ci-134','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','上古八千岁，才是一春秋。',114,'宋词/ci.song.11000.json','["上古八千岁，才是一春秋。", "不应此日，刚把七十寿君侯。", "看取垂天云翼，九万里风在下，与造物同游。", "君欲计岁月，当试问庄周。", "醉淋浪，歌窈窕，舞温柔。", "从今杖屦南涧，白日为君留。", "闻道钧天帝所，频上玉卮春酒，冠珮拥龙楼。", "快上星辰去，名姓动金瓯。"]'),
('song-ci-135','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','云卧衣裳冷。',141,'宋词/ci.song.11000.json','["云卧衣裳冷。", "看萧然、风前月下，水边幽影。", "罗袜尘生凌波去，汤沐烟江万顷。", "爱一点、娇黄成晕。", "不记相逢曾解佩，甚多情、为我香成阵。", "待和泪，收残粉。", "灵均千古怀沙恨。", "恨当时、匆匆忘把，此仙题品。", "烟雨凄迷僝僽损，翠袂摇摇谁整。", "谩写入、瑶琴幽愤。", "弦断招魂无人赋，但金杯的皪银台润。", "愁殢酒，又独醒。"]'),
('song-ci-136','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','兔园旧赏，怅遗踪、飞鸟千山都绝。',122,'宋词/ci.song.11000.json','["兔园旧赏，怅遗踪、飞鸟千山都绝。", "缟带银杯江上路，惟有南枝香别。", "万事新奇，青山一夜，对我头先白。", "倚岩千树，玉龙飞上琼阙。", "莫惜雾鬓风鬟，试教骑鹤，去约尊前月。", "自与诗翁磨冻砚，看扫《幽兰》新阙。", "便拟□□，人间挥汗，留取层冰洁。", "此君何事，晚来还易腰折。"]'),
('song-ci-137','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','对花何似，似吴宫初教，翠围红阵。',120,'宋词/ci.song.11000.json','["对花何似，似吴宫初教，翠围红阵。", "欲笑还愁羞不语，惟有倾城娇韵。", "翠盖风流，牙签名字，旧赏那堪省。", "天香染露，晓来衣润谁整。", "最爱弄玉团酥，就中一朵，曾入扬州咏。", "华屋金盘人未醒，燕子飞来春尽。", "最忆当年，沈香亭北，无限春风恨。", "醉中休问，夜深花睡香冷。"]'),
('song-ci-138','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','我来吊古，上危楼、赢得闲愁千斛。',120,'宋词/ci.song.11000.json','["我来吊古，上危楼、赢得闲愁千斛。", "虎踞龙蟠何处是，只是兴亡满目。", "柳外斜阳，水边归鸟，陇上吹乔木。", "片帆西去，一声谁喷霜竹。", "却忆安石风流，东山岁晚，泪落哀筝曲。", "儿辈功名都付与，长日惟消棋局。", "宝镜难寻，碧云将暮，谁劝杯中绿。", "江头风怒，朝来波浪翻屋。"]'),
('song-ci-139','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','野棠花落，又匆匆、过了青明时节。',120,'宋词/ci.song.11000.json','["野棠花落，又匆匆、过了青明时节。", "剗地东风欺客梦，一夜云屏寒怯。", "曲岸持觞，垂杨系马，此地曾轻别。", "楼空人去，旧游飞燕能说。", "闻道绮陌东头，行人长见，帘底纤纤月。", "旧恨春江流未断，新恨云山千叠。", "料得明朝，尊前重见，镜里花难折。", "也应惊问，近来多少华发。"]'),
('song-ci-140','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','晚风吹雨，战新荷、声乱明珠苍璧。',120,'宋词/ci.song.11000.json','["晚风吹雨，战新荷、声乱明珠苍璧。", "谁把香奁收宝镜，云锦红涵湖碧。", "飞鸟翻空，游鱼吹浪，惯趁笙歌席。", "坐中豪气，看公一饮千石。", "遥想处士风流，鹤随人去，老作飞仙伯。", "茅舍疏篱今在否，松竹已非畴昔。", "欲说当年，望湖楼下，水与云宽窄。", "醉中休问，断肠桃叶消息。"]'),
('song-ci-141','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','近来何处有吾愁，何处还知吾乐。',119,'宋词/ci.song.11000.json','["近来何处有吾愁，何处还知吾乐。", "一点凄凉千古意，独倚西风寥廓。", "并竹寻泉，和云种树，唤做真闲客。", "此心闲处，不应长藉邱壑。", "休说往事皆非，而今云是，且把清尊酌。", "醉里不知谁是我，非月非云非鹤。", "冷露风高，松梢桂子，醉了还醒却。", "北窗高卧，莫教啼鸟惊著。"]'),
('song-ci-142','新荷叶','辛弃疾','宋','宋词','song-ci','新荷叶','[]','人已归来，杜鹃欲劝谁归。',100,'宋词/ci.song.11000.json','["人已归来，杜鹃欲劝谁归。", "绿树如云，等闲借与莺飞。", "兔葵燕梦，问刘郎、几度沾衣。", "翠屏幽梦，觉来水绕山围。", "有酒重携。", "小园随意芳菲。", "往日繁华，而今物是人非。", "春风半面，记当年、初识崔徽。", "南云雁少，锦书无个因依。"]'),
('song-ci-143','新荷叶','辛弃疾','宋','宋词','song-ci','新荷叶','[]','春色如愁，行云带雨才归。',100,'宋词/ci.song.11000.json','["春色如愁，行云带雨才归。", "春意长闲，游丝尽日低飞。", "闲愁几许，更晚风、特地吹衣。", "小窗人静，棋声似解重围。", "光景难携。", "任他鶗鴂芳菲。", "细数从前，不应诗酒皆非。", "知音弦断，笑渊明、空抚馀徽。", "停杯对影，待邀明月相依。"]'),
('song-ci-144','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','长安道，投老倦游归。',100,'宋词/ci.song.11000.json','["长安道，投老倦游归。", "七十古来稀。", "藕花雨湿前湖夜，桂枝风澹小山时。", "怎消除，须殢酒，更吟诗。", "也莫向、竹边孤负雪。", "也莫向、柳边孤负月。", "闲过了，总成痴。", "种花事业无人问，对花情味只天知。", "笑山中，云出早，鸟归迟。"]'),
('song-ci-145','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','西园买，谁载万金归。',100,'宋词/ci.song.11000.json','["西园买，谁载万金归。", "多病胜游稀。", "风斜画烛天香夜，凉生翠盖酒酣时。", "待重寻，居士谱，谪仙诗。", "看黄底、御袍元自贵。", "看红底、状元新得意。", "如斗大，只花痴。", "汉妃翠被娇无奈，吴娃粉阵恨谁知。", "但纷纷，蜂蝶乱，送春迟。"]'),
('song-ci-146','洞仙歌','辛弃疾','宋','宋词','song-ci','洞仙歌','[]','江头父老，说新来朝野。',105,'宋词/ci.song.11000.json','["江头父老，说新来朝野。", "都道今年太平也。", "见朱颜绿鬓，玉带金鱼，相公是，旧日中朝司马。", "遥知宣劝处，东阁华灯，别赐《仙韶》接元夜。", "问天上、几多春，只是人间，但长见、精神如画。", "好都取、山河献君王，看父子貂蝉，玉京迎驾。"]'),
('song-ci-147','洞仙歌','辛弃疾','宋','宋词','song-ci','洞仙歌','[]','飞流万壑，共千岩争秀。',103,'宋词/ci.song.11000.json','["飞流万壑，共千岩争秀。", "孤负平生弄泉手。", "叹轻衫短帽，几许红尘，还自喜，濯发沧浪依旧。", "人生行乐耳，身后虚名，何似生前一杯酒。", "便此地、结吾庐，待学渊明，更手种、门前五柳。", "且归去、父老约重来，问如此青山，定重来否。"]'),
('song-ci-148','八声甘州','辛弃疾','宋','宋词','song-ci','八声甘州','[]','把江山好处付公来，金陵帝王州。',118,'宋词/ci.song.11000.json','["把江山好处付公来，金陵帝王州。", "想今年燕子，依然认得，王谢风流。", "只用平时尊俎，弹压万貔貅。", "依旧钧天梦，玉殿东头。", "看取黄金横带，是明年准拟，丞相封侯。", "有红梅新唱，香阵卷温柔。", "且华堂、通宵一醉，待从今、更数八千秋。", "公知否，邦人香火，夜半才收。"]'),
('song-ci-149','声声慢','辛弃疾','宋','宋词','song-ci','声声慢','[]','开元盛日，天上栽花，月殿桂影重重。',119,'宋词/ci.song.11000.json','["开元盛日，天上栽花，月殿桂影重重。", "十里芬芳，一枝金粟玲珑。", "管弦凝碧池上，记当时、风月愁侬。", "翠华远，但江南草木，烟锁深宫。", "只为天姿冷澹，被西风酝酿，彻骨香浓。", "枉学丹蕉，叶展偷染娇红。", "道人取次装束，是自家、香底家风。", "又怕是，为凄凉、长在醉中。"]'),
('song-ci-150','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','梅梅柳柳斗纤秾。',86,'宋词/ci.song.11000.json','["梅梅柳柳斗纤秾。", "乱山中。", "为谁容。", "试著春衫，依旧怯东风。", "何处踏青人未去，呼女伴，认骄骢。", "儿家门户几重重。", "记相逢。", "画桥东。", "明日重来，风雨暗残红。", "可惜行云春不管，裙带褪，鬓云松。"]'),
('song-ci-151','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','玉箫声远忆骖鸾。',86,'宋词/ci.song.11000.json','["玉箫声远忆骖鸾。", "几悲欢。", "带罗宽。", "且对花前，痛饮莫留残。", "归去小窗明月在，云一缕，玉千竿。", "吴霜应点鬓云斑。", "绮窗闲。", "梦连环。", "说与东风，归意有无间。", "芳草姑苏台下路，和泪看，小屏山。"]'),
('song-ci-152','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','一川松竹任横斜。',86,'宋词/ci.song.11000.json','["一川松竹任横斜。", "有人家。", "被云遮。", "雪后疏梅，时见两三花。", "比□桃源溪上路，风景好，不争多。", "旗亭有酒径须赊。", "晚寒些。", "怎禁他。", "醉里匆匆，归骑自随车。", "白发苍颜吾老矣，只此地，是生涯。"]'),
('song-ci-153','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','剩云残日弄阴晴。',88,'宋词/ci.song.11000.json','["剩云残日弄阴晴。", "晚山明。", "小溪横。", "枝上绵蛮，休作断肠声。", "但是青山山下路，春到处，总堪行。", "当年彩笔赋《芜城》。", "忆平生。", "若为情。", "试取灵槎，归路问君平。", "花底夜深寒色重，须拼却，玉山倾。"]'),
('song-ci-154','六么令','辛弃疾','宋','宋词','song-ci','六么令','[]','酒群花队，攀得短辕折。',114,'宋词/ci.song.11000.json','["酒群花队，攀得短辕折。", "谁怜故山归梦，千里莼羹滑。", "便整松江一棹，点检能言鸭。", "故人欢接。", "醉怀双橘，堕地金圆醒时觉。", "长喜刘郎马上，肯听诗书说。", "谁对叔子风流，直把曹刘压。", "更看君侯事业，不负平生学。", "离觞愁怯。", "送君归后，细写《茶经》煮香雪。"]'),
('song-ci-155','六么令','辛弃疾','宋','宋词','song-ci','六么令','[]','倒冠一笑，华发玉簪折。',113,'宋词/ci.song.11000.json','["倒冠一笑，华发玉簪折。", "阳关自来凄断，却怪歌声滑。", "放浪儿童归舍，莫恼比邻鸭。", "水连山接。", "看君归兴，如醉中醒、梦中觉。", "江上吴侬问我，一一烦君说。", "坐客尊酒频空，剩欠真珠压。", "手把鱼竿未稳，长向沧浪学。", "问愁谁怯。", "可堪杨柳，先作东风满城雪。"]'),
('song-ci-156','满庭芳','辛弃疾','宋','宋词','song-ci','满庭芳','[]','急管哀弦，长歌慢舞，连娟十样宫眉。',117,'宋词/ci.song.11000.json','["急管哀弦，长歌慢舞，连娟十样宫眉。", "不堪红紫，风雨晓来稀。", "惟有杨花飞絮，依旧是、萍满芳池。", "酴醿在，青虬快剪，插遍古铜彝。", "谁将春色去，鸾胶难觅，弦断朱丝。", "恨牡丹多病，也费医治。", "梦里寻春不见，空肠断、怎得春知。", "休惆怅，一觞一咏，须刻右军碑。"]'),
('song-ci-157','满庭芳','辛弃疾','宋','宋词','song-ci','满庭芳','[]','柳外寻春，花边得句，怪公喜气轩眉。',117,'宋词/ci.song.11000.json','["柳外寻春，花边得句，怪公喜气轩眉。", "阳春白雪，清唱古今稀。", "曾是金銮旧客，记凤凰、独绕天池。", "挥毫罢，天颜有喜，催赐上方彝。", "只今江海上，钧天梦觉，清泪如丝。", "算除非，痛把酒疗花治。", "明日五湖佳兴，扁舟去、一笑谁知。", "溪堂好，且拼一醉，倚杖读韩碑。"]'),
('song-ci-158','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','一榻清风殿影凉。',64,'宋词/ci.song.11000.json','["一榻清风殿影凉。", "涓涓流水响回廊。", "千章云木钩輈叫，十里溪风䆉稏香。", "冲急雨，趁斜阳。", "山园细路转微茫。", "倦途却被行人笑，只为林泉有底忙。"]'),
('song-ci-159','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','晚日寒鸦一片愁。',64,'宋词/ci.song.11000.json','["晚日寒鸦一片愁。", "柳塘新绿却温柔。", "若教眼底无离恨，不信人间有白头。", "肠已断，泪难收。", "相思重上小红楼。", "情知已被山遮断，频倚阑干不自由。"]'),
('song-ci-160','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','翠竹千寻上薜萝。',64,'宋词/ci.song.11000.json','["翠竹千寻上薜萝。", "东湖经雨又增波。", "只因买得青山好，却恨归来白发多。", "明画烛，洗金荷。", "主人起舞客齐歌。", "醉中只恨欢娱少，明日醒时奈病何。"]'),
('song-ci-161','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','唱彻《阳关》泪未乾。',66,'宋词/ci.song.11000.json','["唱彻《阳关》泪未乾。", "功名馀事且加餐。", "浮天水送无穷树，带雨云埋一半山。", "今古恨，几千般。", "只应离合是悲欢。", "江头未是风波恶，别有人间行路难。"]'),
('song-ci-162','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','扑面征尘去路遥。',64,'宋词/ci.song.11000.json','["扑面征尘去路遥。", "香篝渐觉水沈销。", "山无重数周遭碧，花不知名分外娇。", "人历历，马萧萧。", "笙旗又过小红桥。", "愁边剩有相思句，摇断吟鞭碧玉梢。"]'),
('song-ci-163','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','枕簟溪堂冷欲秋。',64,'宋词/ci.song.11000.json','["枕簟溪堂冷欲秋。", "断云依水晚来收。", "红莲相倚浑如醉，白鸟无言定自愁。", "书咄咄，且休休。", "一丘一壑也风流。", "不知筋力衰多少，但觉新来懒上楼。"]'),
('song-ci-164','丑奴儿・采桑子','辛弃疾','宋','宋词','song-ci','丑奴儿・采桑子','[]','千峰云起，骤雨一霎时价。',109,'宋词/ci.song.11000.json','["千峰云起，骤雨一霎时价。", "更远树斜阳，风景怎生图画。", "青旗卖酒，山那畔、别有人间，只消山水光中，无事过这一夏。", "午醉醒时，松窗竹户，万千潇洒。", "野鸟飞来，又是一般闲暇。", "却怪白鸥，觑着人、欲下未下。", "旧盟都在，新来莫是，别有说话。"]'),
('song-ci-165','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','衰草残阳三万顷。',70,'宋词/ci.song.11000.json','["衰草残阳三万顷。", "不算飘零，天外孤鸿影。", "几许凄凉须痛饮。", "行人自向江头醒。", "会少离多看两鬓。", "万缕千丝，何况新来病。", "不是离愁难整顿。", "被他引惹其他恨。"]'),
('song-ci-166','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','点检笙歌多酿酒。',70,'宋词/ci.song.11000.json','["点检笙歌多酿酒。", "蝴蝶西园，暖日明花柳。", "醉倒东风眠永昼。", "觉来小院重携手。", "可惜春残风雨又。", "收拾情怀，长把诗僝僽。", "杨柳见人离别后。", "腰肢近日和他瘦。"]'),
('song-ci-167','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','九畹芳菲兰佩好。',70,'宋词/ci.song.11000.json','["九畹芳菲兰佩好。", "空谷无人，自怨蛾眉巧。", "宝瑟泠泠千古调。", "朱丝弦断知音少。", "冉冉年华吾自老。", "水满汀洲，何处寻芳草。", "唤起湘累歌未了。", "石龙舞罢松风晓。"]'),
('song-ci-168','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','小小华年才月半。',70,'宋词/ci.song.11000.json','["小小华年才月半。", "罗幕春风，幸自无人见。", "刚道羞郎低粉面。", "傍人瞥见回娇盼。", "昨夜西池陪女伴。", "柳困花慵，见说归来晚。", "劝客持觞浑未惯。", "未歌先觉花枝颤。"]'),
('song-ci-169','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','少日春怀似酒浓。',73,'宋词/ci.song.11000.json','["少日春怀似酒浓。", "插花走马醉千锺。", "老去逢春如病酒。", "唯有。", "茶瓯香篆小帘栊。", "卷尽残花风未定。", "休恨。", "花开元自要春风。", "试问春归谁得见。", "飞燕。", "来时相遇夕阳中。"]'),
('song-ci-170','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','老去惜花心已懒，爱梅犹绕江村。',70,'宋词/ci.song.11000.json','["老去惜花心已懒，爱梅犹绕江村。", "一枝先破玉溪春。", "更无花态度，全有雪精神。", "剩向空山餐秀色，为渠著句清新。", "竹根流水带溪云。", "醉中浑不记，归路月黄昏。"]'),
('song-ci-171','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','莫向空山吹玉笛，壮怀酒醒心惊。',70,'宋词/ci.song.11000.json','["莫向空山吹玉笛，壮怀酒醒心惊。", "四更霜月太寒生。", "被翻红锦浪，酒满玉壶冰。", "小陆未须临水笑，山林我辈锺情。", "今宵依旧醉中行。", "试寻残菊处，中路侯渊明。"]'),
('song-ci-172','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','锺鼎山林都是梦，人间荣辱休惊。',70,'宋词/ci.song.11000.json','["锺鼎山林都是梦，人间荣辱休惊。", "只消闲处过平生。", "酒杯秋吸露，诗句夜裁冰。", "记取小窗风雨夜，对床灯火多情。", "问谁千里伴君行。", "晚山眉样翠，秋水镜般明。"]'),
('song-ci-173','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','稼轩日向儿童说。',52,'宋词/ci.song.11000.json','["稼轩日向儿童说。", "带湖买得新风月。", "头白早归来。", "种花花已开。", "功名浑是错。", "更莫思量着。", "见说小楼东。", "好山千万重。"]'),
('song-ci-174','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','郁孤台下清江水。',52,'宋词/ci.song.11000.json','["郁孤台下清江水。", "中间多少行人泪。", "西北是长安。", "可怜无数山。", "青山遮不住。", "毕竟江流去。", "江晚正愁予。", "山深闻鹧鸪。"]'),
('song-ci-175','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','无情最是江头柳。',52,'宋词/ci.song.11000.json','["无情最是江头柳。", "长条折尽还依旧。", "木叶下平湖。", "雁来书有无。", "雁无书尚可。", "妙语凭谁和。", "风雨断肠时。", "小山生桂枝。"]'),
('song-ci-176','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','青山欲共高人语。',52,'宋词/ci.song.11000.json','["青山欲共高人语。", "联翩万马来无数。", "烟雨却低回。", "望来终不来。", "人言头上发。", "总向愁中白。", "拍手笑沙鸥。", "一身都是愁。"]'),
('song-ci-177','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','香浮乳酪玻璃碗。',52,'宋词/ci.song.11000.json','["香浮乳酪玻璃碗。", "年年醉里尝新惯。", "何物比春风。", "歌唇一点红。", "江湖清梦断。", "翠笼明光殿。", "万颗写轻匀。", "低头愧野人。"]'),
('song-ci-178','西河','辛弃疾','宋','宋词','song-ci','西河','["\u957f\u6c5f"]','西江水。',126,'宋词/ci.song.11000.json','["西江水。", "道是西风人泪。", "无情却解送行人，月明千里。", "从今日日倚高楼，伤心烟树如荠。", "会君难，别君易。", "草草不如人意。", "十年著破绣衣茸，种成桃李。", "问君可是厌承明，东方鼓吹千骑。", "对梅花、更消一醉。", "有明年、调鼎风味。", "老病自怜憔悴。", "过吾庐、定有幽人相问，岁晚渊明归来未。"]'),
('song-ci-179','木兰花慢','辛弃疾','宋','宋词','song-ci','木兰花慢','[]','汉中开汉业，问此地、是耶非。',122,'宋词/ci.song.11000.json','["汉中开汉业，问此地、是耶非。", "想剑指三秦，君王得意，一战东归。", "追亡事、今不见，但山川满目泪沾衣。", "落日胡尘未断，西风塞马空肥。", "一编书是帝王师。", "小试去征西。", "更草草离筵，匆匆去路，愁满旌旗。", "君思我、回首处，正江涵秋影雁初飞。", "安得车轮四角，不堪带减腰围。"]'),
('song-ci-180','木兰花慢','辛弃疾','宋','宋词','song-ci','木兰花慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','老来情味减，对别酒、怯流年。',124,'宋词/ci.song.11000.json','["老来情味减，对别酒、怯流年。", "况屈指中秋，十分好月，不照人圆。", "无情水、都不管，共西风、只等送归船。", "秋晚莼鲈江上，夜深儿女灯前。", "征衫。", "便好去朝天。", "玉殿正思贤。", "想夜半承明，留教视草，却遣筹边。", "长安故人问我，道寻常、泥酒只依然。", "目断秋霄落雁，醉来时响空弦。"]'),
('song-ci-181','朝中措','辛弃疾','宋','宋词','song-ci','朝中措','[]','绿萍池沼絮飞忙。',57,'宋词/ci.song.11000.json','["绿萍池沼絮飞忙。", "花入蜜脾香。", "长怪春归何处，谁知个里迷藏。", "残云剩雨，些儿意思，直恁思量。", "不是莺声惊觉，梦中啼损红妆。"]'),
('song-ci-182','朝中措','辛弃疾','宋','宋词','song-ci','朝中措','[]','篮舆袅袅破重冈。',57,'宋词/ci.song.11000.json','["篮舆袅袅破重冈。", "玉笛两红妆。", "这里都愁酒尽，那边正和诗忙。", "为谁醉倒，为谁归去，都莫思量。", "白水东边篱落，斜阳欲下牛羊。"]'),
('song-ci-183','祝英台令','辛弃疾','宋','宋词','song-ci','祝英台令','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','宝钗分，桃叶渡。',95,'宋词/ci.song.11000.json','["宝钗分，桃叶渡。", "烟柳暗南浦。", "怕上层楼，十日九风雨。", "断肠片片飞红，都无人管，倩谁唤、流莺声住。", "鬓边觑。", "试把花卜心期，才簪又重数。", "罗帐灯昏，呜咽梦中语。", "是他春带愁来，春归何处。", "却不解、将愁归去。"]'),
('song-ci-184','乌夜啼','辛弃疾','宋','宋词','song-ci','乌夜啼','[]','江头醉倒山公。',45,'宋词/ci.song.11000.json','["江头醉倒山公。", "月明中。", "记得昨宵归路、笑儿童。", "溪欲转。", "山已断。", "两三松。", "一段可怜风月、欠诗翁。"]'),
('song-ci-185','乌夜啼','辛弃疾','宋','宋词','song-ci','乌夜啼','[]','人言我不如公。',45,'宋词/ci.song.11000.json','["人言我不如公。", "酒频中。", "更把平生湖海、问儿童。", "千尺蔓。", "云叶乱。", "系长松。", "却笑一身缠绕、似衰翁。"]'),
('song-ci-186','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','朱颜晕酒，方瞳点漆，闲傍松边倚杖。',68,'宋词/ci.song.11000.json','["朱颜晕酒，方瞳点漆，闲傍松边倚杖。", "不须更展画图看，自是个、寿星模样。", "今朝盛事，一杯深劝，更把新诗齐唱。", "人间八十最风流，长帖在、儿儿额上。"]'),
('song-ci-187','太常引','辛弃疾','宋','宋词','song-ci','太常引','["\u6cf0\u5c71"]','君王著意履声间。',62,'宋词/ci.song.11000.json','["君王著意履声间。", "便令押、紫宸班。", "今代又尊韩。", "道吏部、文章泰山。", "一杯千岁，问公何事，早伴赤松闲。", "功业后来看。", "似江左、风流谢安。"]'),
('song-ci-188','昭君怨','辛弃疾','宋','宋词','song-ci','昭君怨','[]','长记潇湘秋晚。',48,'宋词/ci.song.11000.json','["长记潇湘秋晚。", "歌舞橘洲人散。", "走马月明中。", "折芙蓉。", "今日西山南浦。", "画栋珠帘云雨。", "风景不争多。", "奈愁何。"]'),
('song-ci-189','采桑子','辛弃疾','宋','宋词','song-ci','采桑子','[]','烟迷露麦荒池柳，洗雨烘晴。',52,'宋词/ci.song.11000.json','["烟迷露麦荒池柳，洗雨烘晴。", "洗雨烘晴。", "一样春风几样青。", "提壶脱裤催归去，万恨千情。", "万恨千情。", "各自无聊各自鸣。"]'),
('song-ci-190','杏花天','辛弃疾','宋','宋词','song-ci','杏花天','[]','病来自是於春懒。',65,'宋词/ci.song.11000.json','["病来自是於春懒。", "但别院、笙歌一片。", "蛛丝网遍玻璃盏。", "更问舞裙歌扇。", "有多少、莺愁蝶怨。", "甚梦里、春归不管。", "杨花也笑人情浅。", "故故沾衣扑面。"]'),
('song-ci-191','踏歌','辛弃疾','宋','宋词','song-ci','踏歌','[]','攧厥。',101,'宋词/ci.song.11000.json','["攧厥。", "看精神、压一庞儿劣。", "更言语、一似春莺滑。", "一团儿、美满香和雪。", "去也。", "把春衫、换却同心结。", "向人道、不怕轻离别。", "问昨宵、因甚歌声咽。", "秋被梦，春闺月。", "旧家事、却对何人说。", "告弟弟莫趁蜂和蝶。", "有春归花落时节。"]'),
('song-ci-192','一络索・一落萦','辛弃疾','宋','宋词','song-ci','一络索・一落萦','[]','羞见鉴鸾孤却。',56,'宋词/ci.song.11000.json','["羞见鉴鸾孤却。", "倩人梳掠。", "一春长是为花愁，甚夜夜、东风恶。", "行绕翠帘珠箔。", "锦笺谁托。", "玉觞泪满却停觞，怕酒似、郎情薄。"]'),
('song-ci-193','千秋岁','辛弃疾','宋','宋词','song-ci','千秋岁','[]','塞垣秋草。',87,'宋词/ci.song.11000.json','["塞垣秋草。", "又报平安好。", "尊俎上，英雄表。", "金汤生气象，珠玉霏谭笑。", "春近也，梅花得似人难老。", "莫惜金尊倒。", "凤诏看看到。", "留不住，江东小。", "从容帷幄去，整顿乾坤了。", "千百岁，从今尽是中书考。"]'),
('song-ci-194','感皇恩','辛弃疾','宋','宋词','song-ci','感皇恩','[]','春事到清明，十分花柳。',81,'宋词/ci.song.11000.json','["春事到清明，十分花柳。", "唤得笙歌劝君酒。", "酒如春好，春色年年如旧。", "青春元不老，君知否。", "席上看君，竹清松瘦。", "待与青春斗长久。", "三山路归，明日天香襟袖。", "更持银盏起，为君寿。"]'),
('song-ci-195','青玉案','辛弃疾','宋','宋词','song-ci','青玉案','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','东风夜放花千树。',80,'宋词/ci.song.11000.json','["东风夜放花千树。", "更吹落、星如雨。", "宝马雕车香满路。", "凤箫声动，玉壶光转，一夜鱼龙舞。", "蛾儿雪柳黄金缕。", "笑语盈盈暗香去。", "众里寻他千百度。", "蓦然回首，那人却在，灯火阑珊处。"]'),
('song-ci-196','霜天晓角','辛弃疾','宋','宋词','song-ci','霜天晓角','[]','吴头楚尾。',53,'宋词/ci.song.11000.json','["吴头楚尾。", "一棹人千里。", "休说旧愁新恨，长亭树、今如此。", "宦游吾倦矣。", "玉人留我醉。", "明日万花寒食，得且住、为佳耳。"]'),
('song-ci-197','南乡子','辛弃疾','宋','宋词','song-ci','南乡子','[]','敧枕橹声边。',66,'宋词/ci.song.11000.json','["敧枕橹声边。", "贪听咿哑聒醉眠。", "变作笙歌花底去，依然。", "翠袖盈盈在眼前。", "别后两眉尖。", "欲说还休梦已阑。", "只记埋冤前夜月，相看。", "不管人愁独自圆。"]'),
('song-ci-198','阮郎归','辛弃疾','宋','宋词','song-ci','阮郎归','[]','山前风雨欲黄昏。',58,'宋词/ci.song.11000.json','["山前风雨欲黄昏。", "山头来去雪。", "鹧鸪声里数家村。", "潇湘逢故人。", "挥羽扇，整纶巾。", "少年鞍马尘。", "如今憔悴赋《招魂》。", "儒冠多误身。"]'),
('song-ci-199','南歌子','辛弃疾','宋','宋词','song-ci','南歌子','[]','万万千千恨，前前后后山。',62,'宋词/ci.song.11000.json','["万万千千恨，前前后后山。", "傍人道我轿儿宽。", "不道被他遮得、望伊难。", "今夜江头树，船儿系那边。", "知他热后甚时眠。", "万万不成眠后、有谁扇。"]'),
('song-ci-200','小重山','辛弃疾','宋','宋词','song-ci','小重山','[]','倩得薰风染绿衣。',70,'宋词/ci.song.11000.json','["倩得薰风染绿衣。", "国香收不起，透冰肌。", "略开些子未多时。", "窗儿外，却早被人知。", "越惜越娇痴。", "一枝云鬓上，那人宜。", "莫将他去比荼䕷。", "分明是，他更的些儿。"]'),
('song-ci-201','小重山','辛弃疾','宋','宋词','song-ci','小重山','[]','旋制离歌唱未成。',70,'宋词/ci.song.11000.json','["旋制离歌唱未成。", "阳关先画出，柳边亭。", "中年怀抱管弦声。", "难忘处，风月此时情。", "夜雨共谁听。", "尽教清梦去，两三程。", "商量诗价重连城。", "相如老，汉殿旧知名。"]'),
('song-ci-202','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','千丈悬崖削翠，一川落日熔金。',58,'宋词/ci.song.11000.json','["千丈悬崖削翠，一川落日熔金。", "白鸥来往本无心。", "选甚风波一任。", "别浦鱼肥堪脍，前村酒美重斟。", "千年往事已沈沈。", "闲管兴亡则甚。"]'),
('song-ci-203','减字木兰花','辛弃疾','宋','宋词','song-ci','减字木兰花','[]','盈盈泪眼。',52,'宋词/ci.song.11000.json','["盈盈泪眼。", "往日青楼天样远。", "秋月春花。", "输与寻常姊妹家。", "水村山驿。", "日暮行云无气力。", "锦字偷裁。", "立尽西风雁不来。"]'),
('song-ci-204','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','柳边飞鞚。',54,'宋词/ci.song.11000.json','["柳边飞鞚。", "露湿征衣重。", "宿鹭惊窥沙影动。", "应有鱼虾入梦。", "一川淡月疏星。", "浣沙人影娉婷。", "笑背行人归去，门前稚子啼声。"]'),
('song-ci-205','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','茅檐低小。',54,'宋词/ci.song.11000.json','["茅檐低小。", "溪上青青草。", "醉里蛮音相媚好。", "白发谁家翁媪。", "大儿锄豆溪东。", "中儿正织鸡笼。", "最喜小儿亡赖，溪头卧剥莲蓬。"]'),
('song-ci-206','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','断崖修竹。',54,'宋词/ci.song.11000.json','["断崖修竹。", "竹里藏冰玉。", "路绕清溪三百曲。", "香满黄昏雪屋。", "行人系马疏篱。", "折残犹有高枝。", "留得东风数点，只缘娇懒春迟。"]'),
('song-ci-207','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','绕床饥鼠。',54,'宋词/ci.song.11000.json','["绕床饥鼠。", "蝙蝠翻灯舞。", "屋上松风吹急雨。", "破纸窗间自语。", "平生塞北江南。", "归来华发苍颜。", "布被秋宵梦觉，眼前万里江山。"]'),
('song-ci-208','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','连云松竹。',54,'宋词/ci.song.11000.json','["连云松竹。", "万事从今足。", "拄杖东家分社肉。", "白酒床头初熟。", "西风梨枣山园。", "儿童偷把长竿。", "莫遣旁人惊去，老夫静处闲看。"]'),
('song-ci-209','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','昨宵醉里行，山吐三更月。',48,'宋词/ci.song.11000.json','["昨宵醉里行，山吐三更月。", "不见可怜人，一夜头如雪。", "今宵醉里归，明月关山笛。", "收拾锦囊诗，要寄扬雄宅。"]'),
('song-ci-210','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','谁倾沧海珠，簸弄千明月。',48,'宋词/ci.song.11000.json','["谁倾沧海珠，簸弄千明月。", "唤取酒边来，软语裁春雪。", "人间无凤凰，空费穿云笛。", "醉倒却归来，松菊陶潜宅。"]'),
('song-ci-211','山鬼谣・摸鱼儿','辛弃疾','宋','宋词','song-ci','山鬼谣・摸鱼儿','[]','问何年，此山来此，西风落日无语。',140,'宋词/ci.song.11000.json','["问何年，此山来此，西风落日无语。", "看君似是羲皇上，直作太初名汝。", "溪上路。", "算只有、红尘不到今犹古。", "一杯谁举。", "笑我醉呼君，崔嵬未起，山鸟覆杯去。", "须记取。", "昨夜龙湫风雨。", "门前石浪掀舞。", "四更山鬼吹灯啸，惊倒世间儿女。", "依约处。", "还问我、清游杖屦公良苦。", "神交心许。", "待万里携君，鞭笞鸾凤，诵我远游赋。"]'),
('song-ci-212','声声慢','辛弃疾','宋','宋词','song-ci','声声慢','[]','征埃成阵，行客相逢，都道幻出层楼。',119,'宋词/ci.song.11000.json','["征埃成阵，行客相逢，都道幻出层楼。", "指点檐牙高处，浪拥云浮。", "今年太平万里，罢长淮、千骑临秋。", "凭栏望，有东南佳气，西北神州。", "千里怀嵩人去，应笑我、身在楚尾吴头。", "看取弓刀，陌上车马如流。", "从今赏心乐事，剩安排、酒令诗筹。", "华胥梦，愿年年、人似旧游。"]'),
('song-ci-213','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','直节堂堂，看夹道、冠缨拱立。',115,'宋词/ci.song.11000.json','["直节堂堂，看夹道、冠缨拱立。", "渐翠谷、群仙东下，珮环声急。", "闻道天峰飞堕地，傍湖千丈开青壁。", "是当年、玉斧削方壶，无人识。", "山木润，琅玕湿。", "秋露下，琼珠滴。", "向危亭横跨，玉渊澄碧。", "醉舞且摇鸾凤影，浩歌莫遣鱼龙泣。", "恨此中、风月本吾家，今为客。"]'),
('song-ci-214','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','照影溪梅，怅绝代、幽人独立。',115,'宋词/ci.song.11000.json','["照影溪梅，怅绝代、幽人独立。", "更小驻、雍容千骑，羽觞飞急。", "琴里新声风响珮，笔端醉墨鸦栖壁。", "是使君、文度旧知名，方相识。", "清可漱，泉长滴。", "高欲卧，云还湿。", "快晚风吹赠，满怀空碧。", "宝马嘶归红旆动，团龙试碾铜瓶泣。", "怕他年、重到路应迷，桃源客。"]'),
('song-ci-215','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','可恨东君，把春去春来无迹。',114,'宋词/ci.song.11000.json','["可恨东君，把春去春来无迹。", "便过眼、等闲输了，三分之一。", "昼永暖翻红杏雨，风晴扶起垂杨力。", "更天涯、芳草最关情，烘残日。", "湘浦岸，南塘驿。", "恨不尽，愁如积。", "算年年孤负，对他寒食。", "便恁归来能几许，风流已自非畴昔。", "凭画栏、一线数飞鸿，沈空碧。"]'),
('song-ci-216','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','尘土西风，便无限、凄凉行色。',115,'宋词/ci.song.11000.json','["尘土西风，便无限、凄凉行色。", "还记取、明朝应恨，今宵轻别。", "珠泪争垂华烛暗，雁行中断哀筝切。", "看扁舟、幸自涩清溪，休催发。", "白首路，长亭仄。", "千树柳，千丝结。", "怕行人西去，棹歌声阕。", "黄卷莫教诗酒污，玉阶不信仙凡隔。", "但从今、伴我又随君，佳哉月。"]'),
('song-ci-217','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','天上飞琼，毕竟向、人间情薄。',115,'宋词/ci.song.11000.json','["天上飞琼，毕竟向、人间情薄。", "还又跨、玉龙归去，万花摇落。", "云破林梢添远岫，月临屋角分层阁。", "记少年、骏马走韩庐，掀东郭。", "吟冻雁，嘲饥鹊。", "人已老，欢犹昨。", "对琼瑶满地，与君酬酢。", "最爱霏霏迷远近，却收扰扰还寥廓。", "待羔儿、酒罢又烹茶，扬州鹤。"]'),
('song-ci-218','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','折尽荼䕷，尚留得、一分春色。',115,'宋词/ci.song.11000.json','["折尽荼䕷，尚留得、一分春色。", "还记取、青梅如弹，共伊同摘。", "少日对花昏醉梦，而今醒眼看风月。", "恨牡丹、笑我倚东风，形如雪。", "人渐远，君休说。", "榆荚阵，菖蒲药。", "算不因风雨，只因鶗鴂。", "老冉冉兮花共柳，是栖栖者蜂和蝶。", "也不因、春去有闲愁，因离别。"]'),
('song-ci-219','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','天与文章，看万斛、龙文笔力。',115,'宋词/ci.song.11000.json','["天与文章，看万斛、龙文笔力。", "闻道是、一诗曾赐，千金颜色。", "欲说又休新意思，强啼偷笑真消息。", "算人人、合与共乘鸾，銮坡客。", "倾国艳，难再得。", "还可恨，还勘忆。", "看书寻旧锦，衫裁新碧。", "莺蝶一春花里活，可堪风雨飘红白。", "问谁家、却有燕归梁，香泥湿。"]'),
('song-ci-220','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','绝代佳人，曾一笑、倾城倾国。',115,'宋词/ci.song.11000.json','["绝代佳人，曾一笑、倾城倾国。", "休更叹、旧时清镜，而今华发。", "明日伏波堂上客，老当益壮翁应说。", "恨苦遭、邓禹笑人来，长寂寂。", "诗酒社，江山笔。", "松菊径，云烟屐。", "怕一觞一咏，风流弦绝。", "我梦横江孤鹤去，觉来却与君相别。", "记功名、万里要吾身，佳眠食。"]'),
('song-ci-221','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','敲碎离愁，纱窗外、风摇翠竹。',115,'宋词/ci.song.11000.json','["敲碎离愁，纱窗外、风摇翠竹。", "人去后、吹箫声断，倚楼人独。", "满眼不堪三月暮，举头已觉千山绿。", "但试将、一纸寄来书，从头读。", "相思字，空盈幅。", "相思意，何时足。", "滴罗襟点点，泪珠盈掬。", "芳草不迷行客路，垂杨只碍离人目。", "最苦是、立尽月黄昏，栏干曲。"]'),
('song-ci-222','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','倦客新丰，貂裘敝、征尘满目。',115,'宋词/ci.song.11000.json','["倦客新丰，貂裘敝、征尘满目。", "弹短铗、青蛇三尺，浩歌谁续。", "不念英雄江左老，用之可以尊中国。", "叹诗书、万卷致君人，番沈陆。", "休感叹，年华促。", "人易老，欢难足。", "有玉人怜我，为簪黄菊。", "且置请缨封万户，竟须卖剑酬黄犊。", "叹当年、寂寞贾长沙，伤时哭。"]'),
('song-ci-223','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','家住江南，又过了、清明寒食。',115,'宋词/ci.song.11000.json','["家住江南，又过了、清明寒食。", "花径里、一番风雨，一番狼藉。", "流水暗随红粉去，园林渐觉清阴密。", "算年年、落尽刺桐花，寒无力。", "庭院静，空相忆。", "无说处，闲愁极。", "怕流莺乳燕，得知消息。", "尺素如今何处也，彩云依旧无踪迹。", "谩教人、羞去上层楼，平芜碧。"]'),
('song-ci-224','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','把酒长亭说。',142,'宋词/ci.song.11000.json','["把酒长亭说。", "看渊明、风流酷似，卧龙诸葛。", "何处飞来林间鹊，蹙踏松梢微雪。", "要破帽、多添华发。", "剩水残山无态度，被疏梅、料理成风月。", "两三雁，也萧瑟。", "佳人重约还轻别。", "怅清江、天寒不渡，水深冰合。", "路断车轮生四角，此地行人销骨。", "问谁使、君来愁绝。", "铸就而今相思错，料当初、费尽人间铁。", "长夜笛，莫吹裂。"]'),
('song-ci-225','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','老大犹堪说。',142,'宋词/ci.song.11000.json','["老大犹堪说。", "似而今、元龙臭味，孟公瓜葛。", "我病君来高歌饮，惊散楼头飞雪。", "笑富贵、千钧如发。", "硬语盘空谁来听，记当时、只有西窗月。", "重进酒，唤呜瑟。", "事无两样人心别。", "问渠侬、神州毕竟，几番离合。", "汗血盐车无人顾，千里空收骏骨。", "正目断、关河路绝。", "我最怜君中宵舞，道男儿、到死心如铁。", "看试手，补天裂。"]'),
('song-ci-226','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','["\u6d1e\u5ead\u6e56"]','细把君诗说。',142,'宋词/ci.song.11000.json','["细把君诗说。", "怅馀音、钧天浩荡，洞庭胶葛。", "千尺阴崖尘不到，惟有层冰积雪。", "乍一见、寒生毛发。", "自昔佳人多薄命，对古来、一片伤心月。", "金屋冷，夜调瑟。", "去天尺五君家别。", "看乘空、鱼龙惨淡，风云开合。", "起望衣冠神州路，白日消残战骨。", "叹夷甫、诸人清绝。", "夜半狂歌悲风起，听铮铮、阵马檐间铁。", "南共北，正分裂。"]'),
('song-ci-227','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','凤尾龙香拨。',141,'宋词/ci.song.11000.json','["凤尾龙香拨。", "自开元、霓裳曲罢，几番风月。", "最苦浔阳江头客，画舸亭亭待发。", "记出塞、黄云堆雪。", "马上离愁三万里，望昭阳、宫殿孤鸿没。", "弦解语，恨难说。", "辽阳驿使音尘绝。", "琐窗寒、轻拢慢拈，泪珠盈睫。", "推手含情还却手，一抹梁州哀彻。", "千古事、云飞烟灭。", "贺老定场无消息，想沈香亭北繁华歇。", "弹到此，为呜咽。"]'),
('song-ci-228','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','柳暗清波路。',144,'宋词/ci.song.11000.json','["柳暗清波路。", "送春归、猛风暴雨，一番新绿。", "千里潇湘葡萄涨，人解扁舟欲去。", "又樯燕、留人相语。", "艇子飞来生尘步，唾花寒、唱我新番句。", "波似箭，催鸣橹。", "黄陵祠下山无数。", "听湘娥、泠泠曲罢，为谁情苦。", "行到东吴春已暮，正江阔、潮平稳渡。", "望金雀、觚棱翔舞。", "前度刘郎今重到，问玄都、千树花存否。", "愁为倩，么弦诉。"]'),
('song-ci-229','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','寄我五云字，恰向酒边来。',114,'宋词/ci.song.11000.json','["寄我五云字，恰向酒边来。", "东风过尽归雁，不见客星回。", "闻道琐窗风月，更著诗翁杖屦，合作雪堂猜。", "岁旱莫留客，霖雨要渠来。", "短檠灯，长剑铗，欲生苔。", "雕弓挂壁无用，照影落清杯。", "多病关心药裹，小摘亲锄菜甲，老子正须哀。", "夜雨北窗竹，更倩野人栽。"]'),
('song-ci-230','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','酒罢且勿起，重挽史君须。',114,'宋词/ci.song.11000.json','["酒罢且勿起，重挽史君须。", "一身都是和气，别去意何如。", "我辈情锺休问，父老田头说尹，泪落独怜渠。", "秋水见毛发，千尺定无鱼。", "望清阙，左黄阁，右紫枢。", "东风桃李陌上，下马拜除书。", "屈指吾生馀几，多病故人痛饮，此事正愁馀。", "江湖有归雁，能寄草堂无。"]'),
('song-ci-231','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','我饮不须劝，正怕酒尊空。',114,'宋词/ci.song.11000.json','["我饮不须劝，正怕酒尊空。", "别离亦复何恨，此别恨匆匆。", "头上貂蝉贵客，花外麒麟高冢，人世竟谁雄。", "一笑出门去，千里落花风。", "孙刘辈，能使我，不为公。", "余发种种如是，此事付渠侬。", "但觉平生湖海，除了醉吟风月，此外百无功。", "毫发皆帝力，更乞鉴湖东。"]'),
('song-ci-232','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','寒食不小住，千骑拥春衫。',114,'宋词/ci.song.11000.json','["寒食不小住，千骑拥春衫。", "衡阳石鼓城下，记我旧停骖。", "襟似潇湘桂岭，带似洞庭春草，紫盖屹东南。", "文字起骚雅，刀剑化耕蚕。", "看使君，於此事，定不凡。", "奋髯抵几堂上，尊俎自高谈。", "莫信君门万里，但使民歌五裤，归诏凤凰衔。", "君去我谁饮，明月影成三。"]'),
('song-ci-233','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','头白齿牙缺，君勿笑衰翁。',114,'宋词/ci.song.11000.json','["头白齿牙缺，君勿笑衰翁。", "无穷天地今古，人在四之中。", "臭腐神奇俱尽，贵贱贤愚等耳，造物也儿童。", "老佛更堪笑，谈妙说虚空。", "坐堆豗，行荅飒，立龙锺。", "有时三盏两盏，淡酒醉蒙鸿。", "四十九年前事，一百八盘狭路，拄杖倚墙东。", "老境何所似，只与少年同。"]'),
('song-ci-234','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','上界足官府，公是地行仙。',114,'宋词/ci.song.11000.json','["上界足官府，公是地行仙。", "青毡剑履旧物，玉立侍天颜。", "莫怪新来白发，恐是当年柱下，道德五千言。", "南涧旧活计，猿鹤且相安。", "歌秦缶，宝康瓠，世皆然。", "不知清庙钟磬，零落有谁编。", "堪笑行藏用舍，试问山林钟鼎，底事有亏全。", "再拜荷公赐，双鹤一千年。"]'),
('song-ci-235','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','少年握槊，气凭陵、酒圣诗豪馀事。',120,'宋词/ci.song.11000.json','["少年握槊，气凭陵、酒圣诗豪馀事。", "缩手旁观初未识，两两三三而已。", "变化须臾，鸥飞石镜，鹊抵星桥□。", "捣残秋练，玉砧犹想纤指。", "堪笑千古争心，等闲一胜，拼了光阴费。", "老子忘机浑谩与，鸿鹄飞来天际。", "武媚宫中，韦娘局上，休把兴亡记。", "布衣百万，看君一笑沈醉。"]'),
('song-ci-236','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','倘来轩冕，问还是、今古人间何物。',120,'宋词/ci.song.11000.json','["倘来轩冕，问还是、今古人间何物。", "旧日重城愁万里，风月而今坚壁。", "药笼功名，酒垆身世，可惜蒙头雪。", "浩歌一曲，坐中人物之杰。", "堪叹黄菊凋零，孤标应也有，梅花争发。", "醉里重揩西望眼，惟有孤鸿明减。", "世事从教，浮云来去，枉了冲冠发。", "故人何在，长歌应伴残月。"]'),
('song-ci-237','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','道人元是，道家风、来作烟霞中物。',120,'宋词/ci.song.11000.json','["道人元是，道家风、来作烟霞中物。", "翠幰裁犀遮不定，红透玲珑油壁。", "借得春工，惹将秋露，薰做江梅雪。", "我评花谱，便应推此为杰。", "憔悴何处芳枝，十郎手种，看明年花发。", "坐对虚空香色界，不怕西风起灭。", "别驾风流，多情更要，簪满姮娥发。", "等闲折尽，玉斧重倩修月。"]'),
('song-ci-238','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','江南尽处，堕玉京仙子，绝尘英秀。',122,'宋词/ci.song.11000.json','["江南尽处，堕玉京仙子，绝尘英秀。", "彩笔风流，偏解写、姑射冰姿清瘦。", "笑杀春工，细窥天巧，妙绝应难有。", "丹青图画，一时都愧凡陋。", "还似篱落孤山，嫩寒清晓，祗欠香沾袖。", "淡伫轻盈，谁付与、弄粉调朱纤手。", "疑是花神，朅来人世，占得佳名久。", "松篁佳韵，倩君添做三友。"]'),
('song-ci-239','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','疏疏淡淡，问阿谁、堪比天真颜色。',120,'宋词/ci.song.11000.json','["疏疏淡淡，问阿谁、堪比天真颜色。", "笑杀东君虚占断，多少朱朱白白。", "雪里温柔，水边明秀，不惜春工力。", "骨清香嫩，迥然天与奇绝。", "尝记宝篽寒轻，琐窗人睡起，玉纤轻摘。", "漂泊天涯空瘦损，犹有当年标格。", "万里风烟，一溪霜月，未怕欺他得。", "不如归去，阆苑有个人忆。"]'),
('song-ci-240','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','断崖千丈孤松，挂冠更在松高处。',127,'宋词/ci.song.11000.json','["断崖千丈孤松，挂冠更在松高处。", "平生袖手，故应休矣，功名良苦。", "笑指儿曹，人间醉梦，莫嗔惊汝。", "问黄金馀几，旁人欲说，田园计、君推去。", "叹息芗林旧隐，对先生、竹窗松户。", "一花一草，一觞一咏，风流杖屦。", "野马尘埃，扶摇下视，苍然如许。", "恨当年、九老图中，忘却画、盘园路。"]'),
('song-ci-241','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','倚栏看碧成朱，等闲褪了香袍粉。',126,'宋词/ci.song.11000.json','["倚栏看碧成朱，等闲褪了香袍粉。", "上林高选，匆匆又换，紫云衣润。", "几许春风，朝薰暮染，为花忙损。", "笑旧家桃李，东涂西抹，有多少、凄凉恨。", "拟倩流莺说与，记容华、易消难整。", "人间得意，千红百紫，转头春尽。", "白发怜君，儒冠曾误，平生官冷。", "算风流未减，年年醉里，把花枝问。"]'),
('song-ci-242','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','["\u6d1e\u5ead\u6e56"]','补陀大士虚空，翠岩谁记飞来处。',126,'宋词/ci.song.11000.json','["补陀大士虚空，翠岩谁记飞来处。", "蜂房万点，似穿如碍，玲珑窗户。", "石髓千年，已垂未落，嶙峋冰柱。", "有怒涛声远，落花香在，人疑是、桃源路。", "又说春雷鼻息，是卧龙、弯环如许。", "不然应是，洞庭张乐，湘灵来去。", "我意长松，倒生阴壑，细吟风雨。", "竟茫茫未晓。", "只应白发，是开山祖。"]'),
('song-ci-243','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','稼轩何必长贫，放泉檐外琼珠泻。',126,'宋词/ci.song.11000.json','["稼轩何必长贫，放泉檐外琼珠泻。", "乐天知命，古来谁会，行藏用舍。", "人不堪忧，一瓢自乐，贤哉回也。", "料当年曾问，饭蔬饮水，何为是、栖栖者。", "且对浮云山上，莫匆匆、去流山下。", "苍颜照影，故应流落，轻裘肥马。", "绕齿冰霜，满怀芳乳，先生饮罢。", "笑挂瓢风树，一鸣渠碎，问何如哑。"]'),
('song-ci-244','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','听兮清珮琼瑶些。',126,'宋词/ci.song.11000.json','["听兮清珮琼瑶些。", "明兮镜秋毫些。", "君无去此，流昏涨腻，生蓬蒿些。", "虎豹甘人，渴而饮汝，宁猿猱些。", "大而流江海，覆舟如芥，君无助、狂涛些。", "路险兮、山高些。", "愧余独处无聊些。", "冬槽春盎，归来为我，制松醪些。", "其外芳芬，团龙片凤，煮云膏些。", "古人兮既往，嗟余之乐，乐箪瓢些。"]'),
('song-ci-245','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','相思苦，君与我同心。',102,'宋词/ci.song.11000.json','["相思苦，君与我同心。", "鱼没雁沈沈。", "是梦他松后追轩冕，是化为鹤后去山林。", "对西风，直怅望，到如今。", "待不饮、奈何君有恨。", "待痛饮、奈何吾有病。", "君起舞，试重斟。", "苍梧云外湘妃泪，鼻亭山下鹧鸪吟。", "早归来，流水外，有知音。"]'),
('song-ci-246','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','吾衰矣，须富贵何时。',100,'宋词/ci.song.11000.json','["吾衰矣，须富贵何时。", "富贵是危机。", "暂忘设醴抽身去，未曾得米弃官归。", "穆先生，陶县令，是吾师。", "待葺个、园儿名佚老。", "更作个、亭儿名亦好。", "闲饮酒，醉吟诗。", "千年田换八百主，一人口插几张匙。", "休休休，更说甚，是和非。"]'),
('song-ci-247','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','花好处，不趁绿衣郎。',100,'宋词/ci.song.11000.json','["花好处，不趁绿衣郎。", "缟袂立斜阳。", "面皮儿上因谁白，骨头儿里几多香。", "尽饶他，心似铁，也须忙。", "甚唤得、雪来白倒雪。", "更唤得，月来香杀月。", "谁立马，更窥墙。", "将军止渴山南畔，相公调鼎殿东厢。", "忒高才，经济地，战争场。"]'),
('song-ci-248','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','金闺老，眉寿正如川。',100,'宋词/ci.song.11000.json','["金闺老，眉寿正如川。", "七十且华筵。", "乐天诗句香山里，杜陵酒债曲江边。", "问何如，歌窈窕，舞婵娟。", "更十岁、太公方出将。", "又十岁、武公才入相。", "留盛事，看明年。", "直须腰下添金印，莫教头上欠貂蝉。", "向人间，长富贵，地行仙。"]'),
('song-ci-249','瑞鹤仙','辛弃疾','宋','宋词','song-ci','瑞鹤仙','[]','黄金堆到斗。',127,'宋词/ci.song.11000.json','["黄金堆到斗。", "怎得似、长年画堂劝酒。", "蛾眉最明秀。", "向水沈烟里，两行红袖。", "笙歌撋就。", "争说道、明年时候。", "被姮娥、做了殷勤，仙桂一枝入手。", "知否。", "风流别驾，近日人呼，文章太守。", "天长地久。", "岁岁上、乃翁寿。", "记从来人道，相门出相，金印累累尽有。", "但直须，周公拜前，鲁公拜后。"]'),
('song-ci-250','汉宫春','辛弃疾','宋','宋词','song-ci','汉宫春','[]','行李溪头，有钓车茶具，曲几团蒲。',118,'宋词/ci.song.11000.json','["行李溪头，有钓车茶具，曲几团蒲。", "儿童认得，前度过者篮舆。", "时时照影，甚此身、遍满江湖。", "怅野老，行歌不住，定堪与语难呼。", "一自东篱摇落，问渊明岁晚，心赏何如。", "梅花正自不恶，曾有诗无。", "知翁止酒，待重教、莲社人沽。", "空怅望，风流已矣，江山特地愁予。"]'),
('song-ci-251','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','有酒忘杯，有笔忘诗，弄溪奈何。',139,'宋词/ci.song.11000.json','["有酒忘杯，有笔忘诗，弄溪奈何。", "看纵横斗转，龙蛇起陆，崩腾决去，雪练倾河。", "袅袅东风，悠悠倒景，摇动云山水又波。", "还知否，欠菖蒲攒港，绿竹缘坡。", "长松谁剪嵯峨。", "笑野老来耘山上禾。", "算只因鱼鸟，天然自乐，非关风月，闲处偏多。", "芳草春深，佳人日暮，濯发沧浪独浩歌。", "徘徊久，问人间谁似，老子婆娑。"]'),
('song-ci-252','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','一水西来，千丈晴虹，十里翠屏。',139,'宋词/ci.song.11000.json','["一水西来，千丈晴虹，十里翠屏。", "喜草堂经岁，重来社老，斜川好景，不负渊明。", "老鹤高飞，一枝投宿，长笑蜗牛戴屋行。", "平章了，待十分佳处，著个茅亭。", "青山意气峥嵘。", "似为我归来妩媚生。", "解频教花鸟，前歌后舞，更催云水，暮送朝迎。", "酒圣诗豪，可能无势，我乃而今驾驭卿。", "清溪上，被山灵却笑，白发归耕。"]'),
('song-ci-253','归朝欢','辛弃疾','宋','宋词','song-ci','归朝欢','[]','我笑共工缘底怒。',122,'宋词/ci.song.11000.json','["我笑共工缘底怒。", "触断峨峨天一柱。", "补天又笑女娲忙，却将此石投闲处。", "野烟荒草路。", "先生柱杖来看汝。", "倚苍苔，摩挲试问，千古几风雨。", "长被儿童敲火苦。", "时有牛羊磨角去。", "霍然千丈翠岩屏，锵然一滴甘泉乳。", "结亭三四五。", "会相暖热携歌舞。", "细思量，古来寒士，不遇有时遇。"]'),
('song-ci-254','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','举头西北浮云，倚天万里须长剑。',126,'宋词/ci.song.11000.json','["举头西北浮云，倚天万里须长剑。", "人言此地，夜深长见，斗牛光焰。", "我觉山高，潭空水冷，月明星淡。", "待燃犀下看，凭栏却怕，风雷怒，鱼龙惨。", "峡束□江对起，过危楼、欲飞还敛。", "元龙老矣，不妨高卧，冰壶凉簟。", "千古兴亡，百年悲笑，一时登览。", "问何人又卸，片帆沙岸，系斜阳缆。"]'),
('song-ci-255','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','只愁风雨重阳，思君不见令人老。',126,'宋词/ci.song.11000.json','["只愁风雨重阳，思君不见令人老。", "行期定否，征车几两，去程多少。", "有客书来，长安却早，传闻追诏。", "问归来何日，君家旧事，直须待、为霖了。", "从此兰生蕙长，吾谁与、玩兹芳草。", "自怜拙者，功名相避，去如飞鸟。", "只有良朋，东阡西陌，安排似巧。", "到如今巧处，依前又拙，把平生笑。"]'),
('song-ci-256','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','百郡怯登车，千里输流马。',52,'宋词/ci.song.11000.json','["百郡怯登车，千里输流马。", "乞得胶胶扰扰身，却笑区区者。", "野水玉鸣渠，急雨珠跳瓦。", "一榻清风方是闲，真得归来也。"]'),
('song-ci-257','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','梨花著雨晚来晴。',86,'宋词/ci.song.11000.json','["梨花著雨晚来晴。", "月胧明。", "泪纵横。", "绣阁香浓，深锁凤箫声。", "未必人知春意思，还独自，绕花行。", "酒兵昨夜压愁城。", "太狂生。", "转关情。", "写尽胸中，磈磊未全平。", "却与平章珠玉价，看醉里，锦囊倾。"]'),
('song-ci-258','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','宝钗飞凤鬓惊鸾。',86,'宋词/ci.song.11000.json','["宝钗飞凤鬓惊鸾。", "望重欢。", "水云宽。", "肠断新来，翠被□香残。", "待得来时春尽也，梅著子，笋成竿。", "湘筠帘卷泪痕斑。", "珮声闲。", "玉垂环。", "个里温柔，容我老其间。", "却笑将军三羽箭，何日去，定天山。"]'),
('song-ci-259','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','著意寻春懒便回。',64,'宋词/ci.song.11000.json','["著意寻春懒便回。", "何如信步两三杯。", "山才好处行还倦，诗未成时雨早催。", "携竹杖，更芒鞋。", "朱朱粉粉野蒿开。", "谁家寒食归宁女，笑语柔桑陌上来。"]'),
('song-ci-260','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','水底明霞十顷光。',64,'宋词/ci.song.11000.json','["水底明霞十顷光。", "天教铺锦衬鸳鸯。", "最怜杨柳如张绪，却笑莲花似六郎。", "方竹簟，小胡床。", "晚风消得许多凉。", "背人白鸟都飞去，落日残□更断肠。"]'),
('song-ci-261','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','漠漠轻□拨不开。',64,'宋词/ci.song.11000.json','["漠漠轻□拨不开。", "江南细雨熟黄梅。", "有情无意东边日，已怒重惊忽地雷。", "云柱础，水楼台。", "罗衣费尽博山灰。", "当时一识和羹味，便道为霖消息来。"]'),
('song-ci-262','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','有甚闲愁可皱眉。',64,'宋词/ci.song.11000.json','["有甚闲愁可皱眉。", "老怀无绪自伤悲。", "百年旋逐花阴转，万事长看鬓发知。", "溪上枕，竹间棋。", "怕寻酒伴懒吟诗。", "十分筋力夸强健，只比年时病起时。"]'),
('song-ci-263','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','山上飞泉万斛珠。',64,'宋词/ci.song.11000.json','["山上飞泉万斛珠。", "悬崖千丈落鼪鼯。", "已通樵迳行还碍，似有人声听却无。", "闲略彴，远浮屠。", "溪南修竹有茅庐。", "莫嫌杖屦频来往，此地偏宜著老夫。"]'),
('song-ci-264','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','莫避春阴上马迟。',64,'宋词/ci.song.11000.json','["莫避春阴上马迟。", "春来未有不阴时。", "人情展转闲中看，客路崎岖倦后知。", "梅似雪，柳如丝。", "试听别语慰相思。", "短篷炊饭鲈鱼熟，除却松江枉费诗。"]'),
('song-ci-265','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','白苎新袍入嫩凉。',64,'宋词/ci.song.11000.json','["白苎新袍入嫩凉。", "春蚕食叶响回廊。", "禹门已准桃花浪，月殿先收桂子香。", "鹏北海，凤朝阳。", "又携书剑路茫茫。", "明年此日青云去，却笑人间举子忙。"]'),
('song-ci-266','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','莫上扁舟向剡溪。',64,'宋词/ci.song.11000.json','["莫上扁舟向剡溪。", "浅斟低唱正相宜。", "从□犬吠千家白，且与梅成一段奇。", "香暖处，酒醒时。", "画檐玉箸已偷垂。", "笑君解释春风恨，倩拂蛮笺只费诗。"]'),
('song-ci-267','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','千丈阴崖百丈溪。',68,'宋词/ci.song.11000.json','["千丈阴崖百丈溪。", "孤桐枝上凤偏宜。", "玉音落落虽难合，横理庚庚定自奇。", "人散后，月明诗。", "试弹《幽愤》泪空垂。", "不如却付骚人手，留和《南风》解愠诗。"]'),
('song-ci-268','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','陌上柔条初破芽。',64,'宋词/ci.song.11000.json','["陌上柔条初破芽。", "东邻蚕种已生些。", "平冈细草鸣黄犊，斜日寒林点暮鸦。", "山远近，路横斜。", "青旗沽酒有人家。", "城中桃李愁风雨，春在溪头野荠花。"]'),
('song-ci-269','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','春日平原荠菜花。',64,'宋词/ci.song.11000.json','["春日平原荠菜花。", "新耕雨后落群鸦。", "多情白发春无奈，晚日青□酒易赊。", "闲意态，细生涯。", "牛□西畔有桑麻。", "青裙缟袂谁家女，去趁蚕生看外家。"]'),
('song-ci-270','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','千丈清溪百步雷。',64,'宋词/ci.song.11000.json','["千丈清溪百步雷。", "柴门都向水边开。", "乱云剩带炊烟去，野水闲将日影来。", "穿窈窕，历崔嵬。", "东林试问几时栽。", "动摇意态虽多竹，点缀风流却少梅。"]'),
('song-ci-271','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','敧枕婆娑两鬓霜。',64,'宋词/ci.song.11000.json','["敧枕婆娑两鬓霜。", "起听檐溜碎喧江。", "那边玉箸销啼粉，这里车轮转别肠。", "诗酒社，水边乡。", "可堪醉墨几淋浪。", "画图恰似归家梦，千里河山寸许长。"]'),
('song-ci-272','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','明月别枝惊鹊，清风半夜鸣蝉。',58,'宋词/ci.song.11000.json','["明月别枝惊鹊，清风半夜鸣蝉。", "稻花香里说丰年。", "听取蛙声一片。", "七八个星天外，两三点雨山前。", "旧时茅店社林边。", "路转溪桥忽见。"]'),
('song-ci-273','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','淡黄弓样鞋儿小。',52,'宋词/ci.song.11000.json','["淡黄弓样鞋儿小。", "腰肢只怕风吹倒。", "蓦地管弦催。", "一团红雪飞。", "曲终娇欲诉。", "定忆梨园谱。", "指日按新声。", "主人朝玉京。"]'),
('song-ci-274','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','锦书谁寄相思语。',52,'宋词/ci.song.11000.json','["锦书谁寄相思语。", "天边数遍飞鸿数。", "一夜梦千回。", "梅花入梦来。", "涨痕纷树发。", "霜落沙洲白。", "心事莫惊鸥。", "人间千万愁。"]'),
('song-ci-275','菩萨蛮','辛弃疾','宋','宋词','song-ci','菩萨蛮','[]','阮琴斜挂香罗绶。',52,'宋词/ci.song.11000.json','["阮琴斜挂香罗绶。", "玉纤初试琵琶手。", "桐叶雨声乾。", "真珠落玉盘。", "朱弦调未惯。", "笑倩春风伴。", "莫作别离声。", "且听双凤鸣。"]'),
('song-ci-276','朝中措','辛弃疾','宋','宋词','song-ci','朝中措','[]','年年金蕊艳西风。',56,'宋词/ci.song.11000.json','["年年金蕊艳西风。", "人与菊花同。", "霜鬓经春重绿，仙姿不饮长红。", "焚香度日尽从容。", "笑语调儿童。", "一岁一杯为寿，从今更数千锺。"]'),
('song-ci-277','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','小窗风雨，从今便忆，中夜笑谈清软。',68,'宋词/ci.song.11000.json','["小窗风雨，从今便忆，中夜笑谈清软。", "啼鸦衰柳自无聊，更管得、离人肠断。", "诗书事业，青毡犹在，头上貂蝉会见。", "莫贪风月卧江湖，道日近、长安路远。"]'),
('song-ci-278','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','松冈避暑。',68,'宋词/ci.song.11000.json','["松冈避暑。", "茅檐避雨。", "闲去闲来几度。", "醉扶孤石看飞泉，又却是、前回醒处。", "东家取妇。", "西家归女。", "灯火门前笑语。", "酿成千顷稻花香，夜夜费、一天风露。"]'),
('song-ci-279','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','风雨催春寒食近，平原一片丹青。',70,'宋词/ci.song.11000.json','["风雨催春寒食近，平原一片丹青。", "溪边唤渡柳边行。", "花飞蝴蝶乱，桑嫩野蚕生。", "绿野先生闲袖手，却寻诗酒功名。", "未知明日定阴晴。", "今宵成独醉，却笑众人醒。"]'),
('song-ci-280','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','住世都无菩萨行，仙家风骨精神。',70,'宋词/ci.song.11000.json','["住世都无菩萨行，仙家风骨精神。", "寿如山岳福如云。", "金花汤沐诰，竹马绮罗群。", "更愿升平添喜事，大家祷祝殷勤。", "明年此地庆佳辰。", "一杯千岁酒，重拜太夫人。"]'),
('song-ci-281','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','山路风来草木香。',75,'宋词/ci.song.11000.json','["山路风来草木香。", "雨馀凉意到胡床。", "泉石膏肓吾已甚。", "多病。", "堤防风月费篇章。", "孤负寻常山简醉。", "独自。", "故应知子草《玄》忙。", "湖海早知身汗漫。", "谁伴。", "只甘松竹共凄凉。"]'),
('song-ci-282','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','听我尊前醉后歌。',73,'宋词/ci.song.11000.json','["听我尊前醉后歌。", "人生亡奈别离何。", "但使情亲千里近。", "须信。", "无情对面是山河。", "寄语石头城下水。", "居士。", "而今浑不怕风波。", "借使未如鸥鸟惯。", "相伴。", "也应学得老渔蓑。"]'),
('song-ci-283','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','仄月高寒水石乡。',73,'宋词/ci.song.11000.json','["仄月高寒水石乡。", "倚空青碧对禅床。", "白发自怜心似铁。", "风月。", "使君子细与平章。", "已判生涯筇竹杖。", "来往。", "却惭沙鸟笑人忙。", "便好剩留黄绢句。", "谁赋。", "银钩小草晚天凉。"]'),
('song-ci-284','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','昨夜山公倒载归。',73,'宋词/ci.song.11000.json','["昨夜山公倒载归。", "儿童应笑醉如泥。", "试与扶头浑未醒。", "休问。", "梦魂犹在葛家溪。", "千古醉乡来往路。", "知处。", "温柔东畔白云西。", "起向绿窗高处看。", "题遍。", "刘伶元自有贤妻。"]'),
('song-ci-285','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','春到蓬壶特地晴。',73,'宋词/ci.song.11000.json','["春到蓬壶特地晴。", "神仙队里相公行。", "翠玉相挨呼小字。", "须记。", "笑簪花底是飞琼。", "总是倾城来一处。", "谁妒。", "谁携歌舞到园亭。", "柳妒腰肢花妒艳。", "听看。", "流莺直是妒歌声。"]'),
('song-ci-286','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','百紫千红过了春。',73,'宋词/ci.song.11000.json','["百紫千红过了春。", "杜鹃声苦不堪闻。", "却解啼教春小住。", "风雨。", "空山招得海棠魂。", "一似蜀宫当日女。", "无数。", "猩猩血染赭罗巾。", "毕竟花开谁作主。", "记取。", "大都花属惜花人。"]'),
('song-ci-287','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','侬是嶔崎可笑人。',48,'宋词/ci.song.11000.json','["侬是嶔崎可笑人。", "不妨开口笑时频。", "有人一笑坐生春。", "歌欲颦时还浅笑，醉逢笑处却轻颦。", "宜颦宜笑越精神。"]'),
('song-ci-288','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','梅子熟时到几回。',48,'宋词/ci.song.11000.json','["梅子熟时到几回。", "桃花开后不须猜。", "重来松竹意徘徊。", "惯听禽声浑可谱，饱观鱼阵已能排。", "晚云挟雨唤归来。"]'),
('song-ci-289','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','百世孤芳肯自媒。',48,'宋词/ci.song.11000.json','["百世孤芳肯自媒。", "直须诗句与推排。", "不然唤近酒边来。", "自有渊明方有菊，若无和靖即无梅。", "只今何处向人开。"]'),
('song-ci-290','浣溪沙','辛弃疾','宋','宋词','song-ci','浣溪沙','[]','未到山前骑马回。',48,'宋词/ci.song.11000.json','["未到山前骑马回。", "风吹雨打已无梅。", "共谁消遣两三杯。", "一似旧时春意思，百无是处老形骸。", "也曾头上带花来。"]'),
('song-ci-291','杏花天','辛弃疾','宋','宋词','song-ci','杏花天','[]','牡丹比得谁颜色。',64,'宋词/ci.song.11000.json','["牡丹比得谁颜色。", "似宫中、太真第一。", "渔阳鼙鼓边风急。", "人在沈香亭北。", "买栽池馆多何益。", "莫虚把、千金抛掷。", "若教解语倾人国。", "一个西施也得。"]'),
('song-ci-292','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','风流标格，惺松言语，真个十分奇绝。',68,'宋词/ci.song.11000.json','["风流标格，惺松言语，真个十分奇绝。", "三分兰菊十分梅，斗合就、一枝风月。", "笙簧未语，星河易转，凉夜厌厌留客。", "只愁酒尽各西东，更把酒、推辞一霎。"]'),
('song-ci-293','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','八旬庆会，人间盛事，齐劝一杯春酿。',68,'宋词/ci.song.11000.json','["八旬庆会，人间盛事，齐劝一杯春酿。", "胭脂小字点眉间，犹记得、旧时宫样。", "彩衣更著，功名富贵，直过太公以上。", "大家著意记新词，遇著个、十字便唱。"]'),
('song-ci-294','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','豸冠风采，绣衣声价，曾把经纶少试。',68,'宋词/ci.song.11000.json','["豸冠风采，绣衣声价，曾把经纶少试。", "看看有诏日边来，便入侍、明光殿里。", "东君未老，花明柳媚，且引玉尘沈醉。", "好将三万六千场，自今日、从头数起。"]'),
('song-ci-295','鹊桥仙','辛弃疾','宋','宋词','song-ci','鹊桥仙','[]','轿儿排了，担儿装了，杜宇一声催起。',68,'宋词/ci.song.11000.json','["轿儿排了，担儿装了，杜宇一声催起。", "从今一步一回头，怎睚得、一千馀里。", "旧时行处，旧时歌处，空有燕泥香坠。", "莫嫌白发不思量，也须有、思量去里。"]'),
('song-ci-296','虞美人','辛弃疾','宋','宋词','song-ci','虞美人','[]','一杯莫落吾人后。',68,'宋词/ci.song.11000.json','["一杯莫落吾人后。", "富贵功名寿。", "胸中书传有馀香。", "看写《兰亭》小字、记流觞。", "问谁分我渔樵席。", "江海消闲日。", "看君天上拜恩浓。", "却恐画楼无处、著东风。"]'),
('song-ci-297','虞美人','辛弃疾','宋','宋词','song-ci','虞美人','[]','翠屏罗幕遮前后。',66,'宋词/ci.song.11000.json','["翠屏罗幕遮前后。", "舞袖翻长寿。", "紫髯冠佩御炉香。", "看取明年归奉、万年觞。", "今宵池上蟠桃席。", "咫尺长安日。", "宝烟飞焰万花浓。", "试看中间白鹤、驾仙风。"]'),
('song-ci-298','虞美人','辛弃疾','宋','宋词','song-ci','虞美人','[]','夜深困倚屏风后。',68,'宋词/ci.song.11000.json','["夜深困倚屏风后。", "试请毛延寿。", "宝钗小立白翻香。", "旋唱新词犹误、笑持觞。", "四更山月寒侵席。", "歌舞催时日。", "问他何处最情浓。", "却道”小梅摇落、不禁风。“"]'),
('song-ci-299','虞美人','辛弃疾','宋','宋词','song-ci','虞美人','[]','群花泣尽朝来露。',66,'宋词/ci.song.11000.json','["群花泣尽朝来露。", "争奈春归去。", "不知庭下有荼䕷。", "偷得十分春色、怕春知。", "淡中有味清中贵。", "飞絮残英避。", "露华微渗玉肌香。", "恰似杨妃初试、出兰汤。"]'),
('song-ci-300','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','意态憨生元自好。',70,'宋词/ci.song.11000.json','["意态憨生元自好。", "学画鸦儿，旧日偏他巧。", "蜂蝶不禁花引调。", "西园人去春风少。", "春已无情秋又老。", "谁管闲愁，千里青青草。", "今夜倩簪黄菊了。", "断肠明月霜天晓。"]'),
('song-ci-301','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','谁向椒盘簪彩胜。',70,'宋词/ci.song.11000.json','["谁向椒盘簪彩胜。", "整整韶华，争上春风鬓。", "往日不堪重记省。", "为花长把新春恨。", "春未来时先借问。", "晚恨开迟，早又飘零近。", "今岁花期消息定。", "只愁风雨无凭准。"]'),
('song-ci-302','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','老去怕寻年少伴。',70,'宋词/ci.song.11000.json','["老去怕寻年少伴。", "画栋珠帘，风月无人管。", "公子看花朱碧乱。", "新词搅断香思怨。", "凉夜愁肠千百转。", "一雁西风，锦字何时遣。", "毕竟啼乌才思短。", "唤回晓梦天涯远。"]'),
('song-ci-303','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','莫向城头听漏点。',72,'宋词/ci.song.11000.json','["莫向城头听漏点。", "说与行人，默默情千万。", "总是离愁无近远。", "人间儿女空恩怨。", "锦绣心胸冰雪面。", "旧日诗名，曾道空梁燕。", "倾盖未偿平日愿。", "一杯早唱《阳关》劝。"]'),
('song-ci-304','感皇恩','辛弃疾','宋','宋词','song-ci','感皇恩','[]','七十古来稀，人人都道。',81,'宋词/ci.song.11000.json','["七十古来稀，人人都道。", "不是阴功怎生到。", "松姿虽瘦，偏耐云寒霜晓。", "看君双鬓底，青青好。", "楼雪初晴，庭闱嬉笑。", "一醉何妨玉壶倒。", "从今康健，不用灵丹仙草。", "更看一百岁，人难老。"]'),
('song-ci-305','一枝花・促拍满路花','辛弃疾','宋','宋词','song-ci','一枝花・促拍满路花','[]','千丈擎天手。',111,'宋词/ci.song.11000.json','["千丈擎天手。", "万卷悬河口。", "黄金腰下印，大如斗。", "更千骑弓刀，挥霍遮前后。", "百计千方久。", "似斗草儿童，赢个他家偏有。", "算枉了、双眉长恁皱。", "白发空回首。", "那时闲说向，山中友。", "看丘陇牛羊，更辨贤愚否。", "且自栽花柳。", "怕有人来，但只道、今朝中酒。"]'),
('song-ci-306','永遇乐','辛弃疾','宋','宋词','song-ci','永遇乐','[]','紫陌长安，看花年少，无限歌舞。',128,'宋词/ci.song.11000.json','["紫陌长安，看花年少，无限歌舞。", "白发怜君，寻芳较晚，卷地惊风雨。", "问君知否，鸱夷载酒，不似井瓶身误。", "细思量，悲欢梦里，觉来总无寻处。", "芒鞋竹杖，天教还了，千古玉溪佳句。", "落魄东归，风流赢得，掌上明珠去。", "起看清镜，南冠好在，拂了旧时尘土。", "向君道，云霄万里，这回稳步。"]'),
('song-ci-307','御街行','辛弃疾','宋','宋词','song-ci','御街行','[]','山城甲子冥冥雨。',90,'宋词/ci.song.11000.json','["山城甲子冥冥雨。", "门外青泥路。", "杜鹃只是等闲啼，莫被他催归去。", "垂杨不语，行人去后，也会风前絮。", "情知梦里寻鹓鹭。", "玉殿追班处。", "怕君不饮太愁生，不是苦留君住。", "白头自笑，年年送客，自唤春江渡。"]'),
('song-ci-308','御街行','辛弃疾','宋','宋词','song-ci','御街行','[]','阑干四面山无数。',94,'宋词/ci.song.11000.json','["阑干四面山无数。", "供望眼、朝与暮。", "好风催雨过山来，吹尽一帘烦暑。", "纱厨如雾，簟纹如水，别有生凉处。", "冰肌不受铅华污。", "更旎旎、真香聚。", "临风一曲最妖娇，唱得行人且住。", "藕花都放，木犀开后，待与乘鸾去。"]'),
('song-ci-309','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','溪边照影行，天在清溪底。',48,'宋词/ci.song.11000.json','["溪边照影行，天在清溪底。", "天上有行云，人在行云里。", "高歌谁和余，空谷清音起。", "非鬼亦非仙，一曲桃花水。"]'),
('song-ci-310','渔家傲','辛弃疾','宋','宋词','song-ci','渔家傲','["\u957f\u6c5f"]','道德文章传几世。',72,'宋词/ci.song.11000.json','["道德文章传几世。", "到君合上三台位。", "自是君家门户事。", "当此际。", "鬼山正抱西江水。", "三万六千排日醉。", "鬓毛只恁青青地。", "江里石头争献瑞。", "分明是。", "中间有个长生字。"]'),
('song-ci-311','好事近','辛弃疾','宋','宋词','song-ci','好事近','[]','彩胜斗华灯，平地东风吹却。',53,'宋词/ci.song.11000.json','["彩胜斗华灯，平地东风吹却。", "唤取雪中明月，伴使君行乐。", "红旗铁马响春冰，老去此情薄。", "惟有前村梅在，倩一枝随著。"]'),
('song-ci-312','好事近','辛弃疾','宋','宋词','song-ci','好事近','[]','和泪唱《阳关》，依旧字娇声稳。',55,'宋词/ci.song.11000.json','["和泪唱《阳关》，依旧字娇声稳。", "回首长安何处，怕行人归晚。", "垂杨折尽只啼鸦，把离愁勾引。", "却笑远山无数，被行云低损。"]'),
('song-ci-313','行香子','辛弃疾','宋','宋词','song-ci','行香子','[]','归去来兮。',84,'宋词/ci.song.11000.json','["归去来兮。", "行乐休迟。", "命由天、富贵何时。", "百年光景，七十者稀。", "奈一番愁，一番病，一番衰。", "名利奔驰。", "宠辱惊疑。", "旧家时、都有些儿。", "而今老矣，识破关机。", "算不如闲，不如醉，不如痴。"]'),
('song-ci-314','南歌子','辛弃疾','宋','宋词','song-ci','南歌子','[]','玄入参同契，禅依不二门。',62,'宋词/ci.song.11000.json','["玄入参同契，禅依不二门。", "静看斜日隙中尘。", "始觉人间、何处不纷纷。", "病笑春先老，闲怜懒是真。", "百般啼鸟苦撩人。", "除却提壶、此外不堪闲。"]'),
('song-ci-315','南歌子','辛弃疾','宋','宋词','song-ci','南歌子','[]','世事从头减，秋怀彻底清。',62,'宋词/ci.song.11000.json','["世事从头减，秋怀彻底清。", "夜深犹道枕边声。", "试问清溪底事、不能平。", "月到愁边白，鸡先远处鸣。", "是中无有利和名。", "因甚山前未晓、有人行。"]'),
('song-ci-316','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','此身长健。',54,'宋词/ci.song.11000.json','["此身长健。", "还却功名愿。", "枉读平生三万卷。", "满酌金杯听劝。", "男儿玉带金鱼。", "能消几许诗书。", "料得今宵醉也，两行红袖争扶。"]'),
('song-ci-317','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','诗书万卷。',54,'宋词/ci.song.11000.json','["诗书万卷。", "合上明光殿。", "案上文书看未遍。", "眉里阴功早见。", "十分竹瘦松坚。", "看君自是长年。", "若解尊前痛饮，精神便是神仙。"]'),
('song-ci-318','清平乐','辛弃疾','宋','宋词','song-ci','清平乐','[]','清溪奔快。',54,'宋词/ci.song.11000.json','["清溪奔快。", "不管青山碍。", "千里盘盘平世界。", "更著溪山襟带。", "古今陵谷茫茫。", "市朝往往耕桑。", "此地居然形胜，似曾小小兴亡。"]'),
('song-ci-319','浪淘沙','辛弃疾','宋','宋词','song-ci','浪淘沙','[]','金玉旧情怀。',64,'宋词/ci.song.11000.json','["金玉旧情怀。", "风月追陪。", "扁舟千里兴佳哉。", "不似子猷行半路，却棹船回。", "来岁菊花开。", "记我清杯。", "西风雁过瑱山台。", "把似倩他书不到，好与同来。"]'),
('song-ci-320','浪淘沙','辛弃疾','宋','宋词','song-ci','浪淘沙','[]','不肯过江东。',64,'宋词/ci.song.11000.json','["不肯过江东。", "玉帐匆匆。", "至今草木忆英雄。", "唱著虞兮当日曲，便舞春风。", "儿女此情同。", "往事朦胧。", "湘娥竹上泪痕浓。", "舜盖重瞳堪痛恨，羽又重瞳。"]'),
('song-ci-321','虞美人','辛弃疾','宋','宋词','song-ci','虞美人','[]','当年得意如芳草。',66,'宋词/ci.song.11000.json','["当年得意如芳草。", "日日春风好。", "拔山力尽忽悲歌。", "饮罢虞兮从此、奈君何。", "人间不识精诚苦。", "贪看青青舞。", "蓦然敛袂却亭亭。", "怕是曲中犹带、楚歌声。"]'),
('song-ci-322','新荷叶','辛弃疾','宋','宋词','song-ci','新荷叶','[]','物盛还衰，眼看春药秋萁。',100,'宋词/ci.song.11000.json','["物盛还衰，眼看春药秋萁。", "贵贱交情，翟公门外人稀。", "酒酣耳热，又何须、幽愤裁诗。", "茂林修竹，小园曲迳疏篱。", "秋以为期。", "西风黄菊开时。", "拄杖敲门，从他颠倒裳衣。", "去年堪笑，醉题诗、醒后方知。", "而今东望，心随去鸟先飞。"]'),
('song-ci-323','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','青山非不佳，未解留侬住。',48,'宋词/ci.song.11000.json','["青山非不佳，未解留侬住。", "赤脚踏沧浪，为爱清溪故。", "朝来山鸟啼，劝上山高处。", "我意不关渠，自要寻兰去。"]'),
('song-ci-324','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','宫粉厌涂娇额，浓妆要压秋花。',58,'宋词/ci.song.11000.json','["宫粉厌涂娇额，浓妆要压秋花。", "西真人醉忆仙家。", "飞珮丹霞羽化。", "十里芬芳未足，一亭风露先加。", "杏腮桃脸费铅华。", "终惯秋蟾影下。"]'),
('song-ci-325','糖多令・唐多令','辛弃疾','宋','宋词','song-ci','糖多令・唐多令','[]','淑景斗清明。',74,'宋词/ci.song.11000.json','["淑景斗清明。", "和风拂面轻。", "小杯盘、同集郊坰。", "著个簥儿不肯上，须索要、大家行。", "行步渐轻盈。", "行行笑语频。", "凤鞋儿、微褪些根。", "忽地倚人陪笑道，真个是、脚儿疼。"]'),
('song-ci-326','王孙信・寻芳草','辛弃疾','宋','宋词','song-ci','王孙信・寻芳草','[]','有得许多泪。',66,'宋词/ci.song.11000.json','["有得许多泪。", "又闲却、许多鸳被。", "枕头儿、放处都不是。", "旧家时、怎生睡。", "更也没书来，那堪被、雁儿调戏。", "道无书、却有书中意。", "排几个、人人字。"]'),
('song-ci-327','一翦梅','辛弃疾','宋','宋词','song-ci','一翦梅','[]','记得同烧此夜香。',72,'宋词/ci.song.11000.json','["记得同烧此夜香。", "人在回廊。", "月在回廊。", "而今独自睚昏黄。", "行也思量。", "坐也思量。", "锦字都来三两行。", "千断人肠。", "万断人肠。", "雁儿何处是仙乡。", "来也恓惶。", "去也恓惶。"]'),
('song-ci-328','一翦梅','辛弃疾','宋','宋词','song-ci','一翦梅','[]','独立苍茫醉不归。',72,'宋词/ci.song.11000.json','["独立苍茫醉不归。", "日暮天寒，归去来兮。", "探梅踏雪几何时。", "今我来思。", "杨柳依依。", "白石江头曲岸□。", "一片闲愁，芳草萋萋。", "多情山鸟不须啼。", "桃李无言，下自成蹊。"]'),
('song-ci-329','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','往年巃嵸堂前路。',64,'宋词/ci.song.11000.json','["往年巃嵸堂前路。", "路上人夸通判雨。", "去年拄杖过瓢泉，县吏垂头民笑语。", "学窥圣处文章古。", "清到穷时风味苦。", "尊前老泪不成行，明日送君天上去。"]'),
('song-ci-330','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','山行日日妨风雨。',64,'宋词/ci.song.11000.json','["山行日日妨风雨。", "风雨晴时君不见。", "墙头尘满短辕车，门外人行芳草路。", "南城东野应联句。", "好记琅玕题字处。", "也应竹里著行厨，已向瓮头防吏部。"]'),
('song-ci-331','玉楼春','辛弃疾','宋','宋词','song-ci','玉楼春','[]','人间反覆成云雨。',64,'宋词/ci.song.11000.json','["人间反覆成云雨。", "凫雁江湖来又去。", "十千一斗饮中仙，一百八盘天上路。", "旧时枫叶吴江句。", "今日锦囊无著处。", "看封关外水云侯，剩按山中诗酒部。"]'),
('song-ci-332','南乡子','辛弃疾','宋','宋词','song-ci','南乡子','[]','好个主人家。',66,'宋词/ci.song.11000.json','["好个主人家。", "不问因由便去嗏。", "病得那人妆晃了，巴巴。", "系上裙儿稳也哪。", "别泪没些些。", "海誓山盟总是赊。", "今日新欢须记取，孩儿，更过十年也似他。"]'),
('song-ci-333','南乡子','辛弃疾','宋','宋词','song-ci','南乡子','[]','隔户语春莺。',66,'宋词/ci.song.11000.json','["隔户语春莺。", "才挂帘儿敛袂行。", "渐见凌波罗袜步，盈盈。", "随笑随颦百媚生。", "著意听新声。", "尽是司空自教成。", "今夜酒肠还道窄，多情。", "莫放笼纱蜡炬明。"]'),
('song-ci-334','忆王孙','辛弃疾','宋','宋词','song-ci','忆王孙','[]','登山临水送将归。',36,'宋词/ci.song.11000.json','["登山临水送将归。", "悲莫悲兮生别离。", "不用登临怨落晖。", "昔人非。", "惟有年年秋雁飞。"]'),
('song-ci-335','柳梢青','辛弃疾','宋','宋词','song-ci','柳梢青','[]','姚魏名流。',61,'宋词/ci.song.11000.json','["姚魏名流。", "年年揽断，雨恨风愁。", "解释春光，剩须破费，酒令诗筹。", "玉肌红粉温柔。", "更染尽、天香未休。", "今夜簪花，他年第一，玉殿东头。"]'),
('song-ci-336','惜分飞','辛弃疾','宋','宋词','song-ci','惜分飞','[]','翡翠楼前芳草路。',58,'宋词/ci.song.11000.json','["翡翠楼前芳草路。", "宝马坠鞭曾驻。", "最是周郎顾。", "尊前几度歌声误。", "望断碧云空日暮。", "流水桃源何处。", "闻道春归去。", "更无人管飘红雨。"]'),
('song-ci-337','六州歌头','辛弃疾','宋','宋词','song-ci','六州歌头','["\u957f\u6c5f", "\u897f\u6e56"]','西湖万顷，楼观矗千门。',182,'宋词/ci.song.11000.json','["西湖万顷，楼观矗千门。", "春风路，红堆锦，翠连云。", "俯层轩。", "风月都无际，荡空蔼，开绝境，云梦泽，饶八九，不须吞。", "翡翠明珰，争上金堤去，勃窣媻姗。", "看贤王高会，飞盖入云烟。", "白鹭振振，鼓咽咽。", "记风流远，更休作，嬉游地，等闲看。", "君不见，韩献子，晋将军，赵孤存。", "千载传忠献，两定策，纪元勋。", "孙又子，方谈笑，整乾坤。", "直使长江如带，依前是、□赵须韩。", "伴皇家快乐，长在玉津边。", "只在南园。"]'),
('song-ci-338','六州歌头','辛弃疾','宋','宋词','song-ci','六州歌头','[]','晨来问疾，有鹤止庭隅。',182,'宋词/ci.song.11000.json','["晨来问疾，有鹤止庭隅。", "吾语汝。", "只三事，太愁予。", "病难扶。", "手种青松树。", "碍梅坞。", "妨花迳，才数尺。", "如人立。", "却须锄。", "秋水堂前，曲沼明於镜，可烛眉须。", "被山头急雨，耕垄灌泥涂。", "谁使吾庐。", "映污渠。", "叹青山好，檐外竹，遮欲尽，有还无。", "删竹去，吾乍可，食无鱼。", "爱扶疏。", "又欲为山计，千百虑，累吾躯。", "凡病此。", "吾过矣。", "子奚如。", "口不能言臆对，虽扁鹊、药石难除。", "有要言妙道，往问北山愚。", "庶有瘳乎。"]'),
('song-ci-339','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','宿酒醒时，算只有、清愁而已。',115,'宋词/ci.song.11000.json','["宿酒醒时，算只有、清愁而已。", "人正在、青涂堂上，月华如洗。", "纸帐梅花归梦觉，莼羹鲈鲙秋风起。", "问人生、得意几何时，吾归矣。", "君若问，相思事。", "料长在，歌声里。", "这情怀只是，中年如此。", "明月何妨千里隔，顾君与我何如耳。", "向尊前、重约几时来，江山美。"]'),
('song-ci-340','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','几个轻鸥，来点破、一泓澄绿。',115,'宋词/ci.song.11000.json','["几个轻鸥，来点破、一泓澄绿。", "更何处、一双鸂鶒，故来争浴。", "细读离骚还痛饮，饱看修竹何妨肉。", "有飞泉、日日供明珠，三千斛。", "春雨满，秧新谷。", "闲日永，眠黄犊。", "看云连麦垄，雪堆蚕簇。", "若要足时今足矣，以为未足何时足。", "被野老、相扶入东园，枇杷熟。"]'),
('song-ci-341','永遇乐','辛弃疾','宋','宋词','song-ci','永遇乐','[]','投老空山，万松手种，政尔堪叹。',128,'宋词/ci.song.11000.json','["投老空山，万松手种，政尔堪叹。", "何日成阴，吾年有几，似见儿孙晚。", "古来池馆，云烟草棘，长使后人凄断。", "想当年、良辰已恨，夜阑酒空人散。", "停云高处，谁知老子，万事不关心眼。", "梦觉东窗，聊复尔耳，起欲题书简。", "霎时风怒，倒翻笔砚，天也只教吾懒。", "又何事，催诗雨急，片云斗暗。"]'),
('song-ci-342','兰陵王','辛弃疾','宋','宋词','song-ci','兰陵王','[]','一丘壑。',158,'宋词/ci.song.11000.json','["一丘壑。", "老子风流占却。", "茅檐上、松月桂云，脉脉石泉逗山脚。", "寻思前事错。", "恼杀晨猿夜鹤。", "终须是、邓禹辈人，锦绣麻霞坐黄阁。", "长歌自深酌。", "看天阔鸢飞，渊静鱼跃。", "西风黄菊芗喷薄。", "怅日暮云合，佳人何处，纫兰结佩带杜若。", "入江海曾约。", "遇合。", "事难托。", "莫击磬门前，荷蒉人过，仰天大笑冠簪落。", "待说与穷达，不须疑著。", "古来贤者，进亦乐，退亦乐。"]'),
('song-ci-343','蓦山溪','辛弃疾','宋','宋词','song-ci','蓦山溪','[]','饭蔬饮水，客莫嘲吾拙。',102,'宋词/ci.song.11000.json','["饭蔬饮水，客莫嘲吾拙。", "高处看浮云，一丘壑、中间甚乐。", "功名妙手，壮也不如人，今老矣，尚何堪，堪钓前溪月。", "病来止酒，辜负鸬鹚杓。", "岁晚念平生，待都与、邻翁细说。", "人间万事，先觉者贤乎，深雪里，一枝开，春事梅先觉。"]'),
('song-ci-344','蓦山溪','辛弃疾','宋','宋词','song-ci','蓦山溪','[]','小桥流水，欲下前溪去。',102,'宋词/ci.song.11000.json','["小桥流水，欲下前溪去。", "唤取故人来，伴先生、风烟杖屦。", "行穿窈窕，时历小崎岖，斜带水，半遮山，翠竹栽成路。", "一尊遐想，剩有渊明趣。", "山上有停云，看山下、濛濛细雨。", "野花啼鸟，不肯入诗来，还一似，笑翁诗，句没安排处。"]'),
('song-ci-345','满庭芳','辛弃疾','宋','宋词','song-ci','满庭芳','[]','倾国无媒，入宫见妒，古来颦损蛾眉。',118,'宋词/ci.song.11000.json','["倾国无媒，入宫见妒，古来颦损蛾眉。", "看公如月，光彩众星稀。", "袖手高山流水，听群蛙、鼓吹荒池。", "文章手，直须补衮，藻火粲宗彝。", "痴儿。", "公事了，吴蚕缠绕，自吐馀丝。", "幸一枝粗稳，三径新治。", "且约湖边风月，功名事、欲使谁知。", "都休问，英雄千古，荒草没残碑。"]'),
('song-ci-346','满庭芳','辛弃疾','宋','宋词','song-ci','满庭芳','[]','西崦斜阳，东江流水，物华不为人留。',117,'宋词/ci.song.11000.json','["西崦斜阳，东江流水，物华不为人留。", "铮然一叶，天下已知秋。", "屈指人间得意，问谁是、骑鹤扬州。", "君知我，从来雅意，未老已沧州。", "无穷身外事，百年能几，一醉都休。", "恨儿曹抵死，谓我心忧。", "况有溪山杖屦，阮籍辈、须我来游。", "还堪笑，机心早觉，海上有惊鸥。"]'),
('song-ci-347','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','花知否，花一似何郎。',100,'宋词/ci.song.11000.json','["花知否，花一似何郎。", "又似沈东阳。", "瘦棱棱地天然白，冷清清地许多香。", "笑东君，还又向，北枝忙。", "著一阵、霎时间底雪。", "更一个、缺些儿底月。", "山下路，水边墙。", "风流怕有人知处，影儿守定竹旁厢。", "且饶他，桃李趁，少年场。"]'),
('song-ci-348','最高楼','辛弃疾','宋','宋词','song-ci','最高楼','[]','君听取，尺布尚堪缝。',100,'宋词/ci.song.11000.json','["君听取，尺布尚堪缝。", "斗粟也堪舂。", "人间朋友犹能合，古来兄弟不相容。", "棣华诗，悲二叔，吊周公。", "长叹息、脊令原上急。", "重叹息、豆萁煎正泣。", "形则异，气应同。", "周家五世将军后，前江千载义居风。", "看明朝，丹凤诏，紫泥封。"]'),
('song-ci-349','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','乱云扰扰水潺潺。',86,'宋词/ci.song.11000.json','["乱云扰扰水潺潺。", "笑溪山。", "几时闲。", "更觉桃源，人去隔仙凡。", "万壑千岩楼外雪，琼作树，玉为栏。", "倦游回首且加餐。", "短篷寒。", "画图间。", "见说娇颦，拥髻待君看。", "二月东湖湖上路，官柳嫩，野梅残。"]'),
('song-ci-350','木兰花慢','辛弃疾','宋','宋词','song-ci','木兰花慢','[]','路傍人怪问，此隐者、姓陶不。',122,'宋词/ci.song.11000.json','["路傍人怪问，此隐者、姓陶不。", "堪黄菊如云，朝吟暮醉，唤不回头。", "纵无酒成怅望，只东篱、搔首亦风流。", "与客朝餐一笑，落英饱便归休。", "古来尧舜有巢由。", "江海去悠悠。", "待说与佳人，种成香草，莫怨灵修。", "我无可无不可，意先生、出处有如丘。", "闻道问津人过，杀鸡为黍相留。"]'),
('song-ci-351','木兰花慢','辛弃疾','宋','宋词','song-ci','木兰花慢','[]','旧时楼上客，爱把酒、向南山。',121,'宋词/ci.song.11000.json','["旧时楼上客，爱把酒、向南山。", "笑白发如今，天教放浪，来往其间。", "登楼更谁念我，却回头、西北望层栏。", "云雨珠帘画栋，笙歌雾鬓云鬟。", "近来堪入画图看。", "父老愿公欢。", "甚拄笏悠然，朝来爽气，正尔相关。", "难忘使君后日，便一花一草报平安。", "与客携壶且醉，雁飞秋影江寒。"]'),
('song-ci-352','木兰花慢','辛弃疾','宋','宋词','song-ci','木兰花慢','[]','可怜今夕月，向何处、去悠悠。',122,'宋词/ci.song.11000.json','["可怜今夕月，向何处、去悠悠。", "是别有人间，那边才见，光影东头。", "是天外空汗漫，但长风、浩浩送中秋。", "飞镜无根谁系，嫦娥不嫁谁留。", "谓洋海底问无由。", "恍忽使人愁。", "怕万里长鲸，纵横触破，玉殿琼楼。", "虾蟆故堪浴水，问云何、玉兔解沈浮。", "若道都齐无恙，云何渐渐如钩。"]'),
('song-ci-353','声声慢','辛弃疾','宋','宋词','song-ci','声声慢','[]','停云霭霭，八表同昏，尽日时雨濛濛。',119,'宋词/ci.song.11000.json','["停云霭霭，八表同昏，尽日时雨濛濛。", "搔首良朋，门前平陆成江。", "春醪湛湛独抚，限弥襟、闲饮东窗。", "空延伫，恨舟车南北，欲往何从。", "叹息东园佳树，列初荣枝叶，再兢春风。", "日月于征，安得促席从容。", "翩翩何处飞鸟，息庭树、好语和同。", "当年事，问几人、亲友似翁。"]'),
('song-ci-354','八声甘州','辛弃疾','宋','宋词','song-ci','八声甘州','[]','故将军、饮罢夜归来，长亭解雕鞍。',119,'宋词/ci.song.11000.json','["故将军、饮罢夜归来，长亭解雕鞍。", "恨灞陵醉尉，匆匆未识，桃李无言。", "射虎山横一骑，裂石响惊弦。", "落托封侯事，岁晚田间。", "谁向桑麻杜曲，要短衣匹马，移住南山。", "看风流慷慨，谈笑过残年。", "汉开边、功名万里，甚当时、健者也曾闲。", "纱窗外、斜风细雨，一障轻寒。"]'),
('song-ci-355','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','相公倦台鼎，要伴赤松游。',114,'宋词/ci.song.11000.json','["相公倦台鼎，要伴赤松游。", "高牙千里东下，笳鼓万貔貅。", "试问东山风月，更著中年丝竹，留得谢公不。", "孺子宅边水，云影自悠悠。", "占古语，方人也，正黑头。", "穹龟突兀千丈，石打玉溪流。", "金印沙堤时节，画栋珠帘云雨，一醉早归休。", "贱子亲再拜，西北有神州。"]'),
('song-ci-356','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','["\u6cf0\u5c71"]','长恨复长恨，裁作短歌行。',114,'宋词/ci.song.11000.json','["长恨复长恨，裁作短歌行。", "何人为我楚舞，听我楚狂声。", "余既滋兰九畹，又树蕙之百亩，秋菊更餐英。", "门外沧浪水，可以濯吾缨。", "一杯酒，问何似，身后名。", "人间万事，□□常重泰山轻。", "悲莫悲生离别，乐莫乐新相识，儿女古今情。", "富贵非吾事，归与白鸥盟。"]'),
('song-ci-357','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','我亦卜居者，岁晚望三闾。',114,'宋词/ci.song.11000.json','["我亦卜居者，岁晚望三闾。", "昂昂千里，泛泛不作水中凫。", "好在书携一束，莫问家徒四壁，往日置锥无。", "借车载家具，家具少於车。", "舞乌有，歌亡是，饮子虚。", "二三子者爱我，此外故人疏。", "幽事欲论谁共，白鸥飞来似可，忽去复何如。", "群鸟欣有托，吾亦爱吾庐。"]'),
('song-ci-358','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','四坐且勿语，听我醉中吟。',114,'宋词/ci.song.11000.json','["四坐且勿语，听我醉中吟。", "池塘春草未歇，高树变鸣禽。", "鸿雁初飞江上，蟋蟋还来床下，时序百年心。", "谁要卿料理，山水有清音。", "欢多少，歌长短，酒浅深。", "而今已不如昔，后定不如今。", "闲处直须行乐，良夜更教秉烛，高会惜分阴。", "白发短如许，黄菊倩谁簪。"]'),
('song-ci-359','水龙吟','辛弃疾','宋','宋词','song-ci','水龙吟','[]','昔时曾有佳人，翩然绝世而独立。',125,'宋词/ci.song.11000.json','["昔时曾有佳人，翩然绝世而独立。", "未论一顾倾城，再顾又倾人国。", "宁不知其，倾城倾国，佳人难得。", "看行云行雨，朝朝暮暮，阳台下、襄王侧。", "堂上更阑烛灭。", "记主人、留髡送客。", "合尊促坐，罗襦襟解，微闻芗泽。", "当此之时，止乎礼义，不淫其色。", "但□□□□，啜其泣矣，又何嗟及。"]'),
('song-ci-360','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','翠浪吞平野。',142,'宋词/ci.song.11000.json','["翠浪吞平野。", "挽天河、谁来照影，卧龙山下。", "烟雨偏宜晴更好，约略西施未嫁。", "待细把、江山图画。", "千顷光中堆滟澦，似扁舟、欲下瞿塘马。", "中有句，浩难写。", "诗人例入西湖社。", "记风流、重来手种，绿阴成也。", "陌上游人夸故国，十里水晶台榭。", "更夏道、横空清夜。", "粉黛中□歌妙曲，问当年、鱼鸟无存者。", "堂上燕，又长夏。"]'),
('song-ci-361','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','觅句如东野。',141,'宋词/ci.song.11000.json','["觅句如东野。", "想钱塘、风流处士，水仙祠下。", "更隐小孤烟浪里，望断彭郎欲嫁。", "是一色、空濛难画。", "谁解胸中吞云梦，试呼来、草赋看司马。", "须更把，上林写。", "鸡豚旧日渔樵社。", "问先生、带湖春涨，几时归也。", "为爱琉璃三万顷，正卧水亭烟榭。", "对玉塔、微澜深夜。", "雁鹜如云休报事，被诗逢敌手皆勍者。", "春草梦，也宜夏。"]'),
('song-ci-362','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','绿树听鹈鴂。',141,'宋词/ci.song.11000.json','["绿树听鹈鴂。", "更那堪、鹧鸪声住，杜鹃声切。", "啼到春归无寻处，苦恨芳菲都歇。", "算未抵、人间离别。", "马上琵琶关塞黑，更长门、翠辇辞金阙。", "看燕燕，送归妾。", "将军百战身名裂。", "向河梁、回头万里，故人长绝。", "易水萧萧西风冷，满座衣冠似雪。", "正壮士、悲歌未彻。", "啼鸟还知如许恨，料不啼清泪长啼血。", "谁共我，醉明月。"]'),
('song-ci-363','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','甚矣吾衰矣。',142,'宋词/ci.song.11000.json','["甚矣吾衰矣。", "怅平生、交游零落，只今馀几。", "白发空垂三千丈，一笑人间万事。", "问何物、能令公喜。", "我见青山多妩媚，料青山、见我应如是。", "情与貌，略相似。", "一尊搔首东窗里。", "想渊明、停云诗就，此时风味。", "江左沈酣求名者，岂识浊醪妙理。", "回首叫、云飞风起。", "不恨古人吾不见，恨古人、不见吾狂耳。", "知我者，二三子。"]'),
('song-ci-364','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','我见君来，顿觉吾庐，溪山美哉。',139,'宋词/ci.song.11000.json','["我见君来，顿觉吾庐，溪山美哉。", "怅平生肝胆，都成楚越，只今胶膝，谁是陈雷。", "搔首踟蹰，爱而不见，要得诗来渴望梅。", "还知否，快清风入手，日看千回。", "直须抖擞尘埃。", "人怪我柴门今始开。", "向松间乍可，从他喝道，庭中且莫，踏破苍苔。", "岂有文章，谩劳车马，待唤青刍白饭来。", "君非我，任功名意气，莫恁徘徊。"]'),
('song-ci-365','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','杯汝来前，老子今朝，点检形骸。',139,'宋词/ci.song.11000.json','["杯汝来前，老子今朝，点检形骸。", "甚长年抱渴，咽如焦釜，于今喜睡，气似奔雷。", "汝说刘伶，古今达者，醉后何妨死便埋。", "浑如此，叹汝於知已，真少恩哉。", "更凭歌舞为媒。", "算合作平居鸠毒猜。", "况怨无大小，生於所爱，物无美恶，过则为灾。", "与汝成言，勿留亟退，吾力犹能肆汝杯。", "杯再拜，道麾之即去，招则须来。"]'),
('song-ci-366','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','杯汝知乎，酒泉罢侯，鸱夷乞骸。',139,'宋词/ci.song.11000.json','["杯汝知乎，酒泉罢侯，鸱夷乞骸。", "更高阳入谒，都称齑臼，杜康初筮，正得云雷。", "细数从前，不堪余恨，岁月都将曲糵埋。", "君诗好，似提壶却劝，沽酒何哉。", "君言病岂无媒。", "似壁上雕弓蛇暗猜。", "记醉眠陶令，终全至乐，独醒屈子，未免沈灾。", "欲听公言，惭非勇者，司马家儿解覆杯。", "还堪笑，借今宵一醉，为故人来。"]'),
('song-ci-367','哨遍','辛弃疾','宋','宋词','song-ci','哨遍','["\u6cf0\u5c71"]','蜗角斗争，左触右蛮，一战连千里。',242,'宋词/ci.song.11000.json','["蜗角斗争，左触右蛮，一战连千里。", "君试思、方寸此心微。", "总虚空、并包无际。", "喻此理。", "何言泰山毫末，从来天地一稊米。", "嗟大小相形，鸠鹏自乐，之二虫又何知。", "记跖行仁义孔丘非。", "更殇乐长年老彭悲。", "火鼠论寒，冰蚕语热，定谁同异。", "噫。", "贵贱随时。", "连城才换一羊皮。", "谁与齐万物，庄周吾梦见之。", "正商略遗篇，翩然顾笑，空堂梦觉题秋水。", "有客问洪河，百川灌雨，泾流不辨涯涘。", "於是焉河伯欣然喜。", "以天下之美尽在己。", "渺沧溟望洋东视。", "逡巡向若惊叹，谓我非逢子。", "大方达观之家，未免长见，犹然笑耳。", "北堂之水几何其。", "但清溪一曲而已。"]'),
('song-ci-368','哨遍','辛弃疾','宋','宋词','song-ci','哨遍','[]','一壑自专，五柳笑人，晚乃归田里。',242,'宋词/ci.song.11000.json','["一壑自专，五柳笑人，晚乃归田里。", "问谁知、几者动之微。", "望飞鸿、冥冥天际。", "论妙理。", "浊醪正堪长醉。", "从今自酿躬耕米。", "嗟美恶难齐，盈虚如代，天耶何必人知。", "试回头五十九年非。", "似梦里欢娱觉来悲。", "夔乃怜蚿，谷亦亡羊，算来何异。", "嘻。", "物讳穷时。", "丰狐文豹罪因皮。", "富贵非吾愿，皇皇乎欲何之。", "正万籁都沈，月明中夜，心弥万里清如水。", "却自觉神游，归来坐对，依稀淮岸江涘。", "看一时鱼鸟忘情喜。", "会我已忘机更忘己。", "又何曾物我相视。", "非会濠梁遗意，要是吾非子。", "但教河伯、休惭海若，大小均为水耳。", "世间喜愠更何其。", "笑先生三仕三已。"]'),
('song-ci-369','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','未须草草，赋梅花，多少骚人词客。',121,'宋词/ci.song.11000.json','["未须草草，赋梅花，多少骚人词客。", "总被西湖林处士，不肯分留风月。", "疏影横斜，暗香浮动，□□春消息。", "尚馀花品，未忝今古人物。", "看取香月堂前，岁寒相对，楚两龚之洁。", "自与诗家成一种，不系南昌仙籍。", "怕是当年，香山老子，姓白来江国。", "谪仙人，字太白，还又名白。"]'),
('song-ci-370','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','为沽美酒，过溪来、谁道幽人难致。',122,'宋词/ci.song.11000.json','["为沽美酒，过溪来、谁道幽人难致。", "更觉元龙楼百尺，湖海平生豪气。", "自叹年来，看花索句，老不如人意。", "东风归路，一川松竹如醉。", "怎得身似庄周，梦中蝴蝶，花底人间世。", "记取江头三月暮，风雨不为春计。", "万斛愁来，金貂头上，不抵银瓶贵。", "无多笑我，此篇聊当《宾戏》。"]'),
('song-ci-371','感皇恩','辛弃疾','宋','宋词','song-ci','感皇恩','[]','富贵不须论，公应自有。',81,'宋词/ci.song.11000.json','["富贵不须论，公应自有。", "且把新词祝公寿。", "当年仙桂，父子同攀希有。", "人言金殿上，他年又。", "冠冕在前，周公拜手。", "同日催班鲁公后。", "此时人羡，绿鬓朱颜依旧。", "亲朋来贺喜，休辞酒。"]');
